pub const HEADER_SIZE: usize = 64;
const MAGIC: [u8; 8] = *b"OGDB0001";
const MIN_PAGE_SIZE: u32 = 64;
const EDGE_RECORD_SIZE: usize = 16;
const WAL_HEADER_SIZE: usize = 8;
const WAL_MAGIC: [u8; WAL_HEADER_SIZE] = *b"OGWAL001";
const WAL_RECORD_CREATE_NODE: u8 = 1;
const WAL_RECORD_ADD_EDGE: u8 = 2;
/// WAL v2 CREATE_NODE — carries the node's labels and property map in
/// addition to its id. Introduced by audit finding 2.1 to close the
/// deferred-sync durability gap where a power loss between WAL fsync and
/// `meta.json` / property-store sidecar writeback could lose the
/// labels/properties of a committed transaction. Replay of a v2 record
/// prefers sidecar-loaded state when it is already populated (that state is
/// authoritative for the most recent checkpointed session); it fills empty
/// slots with the WAL payload so a power-loss-destroyed sidecar still
/// recovers the committed labels+props.
///
/// On-disk format: `[tag=3][node_id:u64 LE][labels_len:u32 LE][labels_json
/// (utf-8 JSON array of strings)][props_len:u32 LE][props_json (utf-8 JSON
/// map)]`. The existing 8-byte WAL file magic `OGWAL001` is unchanged —
/// v1 and v2 records coexist in the same WAL file and the record tag is
/// the version marker.
const WAL_RECORD_CREATE_NODE_V2: u8 = 3;
const DELTA_COMPACTION_EDGE_THRESHOLD: usize = 256;
/// Format version for the `<db>.ogdb-meta.json` catalog file.
///
/// Bumped only across minor releases; readers must accept old values per
/// `documentation/COMPATIBILITY.md` § 2. Exposed as `pub const` so downstream
/// crates can gate on the workspace's on-disk format at compile time.
pub const META_FORMAT_VERSION: u32 = 1;
/// Format version for the `<db>.ogdb-freelist.json` allocator file.
///
/// Same migration policy as [`META_FORMAT_VERSION`]
/// (see `documentation/COMPATIBILITY.md` § 2).
pub const FREE_LIST_FORMAT_VERSION: u32 = 1;
/// Format version for the `<db>.ogdb-csr.json` traversal layout.
///
/// Same migration policy as [`META_FORMAT_VERSION`]
/// (see `documentation/COMPATIBILITY.md` § 2).
pub const CSR_LAYOUT_FORMAT_VERSION: u32 = 1;
/// Format version for the `<db>.ogdb-props*` node-property store.
///
/// Same migration policy as [`META_FORMAT_VERSION`]
/// (see `documentation/COMPATIBILITY.md` § 2).
pub const NODE_PROPERTY_STORE_FORMAT_VERSION: u32 = 1;
/// Format version for the `<db>.ogdb.vecindex` vector-index sidecar.
///
/// Same migration policy as [`META_FORMAT_VERSION`]
/// (see `documentation/COMPATIBILITY.md` § 2).
pub const VECTOR_INDEX_FORMAT_VERSION: u32 = 1;
const DEFAULT_BUFFER_POOL_CAPACITY_PAGES: usize = 256;
const NODE_PROPERTY_STORE_HEADER_SIZE: usize = 64;
const NODE_PROPERTY_ROW_HEADER_SIZE: usize = 24;
const NODE_PROPERTY_OVERFLOW_HEADER_SIZE: usize = 16;
const NODE_PROPERTY_NO_OVERFLOW_PAGE: u64 = u64::MAX;
const NODE_PROPERTY_STORE_MAGIC: [u8; 8] = *b"OGPROP01";
const QUERY_BATCH_SIZE: usize = 256;
/// When expansion fan-out exceeds this threshold, prefer factorized intermediate execution.
const FACTORIZE_FAN_OUT_THRESHOLD: f64 = 10.0;
const PAGE_COMPRESSION_MAGIC: [u8; 8] = *b"OGCMPR01";
const PAGE_COMPRESSION_HEADER_SIZE: usize = 24;
const PAGE_COMPRESSION_CODEC_NONE: u8 = 0;
const PAGE_COMPRESSION_CODEC_LZ4: u8 = 1;
