#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ParseError {
    pub message: String,
    pub position: usize,
    pub line: usize,
    pub column: usize,
}

impl ParseError {
    fn new(input: &str, position: usize, message: impl Into<String>) -> Self {
        let bounded = position.min(input.len());
        let (line, column) = line_col_for_offset(input, bounded);
        Self {
            message: message.into(),
            position: bounded,
            line,
            column,
        }
    }

    fn from_span(span: SourceSpan, message: impl Into<String>) -> Self {
        Self {
            message: message.into(),
            position: span.start,
            line: span.line,
            column: span.column,
        }
    }
}

impl Display for ParseError {
    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
        write!(
            f,
            "{} at line {}, column {}",
            self.message, self.line, self.column
        )
    }
}

impl Error for ParseError {}

