/// Physical-plan node produced by the Cypher planner.
///
/// `#[non_exhaustive]` so the planner can grow new operators (e.g. an
/// index-only path or a hash-join) without breaking downstream consumers
/// that pattern-match on this enum. (EVAL-RUST-QUALITY-CYCLE3 B3.)
#[derive(Debug, Clone, PartialEq)]
#[non_exhaustive]
pub enum PhysicalPlan {
    PhysicalScan {
        label: Option<String>,
        variable: Option<String>,
        scan_strategy: PhysicalScanStrategy,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalVectorScan {
        index_name: String,
        label: Option<String>,
        variable: Option<String>,
        query_vector: Vec<f32>,
        k: u64,
        metric: VectorDistanceMetric,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalTextSearch {
        index_name: String,
        label: Option<String>,
        variable: Option<String>,
        property_key: String,
        query_text: String,
        k: u64,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalExpand {
        input: Box<PhysicalPlan>,
        from: String,
        edge_type: Option<String>,
        direction: RelationshipDirection,
        to: Option<String>,
        edge_variable: Option<String>,
        temporal_filter: Option<TemporalFilter>,
        join_strategy: PhysicalJoinStrategy,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalCartesianProduct {
        left: Box<PhysicalPlan>,
        right: Box<PhysicalPlan>,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalFilter {
        input: Box<PhysicalPlan>,
        predicate: CypherExpression,
        selectivity: f64,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalProject {
        input: Box<PhysicalPlan>,
        expressions: Vec<ProjectionItem>,
        distinct: bool,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalSort {
        input: Box<PhysicalPlan>,
        keys: Vec<OrderByItem>,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalLimit {
        input: Box<PhysicalPlan>,
        count: Option<u64>,
        skip: u64,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalAggregation {
        input: Box<PhysicalPlan>,
        group_keys: Vec<CypherExpression>,
        aggregates: Vec<AggregateFunction>,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalCreate {
        input: Option<Box<PhysicalPlan>>,
        patterns: Vec<Pattern>,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalCreateIndex {
        label: String,
        property_keys: Vec<String>,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalDelete {
        input: Box<PhysicalPlan>,
        expressions: Vec<CypherExpression>,
        detach: bool,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalSet {
        input: Box<PhysicalPlan>,
        assignments: Vec<SetAssignment>,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalRemove {
        input: Box<PhysicalPlan>,
        targets: Vec<CypherExpression>,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalMerge {
        input: Option<Box<PhysicalPlan>>,
        pattern: Pattern,
        on_create: Vec<SetAssignment>,
        on_match: Vec<SetAssignment>,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalUnwind {
        input: Option<Box<PhysicalPlan>>,
        expression: CypherExpression,
        variable: String,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalWcojJoin {
        /// Initial input plan (typically scan/filter for the first variable).
        input: Box<PhysicalPlan>,
        /// The relations to join simultaneously.
        relations: Vec<WcojRelation>,
        /// Variable processing order (first variable comes from input plan).
        variable_order: Vec<String>,
        /// Output variables/columns produced by this WCOJ join.
        output_variables: Vec<String>,
        estimated_rows: u64,
        estimated_cost: f64,
    },
    PhysicalFactorizedExpand {
        input: Box<PhysicalPlan>,
        from: String,
        edge_type: Option<String>,
        direction: RelationshipDirection,
        to: Option<String>,
        edge_variable: Option<String>,
        temporal_filter: Option<TemporalFilter>,
        factorized: bool,
        estimated_rows: u64,
        estimated_cost: f64,
    },
}

impl PhysicalPlan {
    pub fn estimated_rows(&self) -> u64 {
        match self {
            Self::PhysicalScan { estimated_rows, .. }
            | Self::PhysicalVectorScan { estimated_rows, .. }
            | Self::PhysicalTextSearch { estimated_rows, .. }
            | Self::PhysicalExpand { estimated_rows, .. }
            | Self::PhysicalCartesianProduct { estimated_rows, .. }
            | Self::PhysicalFilter { estimated_rows, .. }
            | Self::PhysicalProject { estimated_rows, .. }
            | Self::PhysicalSort { estimated_rows, .. }
            | Self::PhysicalLimit { estimated_rows, .. }
            | Self::PhysicalAggregation { estimated_rows, .. }
            | Self::PhysicalCreate { estimated_rows, .. }
            | Self::PhysicalCreateIndex { estimated_rows, .. }
            | Self::PhysicalDelete { estimated_rows, .. }
            | Self::PhysicalSet { estimated_rows, .. }
            | Self::PhysicalRemove { estimated_rows, .. }
            | Self::PhysicalMerge { estimated_rows, .. }
            | Self::PhysicalUnwind { estimated_rows, .. }
            | Self::PhysicalWcojJoin { estimated_rows, .. }
            | Self::PhysicalFactorizedExpand { estimated_rows, .. } => *estimated_rows,
        }
    }

    pub fn estimated_cost(&self) -> f64 {
        match self {
            Self::PhysicalScan { estimated_cost, .. }
            | Self::PhysicalVectorScan { estimated_cost, .. }
            | Self::PhysicalTextSearch { estimated_cost, .. }
            | Self::PhysicalExpand { estimated_cost, .. }
            | Self::PhysicalCartesianProduct { estimated_cost, .. }
            | Self::PhysicalFilter { estimated_cost, .. }
            | Self::PhysicalProject { estimated_cost, .. }
            | Self::PhysicalSort { estimated_cost, .. }
            | Self::PhysicalLimit { estimated_cost, .. }
            | Self::PhysicalAggregation { estimated_cost, .. }
            | Self::PhysicalCreate { estimated_cost, .. }
            | Self::PhysicalCreateIndex { estimated_cost, .. }
            | Self::PhysicalDelete { estimated_cost, .. }
            | Self::PhysicalSet { estimated_cost, .. }
            | Self::PhysicalRemove { estimated_cost, .. }
            | Self::PhysicalMerge { estimated_cost, .. }
            | Self::PhysicalUnwind { estimated_cost, .. }
            | Self::PhysicalWcojJoin { estimated_cost, .. }
            | Self::PhysicalFactorizedExpand { estimated_cost, .. } => *estimated_cost,
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct ScopeBinding {
    variable_type: SemanticType,
    guaranteed_edges: bool,
}

impl ScopeBinding {
    fn new(variable_type: SemanticType) -> Self {
        Self {
            variable_type,
            guaranteed_edges: false,
        }
    }
}

struct SemanticState {
    labels: BTreeSet<String>,
    edge_types: BTreeSet<String>,
    property_keys: BTreeSet<String>,
    seen_labels: BTreeSet<String>,
    seen_edge_types: BTreeSet<String>,
    seen_properties: BTreeSet<String>,
    warnings: Vec<String>,
    catalog_bindings: CatalogBindings,
    scope_bindings: Vec<ClauseScopeBinding>,
    expression_types: Vec<ExpressionTypeAnnotation>,
}

impl SemanticState {
    fn new(catalog: SchemaCatalog) -> Self {
        Self {
            labels: catalog.labels.into_iter().collect(),
            edge_types: catalog.edge_types.into_iter().collect(),
            property_keys: catalog.property_keys.into_iter().collect(),
            seen_labels: BTreeSet::new(),
            seen_edge_types: BTreeSet::new(),
            seen_properties: BTreeSet::new(),
            warnings: Vec::new(),
            catalog_bindings: CatalogBindings {
                labels: Vec::new(),
                edge_types: Vec::new(),
                property_keys: Vec::new(),
            },
            scope_bindings: Vec::new(),
            expression_types: Vec::new(),
        }
    }

    fn analyze(mut self, query: &CypherQuery) -> Result<SemanticModel, AnalysisError> {
        let mut scope = BTreeMap::<String, ScopeBinding>::new();
        self.analyze_query(query, &mut scope)?;
        Ok(SemanticModel {
            query: query.clone(),
            warnings: self.warnings,
            catalog_bindings: self.catalog_bindings,
            scope_bindings: self.scope_bindings,
            expression_types: self.expression_types,
        })
    }

    fn analyze_query(
        &mut self,
        query: &CypherQuery,
        scope: &mut BTreeMap<String, ScopeBinding>,
    ) -> Result<(), AnalysisError> {
        for (index, clause) in query.clauses.iter().enumerate() {
            match clause {
                CypherClause::Match(value) => {
                    for pattern in &value.patterns {
                        self.analyze_pattern(pattern, scope)?;
                    }
                    let _ = value
                        .where_predicate
                        .as_ref()
                        .map(|predicate| self.infer_type(predicate, scope))
                        .transpose()?;
                }
                CypherClause::Create(value) => {
                    for pattern in &value.patterns {
                        self.analyze_pattern(pattern, scope)?;
                    }
                }
                CypherClause::CreateIndex(value) => {
                    self.record_label(&value.label);
                    for property_key in &value.property_keys {
                        self.record_property(property_key);
                    }
                }
                CypherClause::Delete(value) => {
                    for expr in &value.expressions {
                        let _ = self.infer_type(expr, scope)?;
                    }
                    if !value.detach {
                        for expr in &value.expressions {
                            if let CypherExpression::Identifier(name) = expr {
                                if scope
                                    .get(name)
                                    .map(|binding| {
                                        binding.variable_type == SemanticType::Node
                                            && binding.guaranteed_edges
                                    })
                                    .unwrap_or(false)
                                {
                                    return Err(AnalysisError::new(format!(
                                        "DELETE on '{name}' requires DETACH for matched edge-connected nodes"
                                    )));
                                }
                            }
                        }
                    }
                }
                CypherClause::Set(value) => {
                    for assignment in &value.assignments {
                        let _ = self.infer_type(&assignment.target, scope)?;
                        let _ = self.infer_type(&assignment.value, scope)?;
                    }
                }
                CypherClause::Remove(value) => {
                    for target in &value.targets {
                        let _ = self.infer_type(target, scope)?;
                    }
                }
                CypherClause::With(value) => {
                    validate_aggregation_usage(&value.items, &[], "WITH")?;
                    let current = scope.clone();
                    scope.clear();
                    for item in &value.items {
                        let ty = self.infer_type(&item.expression, &current)?;
                        let key = projection_output_name(item).ok_or_else(|| {
                            AnalysisError::new(
                                "WITH expression requires alias unless it is identifier/property",
                            )
                        })?;
                        scope.insert(key, ScopeBinding::new(ty));
                    }
                    let _ = value
                        .where_predicate
                        .as_ref()
                        .map(|predicate| self.infer_type(predicate, scope))
                        .transpose()?;
                }
                CypherClause::Unwind(value) => {
                    let _ = self.infer_type(&value.expression, scope)?;
                    scope.insert(
                        value.variable.clone(),
                        ScopeBinding::new(SemanticType::PropertyValue),
                    );
                }
                CypherClause::Merge(value) => {
                    self.analyze_pattern(&value.pattern, scope)?;
                    for assignment in value.on_create_set.iter().chain(&value.on_match_set) {
                        let _ = self.infer_type(&assignment.target, scope)?;
                        let _ = self.infer_type(&assignment.value, scope)?;
                    }
                }
            }
            self.scope_bindings.push(ClauseScopeBinding {
                clause_index: index,
                bound_variables: scope.keys().cloned().collect(),
            });
        }

        if let Some(return_clause) = &query.return_clause {
            validate_aggregation_usage(&return_clause.items, &return_clause.order_by, "RETURN")?;
            for item in &return_clause.items {
                let _ = self.infer_type(&item.expression, scope)?;
            }
            for key in &return_clause.order_by {
                let _ = self.infer_type(&key.expression, scope)?;
            }
            self.scope_bindings.push(ClauseScopeBinding {
                clause_index: query.clauses.len(),
                bound_variables: scope.keys().cloned().collect(),
            });
        }

        Ok(())
    }

    fn analyze_pattern(
        &mut self,
        pattern: &Pattern,
        scope: &mut BTreeMap<String, ScopeBinding>,
    ) -> Result<(), AnalysisError> {
        let mut previous = self.analyze_node_pattern(&pattern.start, scope)?;
        for chain in &pattern.chains {
            self.analyze_relationship_pattern(&chain.relationship, scope)?;
            let next = self.analyze_node_pattern(&chain.node, scope)?;
            if let Some(binding) = previous.as_ref().and_then(|name| scope.get_mut(name)) {
                binding.guaranteed_edges = true;
            }
            if let Some(name) = next.clone() {
                if let Some(binding) = scope.get_mut(&name) {
                    binding.guaranteed_edges = true;
                }
            }
            previous = next;
        }
        Ok(())
    }

    fn analyze_node_pattern(
        &mut self,
        node: &NodePattern,
        scope: &mut BTreeMap<String, ScopeBinding>,
    ) -> Result<Option<String>, AnalysisError> {
        for label in &node.labels {
            self.record_label(label);
        }
        if let Some(properties) = &node.properties {
            for (key, value) in properties {
                self.record_property(key);
                let _ = self.infer_type(value, scope)?;
            }
        }
        if let Some(variable) = &node.variable {
            bind_variable(scope, variable, SemanticType::Node)?;
        }
        Ok(node.variable.clone())
    }

    fn analyze_relationship_pattern(
        &mut self,
        relationship: &RelationshipPattern,
        scope: &mut BTreeMap<String, ScopeBinding>,
    ) -> Result<(), AnalysisError> {
        if let Some(edge_type) = &relationship.rel_type {
            self.record_edge_type(edge_type);
        }
        if let Some(properties) = &relationship.properties {
            for (key, value) in properties {
                self.record_property(key);
                let _ = self.infer_type(value, scope)?;
            }
        }
        if let Some(variable) = &relationship.variable {
            bind_variable(scope, variable, SemanticType::Relationship)?;
        }
        Ok(())
    }

    fn record_label(&mut self, value: &str) {
        let key = value.trim();
        if key.is_empty() || !self.seen_labels.insert(key.to_string()) {
            return;
        }
        let exists = self.labels.contains(key);
        if !exists {
            self.warnings
                .push(format!("unknown label reference: {key}"));
        }
        self.catalog_bindings.labels.push(CatalogReference {
            name: key.to_string(),
            exists,
        });
    }

    fn record_edge_type(&mut self, value: &str) {
        let key = value.trim();
        if key.is_empty() || !self.seen_edge_types.insert(key.to_string()) {
            return;
        }
        let exists = self.edge_types.contains(key);
        if !exists {
            self.warnings
                .push(format!("unknown edge type reference: {key}"));
        }
        self.catalog_bindings.edge_types.push(CatalogReference {
            name: key.to_string(),
            exists,
        });
    }

    fn record_property(&mut self, value: &str) {
        let key = value.trim();
        if key.is_empty() || !self.seen_properties.insert(key.to_string()) {
            return;
        }
        self.catalog_bindings.property_keys.push(CatalogReference {
            name: key.to_string(),
            exists: self.property_keys.contains(key),
        });
    }

    fn infer_type(
        &mut self,
        expr: &CypherExpression,
        scope: &BTreeMap<String, ScopeBinding>,
    ) -> Result<SemanticType, AnalysisError> {
        let ty = match expr {
            CypherExpression::Identifier(name) => scope
                .get(name)
                .map(|binding| binding.variable_type)
                .ok_or_else(|| AnalysisError::new(format!("unbound variable: {name}")))?,
            CypherExpression::Literal(value) => match value {
                CypherLiteral::Null => SemanticType::Null,
                CypherLiteral::Boolean(_) => SemanticType::Boolean,
                CypherLiteral::Integer(_) => SemanticType::Integer,
                CypherLiteral::Float(_) => SemanticType::Float,
                CypherLiteral::String(_) => SemanticType::String,
            },
            CypherExpression::Parameter(_) => SemanticType::PropertyValue,
            CypherExpression::PropertyAccess { target, property } => {
                let _ = self.infer_type(target, scope)?;
                self.record_property(property);
                SemanticType::PropertyValue
            }
            CypherExpression::FunctionCall {
                name, arguments, ..
            } => {
                for argument in arguments {
                    let _ = self.infer_type(argument, scope)?;
                }
                match name.to_ascii_uppercase().as_str() {
                    "COUNT" => SemanticType::Integer,
                    "AVG" => SemanticType::Float,
                    "COLLECT" => SemanticType::List,
                    _ => SemanticType::PropertyValue,
                }
            }
            CypherExpression::BinaryOp { left, op, right } => {
                let left_ty = self.infer_type(left, scope)?;
                let right_ty = self.infer_type(right, scope)?;
                if *op == CypherBinaryOperator::VectorDistance {
                    SemanticType::Float
                } else if matches!(
                    op,
                    CypherBinaryOperator::Add
                        | CypherBinaryOperator::Subtract
                        | CypherBinaryOperator::Multiply
                        | CypherBinaryOperator::Divide
                ) {
                    if left_ty == SemanticType::Float || right_ty == SemanticType::Float {
                        SemanticType::Float
                    } else if left_ty == SemanticType::Integer && right_ty == SemanticType::Integer
                    {
                        SemanticType::Integer
                    } else {
                        SemanticType::PropertyValue
                    }
                } else {
                    SemanticType::Boolean
                }
            }
            CypherExpression::UnaryOp { op, expr } => {
                let inner = self.infer_type(expr, scope)?;
                if *op == CypherUnaryOperator::Not {
                    SemanticType::Boolean
                } else {
                    inner
                }
            }
            CypherExpression::ListLiteral(values) => {
                for value in values {
                    let _ = self.infer_type(value, scope)?;
                }
                SemanticType::List
            }
            CypherExpression::MapLiteral(values) => {
                for (_, value) in values {
                    let _ = self.infer_type(value, scope)?;
                }
                SemanticType::Map
            }
            CypherExpression::ListComprehension {
                variable,
                list,
                predicate,
                projection,
            } => {
                let _ = self.infer_type(list, scope)?;
                let mut nested = scope.clone();
                nested.insert(
                    variable.clone(),
                    ScopeBinding::new(SemanticType::PropertyValue),
                );
                let _ = predicate
                    .as_ref()
                    .map(|value| self.infer_type(value, &nested))
                    .transpose()?;
                let _ = projection
                    .as_ref()
                    .map(|value| self.infer_type(value, &nested))
                    .transpose()?;
                SemanticType::List
            }
            CypherExpression::Subscript { base, index, end } => {
                let _ = self.infer_type(base, scope)?;
                let _ = self.infer_type(index, scope)?;
                let _ = end
                    .as_ref()
                    .map(|value| self.infer_type(value, scope))
                    .transpose()?;
                if end.is_some() {
                    SemanticType::List
                } else {
                    SemanticType::PropertyValue
                }
            }
            CypherExpression::MapProjection { base, keys } => {
                let _ = self.infer_type(base, scope)?;
                for key in keys {
                    self.record_property(key);
                }
                SemanticType::Map
            }
            CypherExpression::PatternComprehension {
                pattern,
                predicate,
                projection,
                ..
            } => {
                let mut nested = scope.clone();
                self.analyze_pattern(pattern, &mut nested)?;
                let _ = predicate
                    .as_ref()
                    .map(|value| self.infer_type(value, &nested))
                    .transpose()?;
                let _ = self.infer_type(projection, &nested)?;
                SemanticType::List
            }
            CypherExpression::CaseExpression {
                base,
                when_then,
                else_expr,
            } => {
                let _ = base
                    .as_ref()
                    .map(|value| self.infer_type(value, scope))
                    .transpose()?;
                let mut out = SemanticType::Unknown;
                for (when_expr, then_expr) in when_then {
                    let _ = self.infer_type(when_expr, scope)?;
                    let then_ty = self.infer_type(then_expr, scope)?;
                    if out == SemanticType::Unknown {
                        out = then_ty;
                    }
                }
                let else_ty = else_expr
                    .as_ref()
                    .map(|value| self.infer_type(value, scope))
                    .transpose()?;
                out = if out == SemanticType::Unknown {
                    else_ty.unwrap_or(out)
                } else {
                    out
                };
                out
            }
            CypherExpression::ExistsSubquery { .. } => SemanticType::Boolean,
        };
        self.expression_types.push(ExpressionTypeAnnotation {
            expression: expr.clone(),
            inferred_type: ty,
        });
        Ok(ty)
    }
}

fn bind_variable(
    scope: &mut BTreeMap<String, ScopeBinding>,
    name: &str,
    variable_type: SemanticType,
) -> Result<(), AnalysisError> {
    if let Some(existing) = scope.get(name) {
        if existing.variable_type != variable_type {
            return Err(AnalysisError::new(format!(
                "variable '{name}' reused with incompatible type"
            )));
        }
        return Ok(());
    }
    scope.insert(name.to_string(), ScopeBinding::new(variable_type));
    Ok(())
}

fn projection_output_name(item: &ProjectionItem) -> Option<String> {
    item.alias.clone().or_else(|| match &item.expression {
        CypherExpression::Identifier(name) => Some(name.clone()),
        CypherExpression::PropertyAccess { property, .. } => Some(property.clone()),
        _ => None,
    })
}

fn validate_aggregation_usage(
    items: &[ProjectionItem],
    order_by: &[OrderByItem],
    context: &str,
) -> Result<(), AnalysisError> {
    let has_aggregate = items
        .iter()
        .any(|item| expression_contains_aggregate(&item.expression));
    if !has_aggregate {
        return Ok(());
    }
    for item in items {
        if expression_contains_aggregate(&item.expression)
            || expression_is_group_key(&item.expression)
        {
            continue;
        }
        return Err(AnalysisError::new(format!(
            "invalid aggregation in {context}: non-aggregate expression must be grouped"
        )));
    }
    for entry in order_by {
        if expression_contains_aggregate(&entry.expression)
            || expression_is_group_key(&entry.expression)
        {
            continue;
        }
        return Err(AnalysisError::new(format!(
            "invalid aggregation in {context}: ORDER BY expression must be grouped or aggregated"
        )));
    }
    Ok(())
}

fn walk_expression<'a, F: FnMut(&'a CypherExpression)>(expr: &'a CypherExpression, f: &mut F) {
    f(expr);
    match expr {
        CypherExpression::PropertyAccess { target, .. } => walk_expression(target, f),
        CypherExpression::FunctionCall { arguments, .. }
        | CypherExpression::ListLiteral(arguments) => {
            for argument in arguments {
                walk_expression(argument, f);
            }
        }
        CypherExpression::BinaryOp { left, right, .. } => {
            walk_expression(left, f);
            walk_expression(right, f);
        }
        CypherExpression::UnaryOp { expr, .. } => walk_expression(expr, f),
        CypherExpression::MapLiteral(entries) => {
            for (_, value) in entries {
                walk_expression(value, f);
            }
        }
        CypherExpression::ListComprehension {
            list,
            predicate,
            projection,
            ..
        } => {
            walk_expression(list, f);
            if let Some(predicate) = predicate {
                walk_expression(predicate, f);
            }
            if let Some(projection) = projection {
                walk_expression(projection, f);
            }
        }
        CypherExpression::Subscript { base, index, end } => {
            walk_expression(base, f);
            walk_expression(index, f);
            if let Some(end) = end {
                walk_expression(end, f);
            }
        }
        CypherExpression::MapProjection { base, .. } => {
            walk_expression(base, f);
        }
        CypherExpression::PatternComprehension {
            predicate,
            projection,
            ..
        } => {
            if let Some(predicate) = predicate {
                walk_expression(predicate, f);
            }
            walk_expression(projection, f);
        }
        CypherExpression::CaseExpression {
            base,
            when_then,
            else_expr,
        } => {
            if let Some(base) = base {
                walk_expression(base, f);
            }
            for (when_expr, then_expr) in when_then {
                walk_expression(when_expr, f);
                walk_expression(then_expr, f);
            }
            if let Some(else_expr) = else_expr {
                walk_expression(else_expr, f);
            }
        }
        CypherExpression::ExistsSubquery { .. }
        | CypherExpression::Identifier(_)
        | CypherExpression::Literal(_)
        | CypherExpression::Parameter(_) => {}
    }
}

fn expression_contains_aggregate(expr: &CypherExpression) -> bool {
    let mut found = false;
    walk_expression(expr, &mut |candidate| {
        if let CypherExpression::FunctionCall { name, .. } = candidate {
            found |= is_aggregate_function_name(name);
        }
    });
    found
}

fn expression_is_group_key(expr: &CypherExpression) -> bool {
    matches!(
        expr,
        CypherExpression::Identifier(_)
            | CypherExpression::PropertyAccess { .. }
            | CypherExpression::Literal(_)
            | CypherExpression::Parameter(_)
    )
}

fn is_aggregate_function_name(name: &str) -> bool {
    matches!(
        name.to_ascii_uppercase().as_str(),
        "SUM" | "COUNT" | "AVG" | "MIN" | "MAX" | "COLLECT"
    )
}

fn collect_aggregate_functions(items: &[ProjectionItem]) -> Vec<AggregateFunction> {
    let mut out = Vec::<AggregateFunction>::new();
    for item in items {
        walk_expression(&item.expression, &mut |candidate| {
            if let CypherExpression::FunctionCall {
                name,
                distinct,
                arguments,
            } = candidate
            {
                if is_aggregate_function_name(name) {
                    out.push(AggregateFunction {
                        name: name.to_ascii_lowercase(),
                        distinct: *distinct,
                        arguments: arguments.clone(),
                        alias: item.alias.clone(),
                    });
                }
            }
        });
    }
    out
}

fn expression_references_within(expr: &CypherExpression, bound: &BTreeSet<String>) -> bool {
    let mut referenced = BTreeSet::<String>::new();
    walk_expression(expr, &mut |candidate| {
        if let CypherExpression::Identifier(name) = candidate {
            referenced.insert(name.clone());
        }
    });
    referenced.is_subset(bound)
}

/// Internal variable name carried by the synthetic unit-row source planted
/// for bare `RETURN` / `WITH` (no MATCH / UNWIND / etc. preceding). The
/// name is intentionally long and unidiomatic to avoid colliding with any
/// user-bound identifier — `Project` and `Aggregate` never enumerate it,
/// so it stays invisible in the output regardless of collisions.
const BARE_RETURN_SYNTHETIC_VARIABLE: &str = "__ogdb_internal_bare_return_unit_row__";

/// Build the implicit single-empty-row source that every Cypher query has
/// before its first clause. Used when `aggregate_and_project` is called
/// without an upstream plan (e.g. `RETURN 1 AS x` standing alone) — per
/// Cypher semantics the projection still runs once. We model this by
/// reusing `UnwindList`'s existing `input: None` handling: unwinding a
/// one-element list yields exactly one row regardless of graph state.
fn synthetic_unit_row_source() -> LogicalPlan {
    LogicalPlan::UnwindList {
        input: None,
        expression: CypherExpression::ListLiteral(vec![CypherExpression::Literal(
            CypherLiteral::Integer(1),
        )]),
        variable: BARE_RETURN_SYNTHETIC_VARIABLE.to_string(),
    }
}

fn aggregate_and_project(
    input: Option<LogicalPlan>,
    items: &[ProjectionItem],
    distinct: bool,
) -> LogicalPlan {
    let mut plan = input.unwrap_or_else(synthetic_unit_row_source);
    if distinct
        || items
            .iter()
            .any(|item| expression_contains_aggregate(&item.expression))
    {
        plan = LogicalPlan::Aggregate {
            input: Box::new(plan),
            group_keys: items
                .iter()
                .filter(|item| !expression_contains_aggregate(&item.expression))
                .map(|item| item.expression.clone())
                .collect(),
            aggregates: collect_aggregate_functions(items),
        };
    }
    LogicalPlan::Project {
        input: Box::new(plan),
        expressions: items.to_vec(),
        distinct,
    }
}

fn build_logical_plan(model: &SemanticModel) -> Result<LogicalPlan, PlanError> {
    let mut plan = None::<LogicalPlan>;
    for clause in &model.query.clauses {
        let current = plan.take();
        let next = match clause {
            CypherClause::Match(value) => plan_match_clause(current, value)?,
            CypherClause::Create(value) => LogicalPlan::Create {
                input: current.map(Box::new),
                patterns: value.patterns.clone(),
            },
            CypherClause::CreateIndex(value) => {
                if current.is_some() {
                    return Err(PlanError::new(
                        "CREATE INDEX cannot be chained with other clauses",
                    ));
                }
                LogicalPlan::CreateIndex {
                    label: value.label.clone(),
                    property_keys: value.property_keys.clone(),
                }
            }
            CypherClause::Delete(value) => LogicalPlan::Delete {
                input: Box::new(
                    current
                        .ok_or_else(|| PlanError::new("DELETE requires an upstream plan input"))?,
                ),
                expressions: value.expressions.clone(),
                detach: value.detach,
            },
            CypherClause::Set(value) => LogicalPlan::SetProperties {
                input: Box::new(
                    current.ok_or_else(|| PlanError::new("SET requires an upstream plan input"))?,
                ),
                assignments: value.assignments.clone(),
            },
            CypherClause::Remove(value) => LogicalPlan::RemoveProperties {
                input: Box::new(
                    current
                        .ok_or_else(|| PlanError::new("REMOVE requires an upstream plan input"))?,
                ),
                targets: value.targets.clone(),
            },
            CypherClause::With(value) => {
                let mut out = aggregate_and_project(current, &value.items, value.distinct);
                if let Some(predicate) = &value.where_predicate {
                    out = LogicalPlan::Filter {
                        input: Box::new(out),
                        predicate: predicate.clone(),
                    };
                }
                out
            }
            CypherClause::Unwind(value) => LogicalPlan::UnwindList {
                input: current.map(Box::new),
                expression: value.expression.clone(),
                variable: value.variable.clone(),
            },
            CypherClause::Merge(value) => LogicalPlan::Merge {
                input: current.map(Box::new),
                pattern: value.pattern.clone(),
                on_create: value.on_create_set.clone(),
                on_match: value.on_match_set.clone(),
            },
        };
        plan = Some(next);
    }

    if let Some(return_clause) = &model.query.return_clause {
        let mut out =
            aggregate_and_project(plan.take(), &return_clause.items, return_clause.distinct);
        if !return_clause.order_by.is_empty() {
            out = LogicalPlan::Sort {
                input: Box::new(out),
                keys: return_clause.order_by.clone(),
            };
        }
        if let Some(skip) = return_clause.skip {
            out = LogicalPlan::Skip {
                input: Box::new(out),
                count: skip,
            };
        }
        if let Some(limit) = return_clause.limit {
            out = LogicalPlan::Limit {
                input: Box::new(out),
                count: limit,
            };
        }
        plan = Some(out);
    }

    plan.ok_or_else(|| PlanError::new("query produced no logical plan"))
}

fn logical_plan_output_columns(plan: &LogicalPlan) -> Vec<String> {
    match plan {
        LogicalPlan::Scan { variable, .. }
        | LogicalPlan::VectorScan { variable, .. }
        | LogicalPlan::TextSearch { variable, .. } => {
            vec![variable.clone().unwrap_or_else(|| "_anon".to_string())]
        }
        LogicalPlan::Expand {
            input,
            to,
            edge_variable,
            ..
        } => {
            let mut columns = logical_plan_output_columns(input);
            if let Some(edge_variable) = edge_variable
                .as_ref()
                .filter(|value| !columns.contains(*value))
            {
                columns.push(edge_variable.clone());
            }
            if let Some(to) = to.as_ref().filter(|value| !columns.contains(*value)) {
                columns.push(to.clone());
            }
            columns
        }
        LogicalPlan::CartesianProduct { left, right } => {
            let mut columns = logical_plan_output_columns(left);
            for column in logical_plan_output_columns(right) {
                if !columns.contains(&column) {
                    columns.push(column);
                }
            }
            columns
        }
        LogicalPlan::Filter { input, .. }
        | LogicalPlan::Sort { input, .. }
        | LogicalPlan::Limit { input, .. }
        | LogicalPlan::Skip { input, .. }
        | LogicalPlan::Delete { input, .. }
        | LogicalPlan::SetProperties { input, .. }
        | LogicalPlan::RemoveProperties { input, .. } => logical_plan_output_columns(input),
        LogicalPlan::Project { expressions, .. } => projection_output_columns(expressions),
        LogicalPlan::Aggregate {
            group_keys,
            aggregates,
            ..
        } => {
            let mut columns = group_keys.iter().map(expression_key).collect::<Vec<_>>();
            columns.extend(aggregates.iter().map(|aggregate| {
                aggregate.alias.clone().unwrap_or_else(|| {
                    format!(
                        "{}({})",
                        aggregate.name,
                        aggregate
                            .arguments
                            .iter()
                            .map(expression_key)
                            .collect::<Vec<_>>()
                            .join(", ")
                    )
                })
            }));
            columns
        }
        LogicalPlan::Create { input, patterns } => {
            if let Some(input) = input {
                return logical_plan_output_columns(input);
            }
            let mut columns = Vec::<String>::new();
            let mut push_unique = |value: &Option<String>| {
                if let Some(variable) = value.as_ref().filter(|v| !columns.contains(*v)) {
                    columns.push(variable.clone());
                }
            };
            for pattern in patterns {
                push_unique(&pattern.start.variable);
                for chain in &pattern.chains {
                    push_unique(&chain.relationship.variable);
                    push_unique(&chain.node.variable);
                }
            }
            columns
        }
        LogicalPlan::CreateIndex { .. } => Vec::new(),
        LogicalPlan::UnwindList {
            input, variable, ..
        } => {
            let mut columns = input
                .as_ref()
                .map(|plan| logical_plan_output_columns(plan))
                .unwrap_or_default();
            if !columns.contains(variable) {
                columns.push(variable.clone());
            }
            columns
        }
        LogicalPlan::Merge { input, pattern, .. } => {
            if let Some(input) = input {
                return logical_plan_output_columns(input);
            }
            let mut columns = Vec::<String>::new();
            let mut push_unique = |value: &Option<String>| {
                if let Some(variable) = value.as_ref().filter(|v| !columns.contains(*v)) {
                    columns.push(variable.clone());
                }
            };
            push_unique(&pattern.start.variable);
            for chain in &pattern.chains {
                push_unique(&chain.relationship.variable);
                push_unique(&chain.node.variable);
            }
            columns
        }
    }
}

fn node_pattern_property_predicate(node: &NodePattern, variable: &str) -> Option<CypherExpression> {
    let properties = node.properties.as_ref()?;
    let mut predicates = properties
        .iter()
        .map(|(key, value)| CypherExpression::BinaryOp {
            left: Box::new(CypherExpression::PropertyAccess {
                target: Box::new(CypherExpression::Identifier(variable.to_string())),
                property: key.clone(),
            }),
            op: CypherBinaryOperator::Eq,
            right: Box::new(value.clone()),
        });
    let mut predicate = predicates.next()?;
    for next in predicates {
        predicate = CypherExpression::BinaryOp {
            left: Box::new(predicate),
            op: CypherBinaryOperator::And,
            right: Box::new(next),
        };
    }
    Some(predicate)
}

fn plan_match_clause(
    current: Option<LogicalPlan>,
    clause: &MatchClause,
) -> Result<LogicalPlan, PlanError> {
    let mut plan = current;
    let mut bound = plan
        .as_ref()
        .map(logical_plan_output_columns)
        .unwrap_or_default()
        .into_iter()
        .collect::<BTreeSet<_>>();
    let mut where_applied = false;

    for pattern in &clause.patterns {
        let start_name = pattern
            .start
            .variable
            .clone()
            .unwrap_or_else(|| "_anon".to_string());
        let start_is_bound = pattern
            .start
            .variable
            .as_ref()
            .map(|name| bound.contains(name))
            .unwrap_or(false);

        let mut inner = if start_is_bound {
            plan.take()
                .ok_or_else(|| PlanError::new("invalid MATCH plan state"))?
        } else {
            let mut scan = LogicalPlan::Scan {
                label: pattern.start.labels.first().cloned(),
                variable: pattern.start.variable.clone(),
            };

            if let Some(predicate) = &clause.where_predicate {
                if let Some(variable_name) = pattern.start.variable.as_deref() {
                    if let Some((property_key, query_vector, _threshold)) =
                        extract_vector_distance_filter(predicate, variable_name)
                    {
                        scan = LogicalPlan::VectorScan {
                            label: pattern.start.labels.first().cloned(),
                            variable: pattern.start.variable.clone(),
                            property_key,
                            query_vector,
                            k: QUERY_BATCH_SIZE as u64,
                            metric: None,
                        };
                    } else if let Some((property_key, query_text)) =
                        extract_contains_text_filter(predicate, variable_name)
                    {
                        scan = LogicalPlan::TextSearch {
                            label: pattern.start.labels.first().cloned(),
                            variable: pattern.start.variable.clone(),
                            property_key,
                            query_text,
                            k: QUERY_BATCH_SIZE as u64,
                        };
                    }
                }
            }

            if let Some(predicate) = node_pattern_property_predicate(&pattern.start, &start_name) {
                scan = LogicalPlan::Filter {
                    input: Box::new(scan),
                    predicate,
                };
            }

            if let Some(existing) = plan.take() {
                LogicalPlan::CartesianProduct {
                    left: Box::new(existing),
                    right: Box::new(scan),
                }
            } else {
                scan
            }
        };

        if start_is_bound {
            if let Some(predicate) = node_pattern_property_predicate(&pattern.start, &start_name) {
                inner = LogicalPlan::Filter {
                    input: Box::new(inner),
                    predicate,
                };
            }
        }

        let mut pattern_bound = bound.clone();
        if let Some(name) = &pattern.start.variable {
            pattern_bound.insert(name.clone());
        }
        if !where_applied {
            if let Some(predicate) = &clause.where_predicate {
                if expression_references_within(predicate, &pattern_bound) {
                    inner = LogicalPlan::Filter {
                        input: Box::new(inner),
                        predicate: predicate.clone(),
                    };
                    where_applied = true;
                }
            }
        }

        let mut from = start_name;
        for (offset, chain) in pattern.chains.iter().enumerate() {
            inner = LogicalPlan::Expand {
                input: Box::new(inner),
                from: from.clone(),
                edge_type: chain.relationship.rel_type.clone(),
                direction: chain.relationship.direction,
                to: chain.node.variable.clone(),
                edge_variable: chain.relationship.variable.clone(),
                temporal_filter: clause.temporal_filter.clone(),
            };
            if let Some(name) = &chain.relationship.variable {
                pattern_bound.insert(name.clone());
            }
            if let Some(name) = &chain.node.variable {
                pattern_bound.insert(name.clone());
                from = name.clone();
            } else {
                from = format!("_anon_{offset}");
            }
        }

        if !where_applied {
            if let Some(predicate) = &clause.where_predicate {
                if expression_references_within(predicate, &pattern_bound) {
                    inner = LogicalPlan::Filter {
                        input: Box::new(inner),
                        predicate: predicate.clone(),
                    };
                    where_applied = true;
                }
            }
        }

        bound = pattern_bound;
        plan = Some(inner);
    }

    let mut plan =
        plan.ok_or_else(|| PlanError::new("MATCH clause requires at least one pattern"))?;
    if !where_applied {
        if let Some(predicate) = &clause.where_predicate {
            plan = LogicalPlan::Filter {
                input: Box::new(plan),
                predicate: predicate.clone(),
            };
        }
    }
    Ok(plan)
}

fn estimate_filter_selectivity(predicate: &CypherExpression) -> f64 {
    match predicate {
        CypherExpression::BinaryOp { left, op, right } => match op {
            CypherBinaryOperator::Eq | CypherBinaryOperator::Is => 0.15,
            CypherBinaryOperator::NotEq | CypherBinaryOperator::IsNot => 0.85,
            CypherBinaryOperator::LessThan
            | CypherBinaryOperator::GreaterThan
            | CypherBinaryOperator::LessThanOrEqual
            | CypherBinaryOperator::GreaterThanOrEqual
            | CypherBinaryOperator::VectorDistance => 0.35,
            CypherBinaryOperator::RegexMatch => 0.20,
            CypherBinaryOperator::ContainsText => 0.15,
            CypherBinaryOperator::And => (estimate_filter_selectivity(left)
                * estimate_filter_selectivity(right))
            .clamp(0.01, 1.0),
            CypherBinaryOperator::Or => (estimate_filter_selectivity(left)
                + estimate_filter_selectivity(right)
                - estimate_filter_selectivity(left) * estimate_filter_selectivity(right))
            .clamp(0.01, 1.0),
            CypherBinaryOperator::Xor => 0.5,
            _ => 0.5,
        },
        CypherExpression::UnaryOp {
            op: CypherUnaryOperator::Not,
            expr,
        } => (1.0 - estimate_filter_selectivity(expr)).clamp(0.01, 1.0),
        _ => 0.5,
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum IndexPredicateOperator {
    Eq,
    LessThan,
    LessThanOrEqual,
    GreaterThan,
    GreaterThanOrEqual,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct IndexPredicate {
    property_key: String,
    operator: IndexPredicateOperator,
    value: PropertyValue,
}

#[derive(Debug, Clone, Default)]
struct PropertyConstraint {
    equals: Option<PropertyValue>,
    lower: Option<(PropertyValue, bool)>,
    upper: Option<(PropertyValue, bool)>,
    unsatisfiable: bool,
}

impl PropertyConstraint {
    fn from_predicates(predicates: &[IndexPredicate]) -> Self {
        let mut constraint = Self::default();
        for predicate in predicates {
            constraint.apply(predicate.operator, &predicate.value);
        }
        constraint
    }

    fn apply(&mut self, operator: IndexPredicateOperator, value: &PropertyValue) {
        match operator {
            IndexPredicateOperator::Eq => {
                if let Some(existing) = &self.equals {
                    if existing != value {
                        self.unsatisfiable = true;
                    }
                } else {
                    self.equals = Some(value.clone());
                }
            }
            IndexPredicateOperator::LessThan => {
                self.tighten_upper(value, false);
            }
            IndexPredicateOperator::LessThanOrEqual => {
                self.tighten_upper(value, true);
            }
            IndexPredicateOperator::GreaterThan => {
                self.tighten_lower(value, false);
            }
            IndexPredicateOperator::GreaterThanOrEqual => {
                self.tighten_lower(value, true);
            }
        }
        self.validate_equality_bounds();
    }

    fn tighten_lower(&mut self, candidate: &PropertyValue, inclusive: bool) {
        if self.unsatisfiable {
            return;
        }
        if let Some((current, current_inclusive)) = &self.lower {
            match compare_property_values(candidate, current) {
                Some(std::cmp::Ordering::Greater) => {
                    self.lower = Some((candidate.clone(), inclusive));
                }
                Some(std::cmp::Ordering::Equal) => {
                    self.lower = Some((candidate.clone(), *current_inclusive && inclusive));
                }
                Some(std::cmp::Ordering::Less) => {}
                None => self.unsatisfiable = true,
            }
            return;
        }
        self.lower = Some((candidate.clone(), inclusive));
    }

    fn tighten_upper(&mut self, candidate: &PropertyValue, inclusive: bool) {
        if self.unsatisfiable {
            return;
        }
        if let Some((current, current_inclusive)) = &self.upper {
            match compare_property_values(candidate, current) {
                Some(std::cmp::Ordering::Less) => {
                    self.upper = Some((candidate.clone(), inclusive));
                }
                Some(std::cmp::Ordering::Equal) => {
                    self.upper = Some((candidate.clone(), *current_inclusive && inclusive));
                }
                Some(std::cmp::Ordering::Greater) => {}
                None => self.unsatisfiable = true,
            }
            return;
        }
        self.upper = Some((candidate.clone(), inclusive));
    }

    fn validate_equality_bounds(&mut self) {
        if self.unsatisfiable {
            return;
        }
        let Some(equal) = self.equals.as_ref() else {
            return;
        };
        if let Some((lower, inclusive)) = &self.lower {
            match compare_property_values(equal, lower) {
                Some(std::cmp::Ordering::Less) => self.unsatisfiable = true,
                Some(std::cmp::Ordering::Equal) if !inclusive => self.unsatisfiable = true,
                Some(_) => {}
                None => self.unsatisfiable = true,
            }
        }
        if let Some((upper, inclusive)) = &self.upper {
            match compare_property_values(equal, upper) {
                Some(std::cmp::Ordering::Greater) => self.unsatisfiable = true,
                Some(std::cmp::Ordering::Equal) if !inclusive => self.unsatisfiable = true,
                Some(_) => {}
                None => self.unsatisfiable = true,
            }
        }
    }

    fn matches(&self, value: &PropertyValue) -> bool {
        if self.unsatisfiable {
            return false;
        }
        if let Some(equal) = &self.equals {
            if value != equal {
                return false;
            }
        }
        if let Some((lower, inclusive)) = &self.lower {
            match compare_property_values(value, lower) {
                Some(std::cmp::Ordering::Less) => return false,
                Some(std::cmp::Ordering::Equal) if !inclusive => return false,
                Some(_) => {}
                None => return false,
            }
        }
        if let Some((upper, inclusive)) = &self.upper {
            match compare_property_values(value, upper) {
                Some(std::cmp::Ordering::Greater) => return false,
                Some(std::cmp::Ordering::Equal) if !inclusive => return false,
                Some(_) => {}
                None => return false,
            }
        }
        true
    }

    fn is_equality_only(&self) -> bool {
        self.equals.is_some() && self.lower.is_none() && self.upper.is_none() && !self.unsatisfiable
    }
}

fn collect_index_predicates_for_variable(
    predicate: &CypherExpression,
    variable: &str,
    out: &mut Vec<IndexPredicate>,
) {
    match predicate {
        CypherExpression::BinaryOp {
            left,
            op: CypherBinaryOperator::And,
            right,
        } => {
            collect_index_predicates_for_variable(left, variable, out);
            collect_index_predicates_for_variable(right, variable, out);
        }
        _ => {
            if let Some(predicate) = parse_index_predicate(predicate, variable) {
                out.push(predicate);
            }
        }
    }
}

fn parse_index_predicate(predicate: &CypherExpression, variable: &str) -> Option<IndexPredicate> {
    let CypherExpression::BinaryOp { left, op, right } = predicate else {
        return None;
    };
    let operator = match op {
        CypherBinaryOperator::Eq => IndexPredicateOperator::Eq,
        CypherBinaryOperator::LessThan => IndexPredicateOperator::LessThan,
        CypherBinaryOperator::LessThanOrEqual => IndexPredicateOperator::LessThanOrEqual,
        CypherBinaryOperator::GreaterThan => IndexPredicateOperator::GreaterThan,
        CypherBinaryOperator::GreaterThanOrEqual => IndexPredicateOperator::GreaterThanOrEqual,
        _ => return None,
    };
    if let Some(property_key) = property_access_key_for_variable(left, variable) {
        let value = expression_to_index_value(right)?;
        return Some(IndexPredicate {
            property_key,
            operator,
            value,
        });
    }
    if let Some(property_key) = property_access_key_for_variable(right, variable) {
        let value = expression_to_index_value(left)?;
        return Some(IndexPredicate {
            property_key,
            operator: invert_index_operator(operator),
            value,
        });
    }
    None
}

fn property_access_key_for_variable(expr: &CypherExpression, variable: &str) -> Option<String> {
    let CypherExpression::PropertyAccess { target, property } = expr else {
        return None;
    };
    match target.as_ref() {
        CypherExpression::Identifier(name) if name == variable => Some(property.clone()),
        _ => None,
    }
}

fn expression_to_index_value(expr: &CypherExpression) -> Option<PropertyValue> {
    match expr {
        CypherExpression::Literal(CypherLiteral::Boolean(value)) => {
            Some(PropertyValue::Bool(*value))
        }
        CypherExpression::Literal(CypherLiteral::Integer(value)) => {
            Some(PropertyValue::I64(*value))
        }
        CypherExpression::Literal(CypherLiteral::Float(value)) => Some(PropertyValue::F64(*value)),
        CypherExpression::Literal(CypherLiteral::String(value)) => {
            Some(PropertyValue::String(value.clone()))
        }
        CypherExpression::Parameter(name) => Some(PropertyValue::String(format!("${name}"))),
        _ => None,
    }
}

fn expression_to_vector_literal(expr: &CypherExpression) -> Option<Vec<f32>> {
    let CypherExpression::ListLiteral(values) = expr else {
        return None;
    };
    let mut out = Vec::<f32>::with_capacity(values.len());
    for value in values {
        match value {
            CypherExpression::Literal(CypherLiteral::Integer(value)) => out.push(*value as f32),
            CypherExpression::Literal(CypherLiteral::Float(value)) => out.push(*value as f32),
            _ => return None,
        }
    }
    Some(out)
}

fn expression_to_f32_literal(expr: &CypherExpression) -> Option<f32> {
    match expr {
        CypherExpression::Literal(CypherLiteral::Integer(value)) => Some(*value as f32),
        CypherExpression::Literal(CypherLiteral::Float(value)) => Some(*value as f32),
        _ => None,
    }
}

fn extract_vector_distance_filter(
    predicate: &CypherExpression,
    variable: &str,
) -> Option<(String, Vec<f32>, f32)> {
    match predicate {
        CypherExpression::BinaryOp {
            left,
            op: CypherBinaryOperator::And,
            right,
        } => extract_vector_distance_filter(left, variable)
            .or_else(|| extract_vector_distance_filter(right, variable)),
        CypherExpression::BinaryOp {
            left,
            op: CypherBinaryOperator::LessThan | CypherBinaryOperator::LessThanOrEqual,
            right,
        } => {
            let threshold = expression_to_f32_literal(right)?;
            let CypherExpression::BinaryOp {
                left: distance_left,
                op: CypherBinaryOperator::VectorDistance,
                right: distance_right,
            } = left.as_ref()
            else {
                return None;
            };

            if let Some(property_key) = property_access_key_for_variable(distance_left, variable) {
                let query_vector = expression_to_vector_literal(distance_right)?;
                return Some((property_key, query_vector, threshold));
            }
            if let Some(property_key) = property_access_key_for_variable(distance_right, variable) {
                let query_vector = expression_to_vector_literal(distance_left)?;
                return Some((property_key, query_vector, threshold));
            }
            None
        }
        _ => None,
    }
}

fn extract_contains_text_filter(
    predicate: &CypherExpression,
    variable: &str,
) -> Option<(String, String)> {
    match predicate {
        CypherExpression::BinaryOp {
            left,
            op: CypherBinaryOperator::And,
            right,
        } => extract_contains_text_filter(left, variable)
            .or_else(|| extract_contains_text_filter(right, variable)),
        CypherExpression::BinaryOp {
            left,
            op: CypherBinaryOperator::ContainsText,
            right,
        } => {
            let property_key = property_access_key_for_variable(left, variable)?;
            match right.as_ref() {
                CypherExpression::Literal(CypherLiteral::String(value)) => {
                    Some((property_key, value.clone()))
                }
                CypherExpression::Parameter(name) => Some((property_key, format!("${name}"))),
                _ => None,
            }
        }
        _ => None,
    }
}

fn invert_index_operator(operator: IndexPredicateOperator) -> IndexPredicateOperator {
    match operator {
        IndexPredicateOperator::Eq => IndexPredicateOperator::Eq,
        IndexPredicateOperator::LessThan => IndexPredicateOperator::GreaterThan,
        IndexPredicateOperator::LessThanOrEqual => IndexPredicateOperator::GreaterThanOrEqual,
        IndexPredicateOperator::GreaterThan => IndexPredicateOperator::LessThan,
        IndexPredicateOperator::GreaterThanOrEqual => IndexPredicateOperator::LessThanOrEqual,
    }
}

fn normalize_index_definition(
    label: &str,
    property_keys: &[String],
) -> Result<IndexDefinition, DbError> {
    let label = label.trim();
    if label.is_empty() {
        return Err(DbError::InvalidArgument(
            "index label cannot be empty".to_string(),
        ));
    }
    if property_keys.is_empty() {
        return Err(DbError::InvalidArgument(
            "index must include at least one property key".to_string(),
        ));
    }
    let mut normalized = Vec::<String>::with_capacity(property_keys.len());
    let mut seen = BTreeSet::<String>::new();
    for key in property_keys {
        let key = key.trim();
        if key.is_empty() {
            return Err(DbError::InvalidArgument(
                "index property key cannot be empty".to_string(),
            ));
        }
        if !seen.insert(key.to_string()) {
            return Err(DbError::InvalidArgument(format!(
                "duplicate property key in index definition: {key}"
            )));
        }
        normalized.push(key.to_string());
    }
    Ok(IndexDefinition {
        label: label.to_string(),
        property_keys: normalized,
    })
}

fn normalize_vector_index_definition(
    name: &str,
    label: Option<&str>,
    property_key: &str,
    dimensions: usize,
    metric: VectorDistanceMetric,
) -> Result<VectorIndexDefinition, DbError> {
    let name = name.trim();
    if name.is_empty() {
        return Err(DbError::InvalidArgument(
            "vector index name cannot be empty".to_string(),
        ));
    }
    let property_key = property_key.trim();
    if property_key.is_empty() {
        return Err(DbError::InvalidArgument(
            "vector index property key cannot be empty".to_string(),
        ));
    }
    if dimensions == 0 || dimensions > VECTOR_MAX_DIMENSIONS {
        return Err(DbError::InvalidArgument(format!(
            "vector index dimensions must be between 1 and {VECTOR_MAX_DIMENSIONS}"
        )));
    }
    Ok(VectorIndexDefinition {
        name: name.to_string(),
        label: label
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        property_key: property_key.to_string(),
        dimensions,
        metric,
    })
}

fn normalize_fulltext_index_definition(
    name: &str,
    label: Option<&str>,
    property_keys: &[String],
) -> Result<FullTextIndexDefinition, DbError> {
    normalize_fulltext_index_definition_pure(name, label, property_keys)
        .map_err(DbError::InvalidArgument)
}

fn composite_prefix_len(
    definition: &IndexDefinition,
    constraints: &BTreeMap<String, PropertyConstraint>,
) -> usize {
    if definition.property_keys.len() <= 1 {
        return 0;
    }
    let mut prefix_len = 0usize;
    for key in &definition.property_keys {
        let Some(constraint) = constraints.get(key) else {
            break;
        };
        prefix_len += 1;
        if !constraint.is_equality_only() {
            break;
        }
    }
    prefix_len
}

fn lookup_single_index_nodes(index: &BTreeIndex, constraint: &PropertyConstraint) -> Vec<u64> {
    if constraint.unsatisfiable {
        return Vec::new();
    }
    if let Some(value) = constraint.equals.as_ref() {
        if constraint.lower.is_none() && constraint.upper.is_none() {
            return index.entries.get(value).cloned().unwrap_or_default();
        }
    }
    let mut out = Vec::<u64>::new();
    for (candidate, node_ids) in &index.entries {
        if constraint.matches(candidate) {
            out.extend(node_ids.iter().copied());
        }
    }
    out.sort_unstable();
    out.dedup();
    out
}

fn lookup_composite_index_nodes(
    index: &CompositeIndex,
    prefix_keys: &[String],
    constraints: &BTreeMap<String, PropertyConstraint>,
) -> Vec<u64> {
    if prefix_keys.is_empty() {
        return Vec::new();
    }
    let mut out = Vec::<u64>::new();
    for (tuple, node_ids) in &index.entries {
        if tuple.len() < prefix_keys.len() {
            continue;
        }
        let mut matches_prefix = true;
        for (idx, key) in prefix_keys.iter().enumerate() {
            let Some(constraint) = constraints.get(key) else {
                matches_prefix = false;
                break;
            };
            if !constraint.matches(&tuple[idx]) {
                matches_prefix = false;
                break;
            }
        }
        if matches_prefix {
            out.extend(node_ids.iter().copied());
        }
    }
    out.sort_unstable();
    out.dedup();
    out
}

fn consider_best_index_candidates(
    best: &mut Option<(PhysicalScanStrategy, Vec<u64>)>,
    strategy: PhysicalScanStrategy,
    candidates: Vec<u64>,
) {
    if best
        .as_ref()
        .map(|(_, current)| candidates.len() < current.len())
        .unwrap_or(true)
    {
        *best = Some((strategy, candidates));
    }
}

fn expression_key(expr: &CypherExpression) -> String {
    match expr {
        CypherExpression::Identifier(name) => name.clone(),
        CypherExpression::Literal(CypherLiteral::Null) => "null".to_string(),
        CypherExpression::Literal(CypherLiteral::Boolean(value)) => value.to_string(),
        CypherExpression::Literal(CypherLiteral::Integer(value)) => value.to_string(),
        CypherExpression::Literal(CypherLiteral::Float(value)) => value.to_string(),
        CypherExpression::Literal(CypherLiteral::String(value)) => format!("'{value}'"),
        CypherExpression::Parameter(name) => format!("${name}"),
        CypherExpression::PropertyAccess { target, property } => {
            format!("{}.{}", expression_key(target), property)
        }
        CypherExpression::FunctionCall {
            name, arguments, ..
        } => {
            let args = arguments
                .iter()
                .map(expression_key)
                .collect::<Vec<_>>()
                .join(", ");
            format!("{}({args})", name.to_ascii_lowercase())
        }
        CypherExpression::BinaryOp { left, op, right } => {
            format!(
                "({} {:?} {})",
                expression_key(left),
                op,
                expression_key(right)
            )
        }
        CypherExpression::UnaryOp { op, expr } => format!("{op:?} {}", expression_key(expr)),
        CypherExpression::ListLiteral(values) => {
            let values = values
                .iter()
                .map(expression_key)
                .collect::<Vec<_>>()
                .join(", ");
            format!("[{values}]")
        }
        CypherExpression::MapLiteral(values) => {
            let values = values
                .iter()
                .map(|(key, value)| format!("{key}: {}", expression_key(value)))
                .collect::<Vec<_>>()
                .join(", ");
            format!("{{{values}}}")
        }
        CypherExpression::ListComprehension {
            variable,
            list,
            predicate,
            projection,
        } => format!(
            "[{} IN {}{}{}]",
            variable,
            expression_key(list),
            predicate
                .as_ref()
                .map(|value| format!(" WHERE {}", expression_key(value)))
                .unwrap_or_default(),
            projection
                .as_ref()
                .map(|value| format!(" | {}", expression_key(value)))
                .unwrap_or_default()
        ),
        CypherExpression::Subscript { base, index, end } => {
            if let Some(end) = end {
                format!(
                    "{}[{}..{}]",
                    expression_key(base),
                    expression_key(index),
                    expression_key(end)
                )
            } else {
                format!("{}[{}]", expression_key(base), expression_key(index))
            }
        }
        CypherExpression::MapProjection { base, keys } => {
            format!("{}{{{}}}", expression_key(base), keys.join(", "))
        }
        CypherExpression::PatternComprehension {
            pattern,
            predicate,
            projection,
        } => format!(
            "[{}{} | {}]",
            format_pattern_for_expression_key(pattern),
            predicate
                .as_ref()
                .map(|value| format!(" WHERE {}", expression_key(value)))
                .unwrap_or_default(),
            expression_key(projection)
        ),
        CypherExpression::CaseExpression { .. } => "case".to_string(),
        CypherExpression::ExistsSubquery { .. } => "exists".to_string(),
    }
}

fn format_pattern_for_expression_key(pattern: &Pattern) -> String {
    let mut out = format_node_pattern_for_expression_key(&pattern.start);
    for chain in &pattern.chains {
        out.push_str(&format_relationship_pattern_for_expression_key(
            &chain.relationship,
        ));
        out.push_str(&format_node_pattern_for_expression_key(&chain.node));
    }
    out
}

fn format_node_pattern_for_expression_key(node: &NodePattern) -> String {
    let mut out = String::from("(");
    if let Some(variable) = &node.variable {
        out.push_str(variable);
    }
    for label in &node.labels {
        out.push(':');
        out.push_str(label);
    }
    if let Some(properties) = &node.properties {
        let rendered = properties
            .iter()
            .map(|(key, value)| format!("{key}: {}", expression_key(value)))
            .collect::<Vec<_>>()
            .join(", ");
        out.push_str(" {");
        out.push_str(&rendered);
        out.push('}');
    }
    out.push(')');
    out
}

fn format_relationship_pattern_for_expression_key(relationship: &RelationshipPattern) -> String {
    let mut left = "-";
    let mut right = "-";
    match relationship.direction {
        RelationshipDirection::LeftToRight => right = "->",
        RelationshipDirection::RightToLeft => left = "<-",
        RelationshipDirection::Undirected => {}
    }
    let mut out = String::new();
    out.push_str(left);
    if relationship.variable.is_some()
        || relationship.rel_type.is_some()
        || relationship.properties.is_some()
        || relationship.length.is_some()
    {
        out.push('[');
        if let Some(variable) = &relationship.variable {
            out.push_str(variable);
        }
        if let Some(rel_type) = &relationship.rel_type {
            out.push(':');
            out.push_str(rel_type);
        }
        if let Some(length) = relationship.length.as_ref() {
            out.push('*');
            match (length.min_hops, length.max_hops) {
                (Some(min), Some(max)) if min == max => out.push_str(&min.to_string()),
                (Some(min), Some(max)) => out.push_str(&format!("{min}..{max}")),
                (Some(min), None) => out.push_str(&format!("{min}..")),
                (None, Some(max)) => out.push_str(&format!("..{max}")),
                (None, None) => out.push_str(".."),
            }
        }
        if let Some(properties) = &relationship.properties {
            let rendered = properties
                .iter()
                .map(|(key, value)| format!("{key}: {}", expression_key(value)))
                .collect::<Vec<_>>()
                .join(", ");
            out.push_str(" {");
            out.push_str(&rendered);
            out.push('}');
        }
        out.push(']');
    }
    out.push_str(right);
    out
}

fn projection_item_output_name(item: &ProjectionItem) -> String {
    projection_output_name(item).unwrap_or_else(|| expression_key(&item.expression))
}

fn projection_output_columns(items: &[ProjectionItem]) -> Vec<String> {
    let mut names = Vec::<String>::with_capacity(items.len());
    let mut occurrences = BTreeMap::<String, usize>::new();
    for item in items {
        let base = projection_item_output_name(item);
        let count = occurrences
            .entry(base.clone())
            .and_modify(|value| *value += 1)
            .or_insert(1);
        if *count == 1 {
            names.push(base);
        } else {
            names.push(format!("{base}_{count}"));
        }
    }
    names
}

/// A candidate multi-way join detected from a chain of Expand operators in the logical plan.
#[derive(Debug, Clone)]
struct WcojCandidate {
    /// Base input plan (scan and potential pushed-down filters).
    base_plan: LogicalPlan,
    /// Base scan label for cost estimates.
    base_label: Option<String>,
    /// Relations extracted from the expand chain.
    relations: Vec<WcojRelation>,
    /// Ordered list of variables introduced by the join.
    variable_order: Vec<String>,
    /// Output variables/columns (node and edge variables).
    output_variables: Vec<String>,
    /// Whether the pattern reuses variables (cycle/back-edge).
    is_cyclic: bool,
}

struct WcojExecutionContext<'a> {
    variable_order: &'a [String],
    relations: &'a [WcojRelation],
    relation_indexes: &'a [HashMap<u64, Vec<(u64, RuntimeEdgeRef)>>],
    relation_reverse_indexes: &'a [HashMap<u64, Vec<u64>>],
    output_variables: &'a [String],
}

/// Analyze a logical plan tree to detect whether it is a chain of Expand operators rooted
/// at a Scan/Filter(Scan), suitable for WCOJ.
fn detect_wcoj_candidate(plan: &LogicalPlan) -> Option<WcojCandidate> {
    let mut expands = Vec::<(
        String,
        Option<String>,
        RelationshipDirection,
        Option<String>,
        Option<String>,
        Option<TemporalFilter>,
    )>::new();
    let mut current = plan;

    while let LogicalPlan::Expand {
        input,
        from,
        edge_type,
        direction,
        to,
        edge_variable,
        temporal_filter,
    } = current
    {
        expands.push((
            from.clone(),
            edge_type.clone(),
            *direction,
            to.clone(),
            edge_variable.clone(),
            temporal_filter.clone(),
        ));
        current = input;
    }

    // Need at least 2 expands (3+ variables) to consider WCOJ.
    if expands.len() < 2 {
        return None;
    }

    let base_plan = current.clone();
    let mut scan_cursor = current;
    let (base_label, base_variable) = loop {
        match scan_cursor {
            LogicalPlan::Filter { input, .. } => {
                scan_cursor = input;
            }
            LogicalPlan::Scan { label, variable } => break (label.clone(), variable.clone()),
            _ => return None,
        }
    };

    // Collected from outermost -> innermost. Reverse to base -> outward.
    expands.reverse();

    let mut variable_order = Vec::<String>::new();
    let mut output_variables = Vec::<String>::new();
    let mut seen_variables = BTreeSet::<String>::new();
    let mut is_cyclic = false;

    let first_from = expands
        .first()
        .map(|(from, ..)| from.clone())
        .unwrap_or_else(|| "_anon".to_string());
    let base_name = base_variable.clone().unwrap_or(first_from);
    variable_order.push(base_name.clone());
    output_variables.push(base_name.clone());
    seen_variables.insert(base_name);

    let mut relations = Vec::<WcojRelation>::with_capacity(expands.len());
    for (idx, (from, edge_type, direction, to, edge_variable, temporal_filter)) in
        expands.iter().enumerate()
    {
        if !seen_variables.contains(from) {
            return None;
        }

        let to_name = to.clone().unwrap_or_else(|| format!("_anon_{idx}"));
        if seen_variables.contains(&to_name) {
            is_cyclic = true;
        } else {
            variable_order.push(to_name.clone());
            seen_variables.insert(to_name.clone());
        }

        if !output_variables.contains(&to_name) {
            output_variables.push(to_name.clone());
        }
        if let Some(edge_var) = edge_variable.as_ref() {
            if !output_variables.contains(edge_var) {
                output_variables.push(edge_var.clone());
            }
        }

        relations.push(WcojRelation {
            from: from.clone(),
            to: to_name,
            edge_type: edge_type.clone(),
            direction: *direction,
            edge_variable: edge_variable.clone(),
            temporal_filter: temporal_filter.clone(),
        });
    }

    Some(WcojCandidate {
        base_plan,
        base_label,
        relations,
        variable_order,
        output_variables,
        is_cyclic,
    })
}

/// Estimate rows/cost for WCOJ execution.
fn estimate_wcoj_cost(db: &Database, candidate: &WcojCandidate) -> (u64, f64) {
    let node_count = db.node_count().max(1) as f64;
    let base_rows = label_cardinality_for_scan(db, candidate.base_label.as_deref()).max(1);

    let mut total_relation_size: u64 = 0;
    let mut degree_product = 1.0;
    for relation in &candidate.relations {
        let relation_rows = edge_count_for_type(db, relation.edge_type.as_deref()).max(1);
        total_relation_size = total_relation_size.saturating_add(relation_rows);
        let avg_degree = relation_rows as f64 / node_count;
        degree_product *= avg_degree.max(1.0);
    }

    let mut estimated_rows = ((base_rows as f64) * degree_product).ceil() as u64;
    if candidate.is_cyclic {
        let cycle_discount = (candidate.relations.len() as f64).max(1.0);
        estimated_rows = ((estimated_rows as f64) / cycle_discount).ceil() as u64;
    }
    estimated_rows = estimated_rows.max(1);

    // Build cost is linear in relation sizes; leapfrog intersections are modeled as cheap skips.
    let build_cost = total_relation_size as f64 * 0.10;
    let mut intersection_cost = estimated_rows as f64 * candidate.relations.len() as f64 * 0.10;
    if candidate.is_cyclic {
        intersection_cost *= 0.70;
    }
    let total_cost = (build_cost + intersection_cost).max(1.0);

    (estimated_rows, total_cost)
}

/// Estimate rows/cost of the baseline binary hash-expand chain.
fn estimate_binary_chain_cost(db: &Database, candidate: &WcojCandidate) -> (u64, f64) {
    let node_count = db.node_count().max(1);
    let mut current_rows = label_cardinality_for_scan(db, candidate.base_label.as_deref()).max(1);
    let mut total_cost = current_rows as f64;

    for relation in &candidate.relations {
        let edge_rows = edge_count_for_type(db, relation.edge_type.as_deref()).max(1);
        let avg_degree = edge_rows as f64 / node_count as f64;
        let next_rows = ((current_rows as f64) * avg_degree.max(1.0)).ceil() as u64;

        // Existing planner compares nested loop vs hash; use hash as baseline for fairness.
        total_cost += (edge_rows + current_rows.max(1)) as f64;
        current_rows = next_rows.max(1);
    }

    (current_rows.max(1), total_cost.max(1.0))
}

fn edge_count_for_type(db: &Database, edge_type: Option<&str>) -> u64 {
    if let Some(edge_type) = edge_type {
        let key = EdgeTypeKey::Typed(edge_type.to_string());
        if let Some(index) = db.adjacency_by_type.get(&key) {
            return index.base_edge_count() + index.delta_buffer_edge_count();
        }
        return 0;
    }
    db.edge_count()
}

fn label_cardinality_for_scan(db: &Database, label: Option<&str>) -> u64 {
    if let Some(label) = label {
        if let Some(bitmap) = db.meta.label_membership.get(label) {
            return bitmap.len();
        }
        return 0;
    }
    db.node_count()
}

fn collect_filtered_properties_from_plan(plan: &PhysicalPlan) -> Vec<(String, String)> {
    let mut accesses = Vec::<(String, String)>::new();
    collect_filtered_properties_from_plan_recursive(plan, &mut accesses);
    accesses
        .into_iter()
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect()
}

fn collect_filtered_properties_from_plan_recursive(
    plan: &PhysicalPlan,
    accesses: &mut Vec<(String, String)>,
) {
    match plan {
        PhysicalPlan::PhysicalFilter {
            input, predicate, ..
        } => {
            if let PhysicalPlan::PhysicalScan {
                label: Some(label),
                variable: Some(variable),
                ..
            } = input.as_ref()
            {
                let mut predicates = Vec::<IndexPredicate>::new();
                collect_index_predicates_for_variable(predicate, variable, &mut predicates);
                for predicate in predicates {
                    accesses.push((label.clone(), predicate.property_key));
                }
            }
            collect_filtered_properties_from_plan_recursive(input, accesses);
        }
        PhysicalPlan::PhysicalExpand { input, .. }
        | PhysicalPlan::PhysicalFactorizedExpand { input, .. }
        | PhysicalPlan::PhysicalProject { input, .. }
        | PhysicalPlan::PhysicalSort { input, .. }
        | PhysicalPlan::PhysicalLimit { input, .. }
        | PhysicalPlan::PhysicalAggregation { input, .. }
        | PhysicalPlan::PhysicalDelete { input, .. }
        | PhysicalPlan::PhysicalSet { input, .. }
        | PhysicalPlan::PhysicalRemove { input, .. }
        | PhysicalPlan::PhysicalWcojJoin { input, .. } => {
            collect_filtered_properties_from_plan_recursive(input, accesses);
        }
        PhysicalPlan::PhysicalCartesianProduct { left, right, .. } => {
            collect_filtered_properties_from_plan_recursive(left, accesses);
            collect_filtered_properties_from_plan_recursive(right, accesses);
        }
        PhysicalPlan::PhysicalCreate { input, .. }
        | PhysicalPlan::PhysicalMerge { input, .. }
        | PhysicalPlan::PhysicalUnwind { input, .. } => {
            if let Some(input) = input.as_ref() {
                collect_filtered_properties_from_plan_recursive(input, accesses);
            }
        }
        PhysicalPlan::PhysicalScan { .. }
        | PhysicalPlan::PhysicalVectorScan { .. }
        | PhysicalPlan::PhysicalTextSearch { .. }
        | PhysicalPlan::PhysicalCreateIndex { .. } => {}
    }
}

fn estimated_unwind_fanout(expr: &CypherExpression) -> u64 {
    match expr {
        CypherExpression::ListLiteral(values) => values.len() as u64,
        CypherExpression::FunctionCall {
            name, arguments, ..
        } if name.eq_ignore_ascii_case("range") && arguments.len() >= 2 => {
            let lit_i64 = |e: &CypherExpression| -> Option<i64> {
                if let CypherExpression::Literal(CypherLiteral::Integer(v)) = e {
                    Some(*v)
                } else {
                    None
                }
            };
            match (lit_i64(&arguments[0]), lit_i64(&arguments[1])) {
                (Some(a), Some(b)) if b >= a => (b - a + 1) as u64,
                _ => 8,
            }
        }
        _ => 8,
    }
}

fn build_physical_plan(db: &Database, plan: &LogicalPlan) -> Result<PhysicalPlan, PlanError> {
    match plan {
        LogicalPlan::Scan { label, variable } => {
            let total_nodes = db.node_count();
            let estimated_rows = label_cardinality_for_scan(db, label.as_deref());
            let scan_strategy = if label.is_some() && estimated_rows > 0 {
                PhysicalScanStrategy::IndexScan
            } else {
                PhysicalScanStrategy::SequentialScan
            };
            let estimated_cost = match scan_strategy {
                PhysicalScanStrategy::SequentialScan => total_nodes as f64,
                PhysicalScanStrategy::IndexScan
                | PhysicalScanStrategy::PropertyIndexScan
                | PhysicalScanStrategy::CompositeIndexScan => {
                    (estimated_rows as f64 * 0.65).max(1.0)
                }
            };
            Ok(PhysicalPlan::PhysicalScan {
                label: label.clone(),
                variable: variable.clone(),
                scan_strategy,
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::VectorScan {
            label,
            variable,
            property_key,
            query_vector,
            k,
            metric,
        } => {
            let definition = db
                .meta
                .vector_index_catalog
                .iter()
                .find(|definition| {
                    definition.property_key == *property_key
                        && definition.label.as_deref() == label.as_deref()
                })
                .ok_or_else(|| {
                    PlanError::new(format!(
                        "no vector index available for label={:?} property={property_key}",
                        label
                    ))
                })?;
            let estimated_rows = (*k).min(db.node_count()).max(1);
            let estimated_cost = (estimated_rows as f64 * 0.15).max(1.0);
            Ok(PhysicalPlan::PhysicalVectorScan {
                index_name: definition.name.clone(),
                label: label.clone(),
                variable: variable.clone(),
                query_vector: query_vector.clone(),
                k: *k,
                metric: metric.unwrap_or(definition.metric),
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::TextSearch {
            label,
            variable,
            property_key,
            query_text,
            k,
        } => {
            let definition = db
                .meta
                .fulltext_index_catalog
                .iter()
                .find(|definition| {
                    definition
                        .property_keys
                        .iter()
                        .any(|key| key == property_key)
                        && definition.label.as_deref() == label.as_deref()
                })
                .ok_or_else(|| {
                    PlanError::new(format!(
                        "no fulltext index available for label={:?} property={property_key}",
                        label
                    ))
                })?;
            let estimated_rows = (*k).min(db.node_count()).max(1);
            let estimated_cost = (estimated_rows as f64 * 0.2).max(1.0);
            Ok(PhysicalPlan::PhysicalTextSearch {
                index_name: definition.name.clone(),
                label: label.clone(),
                variable: variable.clone(),
                property_key: property_key.clone(),
                query_text: query_text.clone(),
                k: *k,
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::Expand {
            input,
            from,
            edge_type,
            direction,
            to,
            edge_variable,
            temporal_filter,
        } => {
            if let Some(candidate) = detect_wcoj_candidate(plan) {
                let (wcoj_rows, wcoj_cost) = estimate_wcoj_cost(db, &candidate);
                let (_, binary_cost) = estimate_binary_chain_cost(db, &candidate);
                if wcoj_cost < binary_cost {
                    let base_input = build_physical_plan(db, &candidate.base_plan)?;
                    return Ok(PhysicalPlan::PhysicalWcojJoin {
                        input: Box::new(base_input),
                        relations: candidate.relations,
                        variable_order: candidate.variable_order,
                        output_variables: candidate.output_variables,
                        estimated_rows: wcoj_rows,
                        estimated_cost: wcoj_cost,
                    });
                }
            }

            let input = build_physical_plan(db, input)?;
            let input_rows = input.estimated_rows().max(1);
            let edge_rows = edge_count_for_type(db, edge_type.as_deref());
            let node_count = db.node_count().max(1);
            let avg_degree = edge_rows as f64 / node_count as f64;
            let estimated_rows = ((input_rows as f64) * avg_degree.max(1.0)).ceil() as u64;
            let fan_out = estimated_rows as f64 / input_rows as f64;
            if fan_out > FACTORIZE_FAN_OUT_THRESHOLD && input_rows > 64 {
                let estimated_cost = input.estimated_cost()
                    + (edge_rows + input_rows) as f64
                    + estimated_rows as f64 * 0.1;
                return Ok(PhysicalPlan::PhysicalFactorizedExpand {
                    input: Box::new(input),
                    from: from.clone(),
                    edge_type: edge_type.clone(),
                    direction: *direction,
                    to: to.clone(),
                    edge_variable: edge_variable.clone(),
                    temporal_filter: temporal_filter.clone(),
                    factorized: true,
                    estimated_rows,
                    estimated_cost,
                });
            }
            let join_strategy = if input_rows > 128 || edge_rows > 512 {
                PhysicalJoinStrategy::HashJoin
            } else {
                PhysicalJoinStrategy::NestedLoop
            };
            let estimated_cost = input.estimated_cost()
                + match join_strategy {
                    PhysicalJoinStrategy::NestedLoop => (input_rows * edge_rows.max(1)) as f64,
                    PhysicalJoinStrategy::HashJoin => (edge_rows + input_rows) as f64,
                    PhysicalJoinStrategy::WcojJoin => 0.0,
                };
            Ok(PhysicalPlan::PhysicalExpand {
                input: Box::new(input),
                from: from.clone(),
                edge_type: edge_type.clone(),
                direction: *direction,
                to: to.clone(),
                edge_variable: edge_variable.clone(),
                temporal_filter: temporal_filter.clone(),
                join_strategy,
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::CartesianProduct { left, right } => {
            let left = build_physical_plan(db, left)?;
            let right = build_physical_plan(db, right)?;
            let estimated_rows = left.estimated_rows().saturating_mul(right.estimated_rows());
            let estimated_cost = left.estimated_cost()
                + right.estimated_cost()
                + left.estimated_rows().max(1) as f64 * right.estimated_rows().max(1) as f64;
            Ok(PhysicalPlan::PhysicalCartesianProduct {
                left: Box::new(left),
                right: Box::new(right),
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::Filter { input, predicate } => {
            if let LogicalPlan::Scan { label, variable } = input.as_ref() {
                if let (Some(label_name), Some(variable_name)) =
                    (label.as_deref(), variable.as_deref())
                {
                    if let Some((scan_strategy, indexed_rows)) =
                        db.plan_index_scan_for_filter(label_name, variable_name, predicate)
                    {
                        let scan_rows = indexed_rows;
                        let scan_cost = if scan_strategy == PhysicalScanStrategy::PropertyIndexScan
                        {
                            (scan_rows as f64 * 0.30).max(1.0)
                        } else {
                            (scan_rows as f64 * 0.20).max(1.0)
                        };
                        let scan_plan = PhysicalPlan::PhysicalScan {
                            label: label.clone(),
                            variable: variable.clone(),
                            scan_strategy,
                            estimated_rows: scan_rows,
                            estimated_cost: scan_cost,
                        };
                        let selectivity = estimate_filter_selectivity(predicate);
                        let estimated_rows = ((scan_plan.estimated_rows().max(1) as f64)
                            * selectivity)
                            .ceil() as u64;
                        let estimated_cost =
                            scan_plan.estimated_cost() + scan_plan.estimated_rows().max(1) as f64;
                        return Ok(PhysicalPlan::PhysicalFilter {
                            input: Box::new(scan_plan),
                            predicate: predicate.clone(),
                            selectivity,
                            estimated_rows,
                            estimated_cost,
                        });
                    }
                }
            }
            let input = build_physical_plan(db, input)?;
            let selectivity = estimate_filter_selectivity(predicate);
            let estimated_rows =
                ((input.estimated_rows().max(1) as f64) * selectivity).ceil() as u64;
            let estimated_cost = input.estimated_cost() + input.estimated_rows().max(1) as f64;
            Ok(PhysicalPlan::PhysicalFilter {
                input: Box::new(input),
                predicate: predicate.clone(),
                selectivity,
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::Project {
            input,
            expressions,
            distinct,
        } => {
            let input = build_physical_plan(db, input)?;
            let estimated_rows = input.estimated_rows();
            let estimated_cost = input.estimated_cost()
                + (estimated_rows as f64 * expressions.len().max(1) as f64 * 0.10);
            Ok(PhysicalPlan::PhysicalProject {
                input: Box::new(input),
                expressions: expressions.clone(),
                distinct: *distinct,
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::Sort { input, keys } => {
            let input = build_physical_plan(db, input)?;
            let estimated_rows = input.estimated_rows();
            let base = estimated_rows.max(1) as f64;
            let estimated_cost =
                input.estimated_cost() + base * base.log2().max(1.0) * keys.len().max(1) as f64;
            Ok(PhysicalPlan::PhysicalSort {
                input: Box::new(input),
                keys: keys.clone(),
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::Limit { input, count } => {
            let input = build_physical_plan(db, input)?;
            let estimated_rows = input.estimated_rows().min(*count);
            let estimated_cost = input.estimated_cost() + estimated_rows as f64;
            Ok(PhysicalPlan::PhysicalLimit {
                input: Box::new(input),
                count: Some(*count),
                skip: 0,
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::Skip { input, count } => {
            let input = build_physical_plan(db, input)?;
            let estimated_rows = input.estimated_rows().saturating_sub(*count);
            let estimated_cost = input.estimated_cost() + input.estimated_rows() as f64;
            Ok(PhysicalPlan::PhysicalLimit {
                input: Box::new(input),
                count: None,
                skip: *count,
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::Aggregate {
            input,
            group_keys,
            aggregates,
        } => {
            let input = build_physical_plan(db, input)?;
            let estimated_rows = if group_keys.is_empty() {
                1
            } else {
                (input.estimated_rows() / 2).max(1)
            };
            let estimated_cost = input.estimated_cost() + input.estimated_rows() as f64;
            Ok(PhysicalPlan::PhysicalAggregation {
                input: Box::new(input),
                group_keys: group_keys.clone(),
                aggregates: aggregates.clone(),
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::Create { input, patterns } => {
            let input = input
                .as_ref()
                .map(|value| build_physical_plan(db, value))
                .transpose()?;
            let estimated_rows = input
                .as_ref()
                .map(|value| value.estimated_rows())
                .unwrap_or(1);
            let base_cost = input
                .as_ref()
                .map(|value| value.estimated_cost())
                .unwrap_or(0.0);
            let estimated_cost = base_cost + patterns.len().max(1) as f64 * estimated_rows as f64;
            Ok(PhysicalPlan::PhysicalCreate {
                input: input.map(Box::new),
                patterns: patterns.clone(),
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::CreateIndex {
            label,
            property_keys,
        } => Ok(PhysicalPlan::PhysicalCreateIndex {
            label: label.clone(),
            property_keys: property_keys.clone(),
            estimated_rows: 0,
            estimated_cost: property_keys.len().max(1) as f64,
        }),
        LogicalPlan::Delete {
            input,
            expressions,
            detach,
        } => {
            let input = build_physical_plan(db, input)?;
            let estimated_rows = input.estimated_rows();
            let estimated_cost = input.estimated_cost() + estimated_rows as f64;
            Ok(PhysicalPlan::PhysicalDelete {
                input: Box::new(input),
                expressions: expressions.clone(),
                detach: *detach,
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::SetProperties { input, assignments } => {
            let input = build_physical_plan(db, input)?;
            let estimated_rows = input.estimated_rows();
            let estimated_cost =
                input.estimated_cost() + estimated_rows as f64 * assignments.len().max(1) as f64;
            Ok(PhysicalPlan::PhysicalSet {
                input: Box::new(input),
                assignments: assignments.clone(),
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::RemoveProperties { input, targets } => {
            let input = build_physical_plan(db, input)?;
            let estimated_rows = input.estimated_rows();
            let estimated_cost =
                input.estimated_cost() + estimated_rows as f64 * targets.len().max(1) as f64;
            Ok(PhysicalPlan::PhysicalRemove {
                input: Box::new(input),
                targets: targets.clone(),
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::UnwindList {
            input,
            expression,
            variable,
        } => {
            let input = input
                .as_ref()
                .map(|plan| build_physical_plan(db, plan))
                .transpose()?;
            let base_rows = input
                .as_ref()
                .map(|value| value.estimated_rows())
                .unwrap_or(1);
            let fanout = estimated_unwind_fanout(expression);
            let estimated_rows = base_rows.saturating_mul(fanout);
            let base_cost = input
                .as_ref()
                .map(|value| value.estimated_cost())
                .unwrap_or(0.0);
            let estimated_cost = base_cost + estimated_rows as f64;
            Ok(PhysicalPlan::PhysicalUnwind {
                input: input.map(Box::new),
                expression: expression.clone(),
                variable: variable.clone(),
                estimated_rows,
                estimated_cost,
            })
        }
        LogicalPlan::Merge {
            input,
            pattern,
            on_create,
            on_match,
        } => {
            let input = input
                .as_ref()
                .map(|value| build_physical_plan(db, value))
                .transpose()?;
            let estimated_rows = input
                .as_ref()
                .map(|value| value.estimated_rows())
                .unwrap_or(1);
            let base_cost = input
                .as_ref()
                .map(|value| value.estimated_cost())
                .unwrap_or(0.0);
            let estimated_cost = base_cost + estimated_rows as f64;
            Ok(PhysicalPlan::PhysicalMerge {
                input: input.map(Box::new),
                pattern: pattern.clone(),
                on_create: on_create.clone(),
                on_match: on_match.clone(),
                estimated_rows,
                estimated_cost,
            })
        }
    }
}

fn property_value_to_json(value: &PropertyValue) -> serde_json::Value {
    match value {
        PropertyValue::Bool(value) => serde_json::Value::Bool(*value),
        PropertyValue::I64(value) => serde_json::Value::Number((*value).into()),
        PropertyValue::F64(value) => serde_json::Number::from_f64(*value)
            .map_or(serde_json::Value::Null, serde_json::Value::Number),
        PropertyValue::String(value) => serde_json::Value::String(value.clone()),
        PropertyValue::Bytes(value) => {
            let encoded = value
                .iter()
                .map(|byte| format!("{byte:02x}"))
                .collect::<String>();
            serde_json::Value::String(format!("bytes:{encoded}"))
        }
        PropertyValue::Vector(value) => serde_json::Value::Array(
            value
                .iter()
                .map(|entry| {
                    serde_json::Number::from_f64(*entry as f64)
                        .map(serde_json::Value::Number)
                        .unwrap_or(serde_json::Value::Null)
                })
                .collect(),
        ),
        PropertyValue::Date(days) => serde_json::Value::String(days_to_date_string(*days)),
        PropertyValue::DateTime {
            micros,
            tz_offset_minutes,
        } => serde_json::Value::String(micros_to_datetime_string(*micros, *tz_offset_minutes)),
        PropertyValue::Duration {
            months,
            days,
            nanos,
        } => serde_json::Value::String(format_duration(*months, *days, *nanos)),
        PropertyValue::List(values) => {
            serde_json::Value::Array(values.iter().map(property_value_to_json).collect())
        }
        PropertyValue::Map(values) => serde_json::Value::Object(
            values
                .iter()
                .map(|(key, value)| (key.clone(), property_value_to_json(value)))
                .collect(),
        ),
        // PropertyValue is `#[non_exhaustive]` (EVAL-RUST-QUALITY-CYCLE3 B3);
        // unknown future variants serialize as JSON null until each gets a
        // dedicated mapping.
        _ => serde_json::Value::Null,
    }
}

fn format_property_value(value: &PropertyValue) -> String {
    match value {
        PropertyValue::Bool(value) => value.to_string(),
        PropertyValue::I64(value) => value.to_string(),
        PropertyValue::F64(value) => value.to_string(),
        PropertyValue::String(value) => value.clone(),
        PropertyValue::Bytes(value) => value
            .iter()
            .map(|byte| format!("{byte:02x}"))
            .collect::<String>(),
        PropertyValue::Vector(value) => format!(
            "[{}]",
            value
                .iter()
                .map(|entry| entry.to_string())
                .collect::<Vec<_>>()
                .join(",")
        ),
        PropertyValue::Date(days) => days_to_date_string(*days),
        PropertyValue::DateTime {
            micros,
            tz_offset_minutes,
        } => micros_to_datetime_string(*micros, *tz_offset_minutes),
        PropertyValue::Duration {
            months,
            days,
            nanos,
        } => format_duration(*months, *days, *nanos),
        PropertyValue::List(values) => format!(
            "[{}]",
            values
                .iter()
                .map(format_property_value)
                .collect::<Vec<_>>()
                .join(", ")
        ),
        PropertyValue::Map(values) => format!(
            "{{{}}}",
            values
                .iter()
                .map(|(key, value)| format!("{key}: {}", format_property_value(value)))
                .collect::<Vec<_>>()
                .join(", ")
        ),
        // PropertyValue is `#[non_exhaustive]` (EVAL-RUST-QUALITY-CYCLE3 B3);
        // unknown future variants format as their debug representation.
        other => format!("{other:?}"),
    }
}

fn property_value_type_name(value: &PropertyValue) -> &'static str {
    match value {
        PropertyValue::Bool(_) => "bool",
        PropertyValue::I64(_) => "i64",
        PropertyValue::F64(_) => "f64",
        PropertyValue::String(_) => "string",
        PropertyValue::Bytes(_) => "bytes",
        PropertyValue::Vector(_) => "vector",
        PropertyValue::Date(_) => "date",
        PropertyValue::DateTime { .. } => "datetime",
        PropertyValue::Duration { .. } => "duration",
        PropertyValue::List(_) => "list",
        PropertyValue::Map(_) => "map",
        // PropertyValue is `#[non_exhaustive]` (EVAL-RUST-QUALITY-CYCLE3 B3);
        // unknown future variants are reported as "unknown" until classified.
        _ => "unknown",
    }
}

fn property_value_is_null(value: &PropertyValue) -> bool {
    matches!(value, PropertyValue::String(text) if text == "null")
}

fn compare_property_values(
    left: &PropertyValue,
    right: &PropertyValue,
) -> Option<std::cmp::Ordering> {
    match (left, right) {
        (PropertyValue::Bool(l), PropertyValue::Bool(r)) => Some(l.cmp(r)),
        (PropertyValue::I64(l), PropertyValue::I64(r)) => Some(l.cmp(r)),
        (PropertyValue::F64(l), PropertyValue::F64(r)) => l.partial_cmp(r),
        (PropertyValue::I64(l), PropertyValue::F64(r)) => (*l as f64).partial_cmp(r),
        (PropertyValue::F64(l), PropertyValue::I64(r)) => l.partial_cmp(&(*r as f64)),
        (PropertyValue::String(l), PropertyValue::String(r)) => Some(l.cmp(r)),
        (PropertyValue::Vector(l), PropertyValue::Vector(r)) => Some(compare_f32_vectors(l, r)),
        (PropertyValue::Date(l), PropertyValue::Date(r)) => Some(l.cmp(r)),
        (PropertyValue::DateTime { micros: l, .. }, PropertyValue::DateTime { micros: r, .. }) => {
            Some(l.cmp(r))
        }
        (
            PropertyValue::Duration {
                months: lm,
                days: ld,
                nanos: ln,
            },
            PropertyValue::Duration {
                months: rm,
                days: rd,
                nanos: rn,
            },
        ) => Some(lm.cmp(rm).then_with(|| ld.cmp(rd)).then_with(|| ln.cmp(rn))),
        (PropertyValue::List(l), PropertyValue::List(r)) => Some(l.cmp(r)),
        (PropertyValue::Map(l), PropertyValue::Map(r)) => {
            Some(l.len().cmp(&r.len()).then_with(|| {
                l.iter()
                    .zip(r.iter())
                    .filter_map(|((left_key, left_value), (right_key, right_value))| {
                        let key_cmp = left_key.cmp(right_key);
                        if key_cmp != std::cmp::Ordering::Equal {
                            Some(key_cmp)
                        } else {
                            compare_property_values(left_value, right_value)
                        }
                    })
                    .find(|ordering| *ordering != std::cmp::Ordering::Equal)
                    .unwrap_or(std::cmp::Ordering::Equal)
            }))
        }
        _ => None,
    }
}

fn parse_date_literal(input: &str) -> Option<i32> {
    let bytes = input.as_bytes();
    if bytes.len() != 10 || bytes[4] != b'-' || bytes[7] != b'-' {
        return None;
    }
    let year: i32 = input.get(0..4)?.parse().ok()?;
    let month: u32 = input.get(5..7)?.parse().ok()?;
    let day: u32 = input.get(8..10)?.parse().ok()?;
    if !(1..=12).contains(&month) {
        return None;
    }
    let max_day = days_in_month(year, month)?;
    if day == 0 || day > max_day {
        return None;
    }
    Some(date_to_days_since_epoch(year, month, day))
}

fn parse_datetime_literal(input: &str) -> Option<(i64, i16)> {
    let separator = input.find('T').or_else(|| input.find('t'))?;
    let date_part = input.get(0..separator)?;
    let mut time_and_tz = input.get(separator + 1..)?;
    let days = parse_date_literal(date_part)?;

    let tz_offset_minutes = if time_and_tz.ends_with('Z') || time_and_tz.ends_with('z') {
        time_and_tz = time_and_tz.get(..time_and_tz.len().saturating_sub(1))?;
        0i16
    } else if let Some(pos) = time_and_tz.rfind('+') {
        let tz = parse_tz_offset(time_and_tz.get(pos + 1..)?)?;
        time_and_tz = time_and_tz.get(..pos)?;
        tz
    } else if let Some(pos) = time_and_tz.rfind('-') {
        let tz = parse_tz_offset(time_and_tz.get(pos + 1..)?)?;
        time_and_tz = time_and_tz.get(..pos)?;
        -tz
    } else {
        0i16
    };

    let parts = time_and_tz.split(':').collect::<Vec<_>>();
    if parts.len() < 2 || parts.len() > 3 {
        return None;
    }
    let hours: i64 = parts[0].parse().ok()?;
    let minutes: i64 = parts[1].parse().ok()?;
    if !(0..=23).contains(&hours) || !(0..=59).contains(&minutes) {
        return None;
    }

    let (seconds, fractional_micros) = if parts.len() == 3 {
        let seconds_part = parts[2];
        if let Some(dot_idx) = seconds_part.find('.') {
            let seconds: i64 = seconds_part.get(..dot_idx)?.parse().ok()?;
            let fractional = seconds_part.get(dot_idx + 1..)?;
            if fractional.is_empty() || !fractional.chars().all(|ch| ch.is_ascii_digit()) {
                return None;
            }
            let mut micros_text = fractional.to_string();
            if micros_text.len() > 6 {
                micros_text.truncate(6);
            }
            while micros_text.len() < 6 {
                micros_text.push('0');
            }
            let micros = micros_text.parse::<i64>().ok()?;
            (seconds, micros)
        } else {
            let seconds = seconds_part.parse::<i64>().ok()?;
            (seconds, 0i64)
        }
    } else {
        (0i64, 0i64)
    };

    if !(0..=59).contains(&seconds) {
        return None;
    }

    let seconds_of_day = hours
        .checked_mul(3_600)?
        .checked_add(minutes.checked_mul(60)?)?
        .checked_add(seconds)?;
    let day_micros = seconds_of_day
        .checked_mul(1_000_000)?
        .checked_add(fractional_micros)?;
    let total_micros = i64::from(days)
        .checked_mul(86_400_000_000)?
        .checked_add(day_micros)?;
    let utc_offset_micros = i64::from(tz_offset_minutes).checked_mul(60_000_000)?;
    let utc_micros = total_micros.checked_sub(utc_offset_micros)?;
    Some((utc_micros, tz_offset_minutes))
}

fn parse_tz_offset(input: &str) -> Option<i16> {
    let (hours, minutes) = if input.len() == 5 && input.as_bytes().get(2) == Some(&b':') {
        let hours = input.get(..2)?.parse::<i16>().ok()?;
        let minutes = input.get(3..)?.parse::<i16>().ok()?;
        (hours, minutes)
    } else if input.len() == 4 {
        let hours = input.get(..2)?.parse::<i16>().ok()?;
        let minutes = input.get(2..)?.parse::<i16>().ok()?;
        (hours, minutes)
    } else {
        return None;
    };
    if !(0..=23).contains(&hours) || !(0..=59).contains(&minutes) {
        return None;
    }
    hours.checked_mul(60)?.checked_add(minutes)
}

/// Parses ISO 8601 duration "P[n]Y[n]M[n]DT[n]H[n]M[n]S" -> (months, days, nanos)
fn parse_duration_literal(s: &str) -> Option<(i64, i64, i64)> {
    let s = s.trim();
    if !s.starts_with('P') && !s.starts_with('p') {
        return None;
    }
    let s = &s[1..];

    let mut months: i64 = 0;
    let mut days: i64 = 0;
    let mut nanos: i64 = 0;
    let mut in_time = false;
    let mut num_buf = String::new();

    for ch in s.chars() {
        match ch {
            'T' | 't' => {
                in_time = true;
            }
            '0'..='9' | '.' => {
                num_buf.push(ch);
            }
            'Y' | 'y' if !in_time => {
                let years: i64 = num_buf.parse().ok()?;
                months += years * 12;
                num_buf.clear();
            }
            'M' | 'm' if !in_time => {
                let m: i64 = num_buf.parse().ok()?;
                months += m;
                num_buf.clear();
            }
            'W' | 'w' if !in_time => {
                let weeks: i64 = num_buf.parse().ok()?;
                days += weeks * 7;
                num_buf.clear();
            }
            'D' | 'd' if !in_time => {
                let d: i64 = num_buf.parse().ok()?;
                days += d;
                num_buf.clear();
            }
            'H' | 'h' if in_time => {
                let h: f64 = num_buf.parse().ok()?;
                nanos += (h * 3_600_000_000_000.0) as i64;
                num_buf.clear();
            }
            'M' | 'm' if in_time => {
                let m: f64 = num_buf.parse().ok()?;
                nanos += (m * 60_000_000_000.0) as i64;
                num_buf.clear();
            }
            'S' | 's' if in_time => {
                let secs: f64 = num_buf.parse().ok()?;
                nanos += (secs * 1_000_000_000.0) as i64;
                num_buf.clear();
            }
            _ => return None,
        }
    }

    if !num_buf.is_empty() {
        return None;
    }

    Some((months, days, nanos))
}

/// Formats duration components as ISO 8601 string
fn format_duration(months: i64, days: i64, nanos: i64) -> String {
    let mut result = String::from("P");
    let years = months / 12;
    let remaining_months = months % 12;
    if years != 0 {
        result.push_str(&format!("{years}Y"));
    }
    if remaining_months != 0 {
        result.push_str(&format!("{remaining_months}M"));
    }
    if days != 0 {
        result.push_str(&format!("{days}D"));
    }

    if nanos != 0 {
        result.push('T');
        let total_secs = nanos / 1_000_000_000;
        let remaining_nanos = nanos % 1_000_000_000;
        let hours = total_secs / 3600;
        let mins = (total_secs % 3600) / 60;
        let secs = total_secs % 60;
        if hours != 0 {
            result.push_str(&format!("{hours}H"));
        }
        if mins != 0 {
            result.push_str(&format!("{mins}M"));
        }
        if secs != 0 || remaining_nanos != 0 {
            if remaining_nanos != 0 {
                let frac = format!("{:09}", remaining_nanos)
                    .trim_end_matches('0')
                    .to_string();
                result.push_str(&format!("{secs}.{frac}S"));
            } else {
                result.push_str(&format!("{secs}S"));
            }
        }
    }

    if result == "P" {
        result.push_str("T0S");
    }

    result
}

fn days_to_date_string(days_since_epoch: i32) -> String {
    let z = i64::from(days_since_epoch) + 719_468;
    let era = if z >= 0 { z } else { z - 146_096 } / 146_097;
    let day_of_era = (z - era * 146_097) as u32;
    let year_of_era =
        (day_of_era - day_of_era / 1_460 + day_of_era / 36_524 - day_of_era / 146_096) / 365;
    let year = year_of_era as i64 + era * 400;
    let day_of_year = day_of_era - (365 * year_of_era + year_of_era / 4 - year_of_era / 100);
    let month_phase = (5 * day_of_year + 2) / 153;
    let day = day_of_year - (153 * month_phase + 2) / 5 + 1;
    let month = if month_phase < 10 {
        month_phase + 3
    } else {
        month_phase - 9
    };
    let year = if month <= 2 { year + 1 } else { year };
    format!("{year:04}-{month:02}-{day:02}")
}

fn micros_to_datetime_string(micros: i64, tz_offset_minutes: i16) -> String {
    let tz_micros = i64::from(tz_offset_minutes) * 60_000_000;
    let local_micros = micros.saturating_add(tz_micros);
    let total_seconds = local_micros.div_euclid(1_000_000);
    let fractional_micros = local_micros.rem_euclid(1_000_000);
    let days = total_seconds.div_euclid(86_400);
    let seconds_in_day = total_seconds.rem_euclid(86_400);
    let hours = seconds_in_day / 3_600;
    let minutes = (seconds_in_day % 3_600) / 60;
    let seconds = seconds_in_day % 60;
    let date = days_to_date_string(days as i32);

    let tz_suffix = if tz_offset_minutes == 0 {
        "Z".to_string()
    } else {
        let sign = if tz_offset_minutes >= 0 { '+' } else { '-' };
        let abs = tz_offset_minutes.unsigned_abs();
        format!("{sign}{:02}:{:02}", abs / 60, abs % 60)
    };

    if fractional_micros == 0 {
        format!("{date}T{hours:02}:{minutes:02}:{seconds:02}{tz_suffix}")
    } else {
        format!("{date}T{hours:02}:{minutes:02}:{seconds:02}.{fractional_micros:06}{tz_suffix}")
    }
}

fn date_to_days_since_epoch(year: i32, month: u32, day: u32) -> i32 {
    let adjusted_year = if month <= 2 {
        i64::from(year) - 1
    } else {
        i64::from(year)
    };
    let era = if adjusted_year >= 0 {
        adjusted_year
    } else {
        adjusted_year - 399
    } / 400;
    let year_of_era = (adjusted_year - era * 400) as u32;
    let month_index = if month > 2 { month - 3 } else { month + 9 };
    let day_of_year = (153 * month_index + 2) / 5 + day - 1;
    let day_of_era = year_of_era * 365 + year_of_era / 4 - year_of_era / 100 + day_of_year;
    let absolute_days = era * 146_097 + i64::from(day_of_era) - 719_468;
    absolute_days as i32
}

fn days_in_month(year: i32, month: u32) -> Option<u32> {
    match month {
        1 | 3 | 5 | 7 | 8 | 10 | 12 => Some(31),
        4 | 6 | 9 | 11 => Some(30),
        2 => Some(if is_leap_year(year) { 29 } else { 28 }),
        _ => None,
    }
}

fn is_leap_year(year: i32) -> bool {
    (year % 4 == 0 && year % 100 != 0) || year % 400 == 0
}

fn current_unix_millis() -> i64 {
    let millis = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_millis();
    i64::try_from(millis).unwrap_or(i64::MAX)
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct UnionQuerySplit {
    segments: Vec<String>,
    union_all: Vec<bool>,
}

#[derive(Debug, Clone, Copy)]
struct HybridQueryWeights {
    vector: f32,
    text: f32,
}

fn split_top_level_union_query(query: &str) -> Result<Option<UnionQuerySplit>, QueryError> {
    let tokens = lex_cypher(query)?;
    if tokens.is_empty() {
        return Ok(None);
    }

    let mut paren_depth = 0usize;
    let mut bracket_depth = 0usize;
    let mut brace_depth = 0usize;
    let mut segment_start = 0usize;
    let mut segments = Vec::<String>::new();
    let mut union_all = Vec::<bool>::new();
    let mut idx = 0usize;

    while idx < tokens.len() {
        let token = &tokens[idx];
        match token.kind {
            TokenKind::Punctuation(CypherPunctuation::LeftParen) => {
                paren_depth = paren_depth.saturating_add(1);
            }
            TokenKind::Punctuation(CypherPunctuation::RightParen) => {
                paren_depth = paren_depth.saturating_sub(1);
            }
            TokenKind::Punctuation(CypherPunctuation::LeftBracket) => {
                bracket_depth = bracket_depth.saturating_add(1);
            }
            TokenKind::Punctuation(CypherPunctuation::RightBracket) => {
                bracket_depth = bracket_depth.saturating_sub(1);
            }
            TokenKind::Punctuation(CypherPunctuation::LeftBrace) => {
                brace_depth = brace_depth.saturating_add(1);
            }
            TokenKind::Punctuation(CypherPunctuation::RightBrace) => {
                brace_depth = brace_depth.saturating_sub(1);
            }
            TokenKind::Keyword(CypherKeyword::Union)
                if paren_depth == 0 && bracket_depth == 0 && brace_depth == 0 =>
            {
                let segment = query[segment_start..token.span.start].trim();
                if segment.is_empty() {
                    return Err(QueryError::new(
                        "UNION query branch cannot be empty before UNION",
                    ));
                }
                segments.push(segment.to_string());

                let mut consumed_all = false;
                if tokens
                    .get(idx + 1)
                    .is_some_and(|next| matches!(next.kind, TokenKind::Keyword(CypherKeyword::All)))
                {
                    consumed_all = true;
                }
                union_all.push(consumed_all);
                segment_start = if consumed_all {
                    tokens[idx + 1].span.end
                } else {
                    token.span.end
                };
                if consumed_all {
                    idx = idx.saturating_add(1);
                }
            }
            _ => {}
        }
        idx = idx.saturating_add(1);
    }

    if segments.is_empty() {
        return Ok(None);
    }

    let tail = query[segment_start..].trim();
    if tail.is_empty() {
        return Err(QueryError::new(
            "UNION query branch cannot be empty after UNION",
        ));
    }
    segments.push(tail.to_string());
    Ok(Some(UnionQuerySplit {
        segments,
        union_all,
    }))
}

fn dedupe_query_rows(
    rows: Vec<BTreeMap<String, PropertyValue>>,
    columns: &[String],
) -> Vec<BTreeMap<String, PropertyValue>> {
    let mut seen = BTreeSet::<String>::new();
    let mut unique = Vec::<BTreeMap<String, PropertyValue>>::new();
    for row in rows {
        let key = columns
            .iter()
            .map(|column| {
                row.get(column)
                    .map(format_property_value)
                    .unwrap_or_else(|| "null".to_string())
            })
            .collect::<Vec<_>>()
            .join("\u{1f}");
        if seen.insert(key) {
            unique.push(row);
        }
    }
    unique
}

fn query_result_from_rows(
    columns: Vec<String>,
    rows: Vec<BTreeMap<String, PropertyValue>>,
) -> QueryResult {
    let mut output = BTreeMap::<String, Vec<PropertyValue>>::new();
    for column in &columns {
        output.insert(column.clone(), Vec::with_capacity(rows.len()));
    }
    for row in rows {
        for column in &columns {
            output.entry(column.clone()).or_default().push(
                row.get(column)
                    .cloned()
                    .unwrap_or_else(|| PropertyValue::String("null".to_string())),
            );
        }
    }
    QueryResult {
        columns,
        batches: vec![RecordBatch { columns: output }],
    }
}

fn query_has_leading_optional_match(query: &CypherQuery) -> bool {
    matches!(
        query.clauses.first(),
        Some(CypherClause::Match(MatchClause { optional: true, .. }))
    )
}

fn optional_match_null_row_result(columns: Vec<String>) -> QueryResult {
    let mut output = BTreeMap::<String, Vec<PropertyValue>>::new();
    for column in &columns {
        output.insert(
            column.clone(),
            vec![PropertyValue::String("null".to_string())],
        );
    }
    QueryResult {
        columns,
        batches: vec![RecordBatch { columns: output }],
    }
}

fn query_requires_write_access(query: &str) -> bool {
    let upper = query.trim().to_ascii_uppercase();
    [
        "CREATE",
        "DELETE",
        "SET",
        "MERGE",
        "REMOVE",
        "DROP",
        "DETACH DELETE",
    ]
    .iter()
    .any(|keyword| upper.contains(keyword))
}

fn query_operation_kind(query: &str) -> &'static str {
    let upper = query.trim().to_ascii_uppercase();
    if upper.contains("CREATE") {
        "CREATE"
    } else if upper.contains("DELETE") {
        "DELETE"
    } else if upper.contains("SET") {
        "SET"
    } else if upper.contains("MERGE") {
        "MERGE"
    } else if upper.contains("REMOVE") {
        "REMOVE"
    } else if upper.contains("DROP") {
        "DROP"
    } else {
        "WRITE"
    }
}

fn temporal_i64_property(properties: &PropertyMap, key: &str) -> Result<Option<i64>, DbError> {
    match properties.get(key) {
        Some(PropertyValue::I64(value)) => Ok(Some(*value)),
        Some(other) => Err(DbError::InvalidArgument(format!(
            "temporal property '{key}' must be i64 unix millis, found {}",
            property_value_type_name(other)
        ))),
        None => Ok(None),
    }
}

fn parse_edge_valid_window(
    properties: &PropertyMap,
) -> Result<(Option<i64>, Option<i64>), DbError> {
    let valid_from = temporal_i64_property(properties, "valid_from")?;
    let valid_to = temporal_i64_property(properties, "valid_to")?;
    validate_valid_window(valid_from, valid_to).map_err(DbError::InvalidArgument)?;
    Ok((valid_from, valid_to))
}

#[derive(Debug, Clone, PartialEq)]
struct RuntimeEdgeRef {
    edge_id: u64,
    src: u64,
    dst: u64,
    edge_type: Option<String>,
}

#[derive(Debug, Clone, PartialEq)]
enum RuntimeValue {
    Null,
    Property(PropertyValue),
    Node(u64),
    Edge(RuntimeEdgeRef),
}

#[derive(Debug, Clone, PartialEq)]
struct RuntimeBatch {
    columns: Vec<String>,
    data: BTreeMap<String, Vec<RuntimeValue>>,
}

/// One bound value in a factorized result tree.
#[derive(Debug, Clone, PartialEq)]
struct FactorNode {
    variable: String,
    value: RuntimeValue,
    edge_variable: Option<String>,
    edge_value: Option<RuntimeValue>,
    children: Vec<FactorNode>,
}

/// A correlated variable group in a factorized result tree.
#[derive(Debug, Clone, PartialEq)]
struct FactorGroup {
    variable: String,
    roots: Vec<FactorNode>,
    all_variables: Vec<String>,
}

/// Factorized intermediate result representation.
#[derive(Debug, Clone, PartialEq)]
struct FactorTree {
    groups: Vec<FactorGroup>,
}

impl RuntimeBatch {
    fn new(columns: Vec<String>) -> Self {
        let mut data = BTreeMap::<String, Vec<RuntimeValue>>::new();
        for column in &columns {
            data.insert(column.clone(), Vec::new());
        }
        Self { columns, data }
    }

    fn row_count(&self) -> usize {
        self.columns
            .first()
            .and_then(|column| self.data.get(column))
            .map(|values| values.len())
            .unwrap_or(0)
    }

    fn push_row(&mut self, row: &BTreeMap<String, RuntimeValue>) {
        for column in &self.columns {
            let value = row.get(column).cloned().unwrap_or(RuntimeValue::Null);
            self.data
                .get_mut(column)
                .expect("runtime column must exist")
                .push(value);
        }
    }
}

fn runtime_value_key(value: &RuntimeValue) -> String {
    match value {
        RuntimeValue::Null => "null".to_string(),
        RuntimeValue::Node(value) => format!("node:{value}"),
        RuntimeValue::Edge(value) => format!("edge:{}:{}:{}", value.edge_id, value.src, value.dst),
        RuntimeValue::Property(value) => match value {
            PropertyValue::Bool(value) => format!("bool:{value}"),
            PropertyValue::I64(value) => format!("i64:{value}"),
            PropertyValue::F64(value) => format!("f64:{value}"),
            PropertyValue::String(value) => format!("string:{value}"),
            PropertyValue::Bytes(value) => format!(
                "bytes:{}",
                value
                    .iter()
                    .map(|byte| format!("{byte:02x}"))
                    .collect::<String>()
            ),
            PropertyValue::Vector(value) => format!(
                "vector:[{}]",
                value
                    .iter()
                    .map(|entry| entry.to_string())
                    .collect::<Vec<_>>()
                    .join(",")
            ),
            PropertyValue::Date(value) => format!("date:{value}"),
            PropertyValue::DateTime {
                micros,
                tz_offset_minutes,
            } => format!("datetime:{micros}:{tz_offset_minutes}"),
            PropertyValue::Duration {
                months,
                days,
                nanos,
            } => format!("duration:{months}:{days}:{nanos}"),
            PropertyValue::List(values) => format!(
                "list:[{}]",
                values
                    .iter()
                    .map(|value| runtime_value_key(&RuntimeValue::Property(value.clone())))
                    .collect::<Vec<_>>()
                    .join(",")
            ),
            PropertyValue::Map(values) => format!(
                "map:{{{}}}",
                values
                    .iter()
                    .map(|(key, value)| format!(
                        "{key}:{}",
                        runtime_value_key(&RuntimeValue::Property(value.clone()))
                    ))
                    .collect::<Vec<_>>()
                    .join(",")
            ),
            // PropertyValue is `#[non_exhaustive]` (EVAL-RUST-QUALITY-CYCLE3 B3);
            // future variants get a debug-formatted key so equality keeps working.
            other => format!("unknown:{other:?}"),
        },
    }
}

fn runtime_value_variant_rank(value: &RuntimeValue) -> u8 {
    match value {
        RuntimeValue::Null => 0,
        RuntimeValue::Property(_) => 1,
        RuntimeValue::Node(_) => 2,
        RuntimeValue::Edge(_) => 3,
    }
}

fn compare_runtime_values(left: &RuntimeValue, right: &RuntimeValue) -> std::cmp::Ordering {
    match (left, right) {
        (RuntimeValue::Null, RuntimeValue::Null) => std::cmp::Ordering::Equal,
        (RuntimeValue::Null, _) => std::cmp::Ordering::Less,
        (_, RuntimeValue::Null) => std::cmp::Ordering::Greater,
        (RuntimeValue::Node(left_id), RuntimeValue::Node(right_id)) => left_id.cmp(right_id),
        (RuntimeValue::Edge(left_edge), RuntimeValue::Edge(right_edge)) => left_edge
            .edge_id
            .cmp(&right_edge.edge_id)
            .then_with(|| left_edge.src.cmp(&right_edge.src))
            .then_with(|| left_edge.dst.cmp(&right_edge.dst)),
        (RuntimeValue::Property(left_value), RuntimeValue::Property(right_value)) => {
            left_value.cmp(right_value)
        }
        _ => runtime_value_variant_rank(left)
            .cmp(&runtime_value_variant_rank(right))
            .then_with(|| runtime_value_key(left).cmp(&runtime_value_key(right))),
    }
}

fn runtime_order_key_fallback(
    expression: &CypherExpression,
    row: &BTreeMap<String, RuntimeValue>,
) -> Option<RuntimeValue> {
    match expression {
        CypherExpression::Identifier(name) => row.get(name).cloned(),
        CypherExpression::PropertyAccess { property, .. } => row.get(property).cloned(),
        _ => None,
    }
}

fn runtime_value_truthy(value: &RuntimeValue) -> bool {
    match value {
        RuntimeValue::Null => false,
        RuntimeValue::Node(_) | RuntimeValue::Edge(_) => true,
        RuntimeValue::Property(PropertyValue::Bool(value)) => *value,
        RuntimeValue::Property(PropertyValue::I64(value)) => *value != 0,
        RuntimeValue::Property(PropertyValue::F64(value)) => *value != 0.0,
        RuntimeValue::Property(PropertyValue::String(value)) => !value.is_empty(),
        RuntimeValue::Property(PropertyValue::Bytes(value)) => !value.is_empty(),
        RuntimeValue::Property(PropertyValue::Vector(value)) => !value.is_empty(),
        RuntimeValue::Property(PropertyValue::Date(_)) => true,
        RuntimeValue::Property(PropertyValue::DateTime { .. }) => true,
        RuntimeValue::Property(PropertyValue::Duration { .. }) => true,
        RuntimeValue::Property(PropertyValue::List(value)) => !value.is_empty(),
        RuntimeValue::Property(PropertyValue::Map(value)) => !value.is_empty(),
        // PropertyValue is `#[non_exhaustive]` (EVAL-RUST-QUALITY-CYCLE3 B3);
        // unknown future variants are treated as truthy by default.
        RuntimeValue::Property(_) => true,
    }
}

fn runtime_to_property_value(value: &RuntimeValue) -> PropertyValue {
    match value {
        RuntimeValue::Null => PropertyValue::String("null".to_string()),
        RuntimeValue::Node(value) => PropertyValue::I64(*value as i64),
        RuntimeValue::Edge(value) => PropertyValue::I64(value.edge_id as i64),
        RuntimeValue::Property(value) => value.clone(),
    }
}

fn runtime_to_f64(value: &RuntimeValue) -> Option<f64> {
    match value {
        RuntimeValue::Property(PropertyValue::I64(value)) => Some(*value as f64),
        RuntimeValue::Property(PropertyValue::F64(value)) => Some(*value),
        _ => None,
    }
}

fn runtime_to_vector(value: &RuntimeValue) -> Option<Vec<f32>> {
    match value {
        RuntimeValue::Property(PropertyValue::Vector(value)) => Some(value.clone()),
        RuntimeValue::Property(PropertyValue::String(value)) => parse_vector_literal_text(value),
        RuntimeValue::Property(PropertyValue::List(values)) => values
            .iter()
            .map(|value| match value {
                PropertyValue::I64(value) => Some(*value as f32),
                PropertyValue::F64(value) => Some(*value as f32),
                _ => None,
            })
            .collect::<Option<Vec<_>>>(),
        _ => None,
    }
}

fn levenshtein(a: &str, b: &str) -> usize {
    if a == b {
        return 0;
    }
    if a.is_empty() {
        return b.chars().count();
    }
    if b.is_empty() {
        return a.chars().count();
    }

    let a_chars = a.chars().collect::<Vec<_>>();
    let b_chars = b.chars().collect::<Vec<_>>();
    let mut prev = (0..=b_chars.len()).collect::<Vec<_>>();
    let mut curr = vec![0usize; b_chars.len() + 1];

    for (i, ca) in a_chars.iter().enumerate() {
        curr[0] = i + 1;
        for (j, cb) in b_chars.iter().enumerate() {
            let cost = usize::from(ca != cb);
            curr[j + 1] = (prev[j + 1] + 1).min(curr[j] + 1).min(prev[j] + cost);
        }
        prev.copy_from_slice(&curr);
    }

    prev[b_chars.len()]
}

fn contains_text_match(text: &str, query: &str) -> bool {
    let text = text.to_ascii_lowercase();
    let query = query.to_ascii_lowercase();
    if query.is_empty() {
        return false;
    }
    if text.contains(&query) {
        return true;
    }
    let query_tokens = query.split_whitespace().collect::<Vec<_>>();
    if query_tokens.is_empty() {
        return false;
    }
    let text_tokens = text
        .split(|c: char| !c.is_ascii_alphanumeric())
        .filter(|token| !token.is_empty())
        .collect::<Vec<_>>();
    query_tokens.iter().all(|needle| {
        text_tokens
            .iter()
            .any(|hay| levenshtein(hay, needle) <= 1 || hay.starts_with(needle))
    })
}

fn strip_prefix_case_insensitive<'a>(input: &'a str, prefix: &str) -> Option<&'a str> {
    if input.len() < prefix.len() {
        return None;
    }
    if input[..prefix.len()].eq_ignore_ascii_case(prefix) {
        return Some(&input[prefix.len()..]);
    }
    None
}

fn split_call_invocation(input: &str) -> Option<(&str, &str)> {
    let mut depth = 1usize;
    let mut in_single_quote = false;
    let mut in_double_quote = false;
    let mut escaped = false;
    for (idx, ch) in input.char_indices() {
        if escaped {
            escaped = false;
            continue;
        }
        if ch == '\\' {
            escaped = true;
            continue;
        }
        if ch == '\'' && !in_double_quote {
            in_single_quote = !in_single_quote;
            continue;
        }
        if ch == '"' && !in_single_quote {
            in_double_quote = !in_double_quote;
            continue;
        }
        if in_single_quote || in_double_quote {
            continue;
        }
        match ch {
            '(' => depth += 1,
            ')' => {
                depth -= 1;
                if depth == 0 {
                    return Some((&input[..idx], &input[idx + 1..]));
                }
            }
            _ => {}
        }
    }
    None
}

fn split_top_level_args(input: &str) -> Vec<String> {
    let mut args = Vec::<String>::new();
    let mut start = 0usize;
    let mut bracket_depth = 0usize;
    let mut paren_depth = 0usize;
    let mut in_single_quote = false;
    let mut in_double_quote = false;
    let mut escaped = false;

    for (idx, ch) in input.char_indices() {
        if escaped {
            escaped = false;
            continue;
        }
        if ch == '\\' {
            escaped = true;
            continue;
        }
        if ch == '\'' && !in_double_quote {
            in_single_quote = !in_single_quote;
            continue;
        }
        if ch == '"' && !in_single_quote {
            in_double_quote = !in_double_quote;
            continue;
        }
        if in_single_quote || in_double_quote {
            continue;
        }
        match ch {
            '[' => bracket_depth += 1,
            ']' => bracket_depth = bracket_depth.saturating_sub(1),
            '(' => paren_depth += 1,
            ')' => paren_depth = paren_depth.saturating_sub(1),
            ',' if bracket_depth == 0 && paren_depth == 0 => {
                args.push(input[start..idx].trim().to_string());
                start = idx + 1;
            }
            _ => {}
        }
    }
    let tail = input[start..].trim();
    if !tail.is_empty() {
        args.push(tail.to_string());
    }
    args
}

fn parse_string_argument(raw: &str) -> Option<String> {
    let trimmed = raw.trim();
    if trimmed.len() < 2 {
        return None;
    }
    let bytes = trimmed.as_bytes();
    let quote = bytes.first().copied()?;
    if (quote != b'\'' && quote != b'"') || bytes.last().copied()? != quote {
        return None;
    }
    Some(trimmed[1..trimmed.len() - 1].to_string())
}

fn parse_vector_argument(raw: &str) -> Option<Vec<f32>> {
    parse_vector_literal_text(raw.trim())
}

fn parse_distance_metric_argument(raw: &str) -> Option<VectorDistanceMetric> {
    let value = parse_string_argument(raw).unwrap_or_else(|| raw.trim().to_string());
    match value.to_ascii_lowercase().as_str() {
        "cosine" => Some(VectorDistanceMetric::Cosine),
        "euclidean" | "l2" => Some(VectorDistanceMetric::Euclidean),
        "dot" | "dotproduct" | "dot_product" => Some(VectorDistanceMetric::DotProduct),
        _ => None,
    }
}

fn parse_time_range_argument(raw: &str) -> Option<(i64, i64)> {
    let trimmed = raw.trim();
    if trimmed.len() < 5 || !trimmed.starts_with('[') || !trimmed.ends_with(']') {
        return None;
    }
    let inner = &trimmed[1..trimmed.len() - 1];
    let values = split_top_level_args(inner);
    if values.len() != 2 {
        return None;
    }
    let start = values[0].trim().parse::<i64>().ok()?;
    let end = values[1].trim().parse::<i64>().ok()?;
    Some((start, end))
}

fn rows_from_batches(batches: &[RuntimeBatch]) -> Vec<BTreeMap<String, RuntimeValue>> {
    let mut rows = Vec::<BTreeMap<String, RuntimeValue>>::new();
    for batch in batches {
        let row_count = batch.row_count();
        for row_idx in 0..row_count {
            let mut row = BTreeMap::<String, RuntimeValue>::new();
            for column in &batch.columns {
                if let Some(values) = batch.data.get(column) {
                    if let Some(value) = values.get(row_idx) {
                        row.insert(column.clone(), value.clone());
                    }
                }
            }
            rows.push(row);
        }
    }
    rows
}

fn batches_from_rows(
    rows: &[BTreeMap<String, RuntimeValue>],
    column_order: &[String],
    batch_size: usize,
) -> Vec<RuntimeBatch> {
    if rows.is_empty() {
        return Vec::new();
    }
    let mut out = Vec::<RuntimeBatch>::new();
    let mut current = RuntimeBatch::new(column_order.to_vec());
    for row in rows {
        current.push_row(row);
        if current.row_count() >= batch_size {
            out.push(current);
            current = RuntimeBatch::new(column_order.to_vec());
        }
    }
    if current.row_count() > 0 {
        out.push(current);
    }
    out
}

fn merge_runtime_rows(
    left: &BTreeMap<String, RuntimeValue>,
    right: &BTreeMap<String, RuntimeValue>,
) -> Option<BTreeMap<String, RuntimeValue>> {
    let mut merged = left.clone();
    for (key, value) in right {
        if let Some(existing) = merged.get(key) {
            if existing != value {
                return None;
            }
        } else {
            merged.insert(key.clone(), value.clone());
        }
    }
    Some(merged)
}

/// Materialize a factor tree into flat rows.
fn materialize_factor_tree(tree: &FactorTree) -> Vec<BTreeMap<String, RuntimeValue>> {
    if tree.groups.is_empty() {
        return Vec::new();
    }

    let mut groups = Vec::<Vec<BTreeMap<String, RuntimeValue>>>::new();
    for group in &tree.groups {
        let mut rows = Vec::<BTreeMap<String, RuntimeValue>>::new();
        for root in &group.roots {
            let mut partial = BTreeMap::<String, RuntimeValue>::new();
            materialize_factor_node(root, &mut partial, &mut rows);
        }
        if rows.is_empty() {
            return Vec::new();
        }
        groups.push(rows);
    }

    let mut result = groups[0].clone();
    for group_rows in groups.iter().skip(1) {
        let mut combined = Vec::<BTreeMap<String, RuntimeValue>>::new();
        for left in &result {
            for right in group_rows {
                if let Some(merged) = merge_runtime_rows(left, right) {
                    combined.push(merged);
                }
            }
        }
        if combined.is_empty() {
            return Vec::new();
        }
        result = combined;
    }
    result
}

fn materialize_factor_node(
    node: &FactorNode,
    partial: &mut BTreeMap<String, RuntimeValue>,
    output: &mut Vec<BTreeMap<String, RuntimeValue>>,
) {
    partial.insert(node.variable.clone(), node.value.clone());
    if let (Some(edge_variable), Some(edge_value)) = (&node.edge_variable, &node.edge_value) {
        partial.insert(edge_variable.clone(), edge_value.clone());
    }

    if node.children.is_empty() {
        output.push(partial.clone());
    } else {
        let mut by_variable = BTreeMap::<String, Vec<&FactorNode>>::new();
        for child in &node.children {
            by_variable
                .entry(child.variable.clone())
                .or_default()
                .push(child);
        }

        if by_variable.len() == 1 {
            for child in &node.children {
                materialize_factor_node(child, partial, output);
            }
        } else {
            let mut per_variable_rows = Vec::<Vec<BTreeMap<String, RuntimeValue>>>::new();
            for children in by_variable.values() {
                let mut rows = Vec::<BTreeMap<String, RuntimeValue>>::new();
                for child in children {
                    let mut child_partial = BTreeMap::<String, RuntimeValue>::new();
                    materialize_factor_node(child, &mut child_partial, &mut rows);
                }
                if rows.is_empty() {
                    partial.remove(&node.variable);
                    if let Some(edge_variable) = &node.edge_variable {
                        partial.remove(edge_variable);
                    }
                    return;
                }
                per_variable_rows.push(rows);
            }

            let mut combined = per_variable_rows[0].clone();
            for group_rows in per_variable_rows.iter().skip(1) {
                let mut next = Vec::<BTreeMap<String, RuntimeValue>>::new();
                for left in &combined {
                    for right in group_rows {
                        if let Some(merged) = merge_runtime_rows(left, right) {
                            next.push(merged);
                        }
                    }
                }
                combined = next;
                if combined.is_empty() {
                    break;
                }
            }

            for row in combined {
                if let Some(merged) = merge_runtime_rows(partial, &row) {
                    output.push(merged);
                }
            }
        }
    }

    partial.remove(&node.variable);
    if let Some(edge_variable) = &node.edge_variable {
        partial.remove(edge_variable);
    }
}

/// Intersects two sorted, deduplicated slices.
fn sorted_intersect(a: &[u64], b: &[u64]) -> Vec<u64> {
    let mut out = Vec::<u64>::new();
    let (mut i, mut j) = (0usize, 0usize);
    while i < a.len() && j < b.len() {
        match a[i].cmp(&b[j]) {
            std::cmp::Ordering::Less => i += 1,
            std::cmp::Ordering::Greater => j += 1,
            std::cmp::Ordering::Equal => {
                out.push(a[i]);
                i += 1;
                j += 1;
            }
        }
    }
    out
}

#[derive(Debug, Clone)]
struct AggregateAccumulator {
    function: AggregateFunction,
    distinct_seen: BTreeSet<String>,
    count: i64,
    sum: f64,
    sum_is_float: bool,
    min: Option<PropertyValue>,
    max: Option<PropertyValue>,
    collect: Vec<PropertyValue>,
}

impl AggregateAccumulator {
    fn new(function: &AggregateFunction) -> Self {
        Self {
            function: function.clone(),
            distinct_seen: BTreeSet::new(),
            count: 0,
            sum: 0.0,
            sum_is_float: false,
            min: None,
            max: None,
            collect: Vec::new(),
        }
    }

    fn push(&mut self, arguments: Vec<RuntimeValue>) {
        let value = arguments.into_iter().next().unwrap_or(RuntimeValue::Null);
        if self.function.distinct {
            let key = runtime_value_key(&value);
            if !self.distinct_seen.insert(key) {
                return;
            }
        }
        match self.function.name.to_ascii_uppercase().as_str() {
            "COUNT"
                if !matches!(value, RuntimeValue::Null) || self.function.arguments.is_empty() =>
            {
                self.count += 1;
            }
            "SUM" => {
                if let Some(number) = runtime_to_f64(&value) {
                    self.sum += number;
                    self.sum_is_float |=
                        matches!(value, RuntimeValue::Property(PropertyValue::F64(_)));
                }
            }
            "AVG" => {
                if let Some(number) = runtime_to_f64(&value) {
                    self.sum += number;
                    self.count += 1;
                    self.sum_is_float = true;
                }
            }
            "MIN" => {
                let candidate = runtime_to_property_value(&value);
                if let Some(current) = &self.min {
                    if compare_property_values(&candidate, current)
                        .map(|ordering| ordering == std::cmp::Ordering::Less)
                        .unwrap_or(false)
                    {
                        self.min = Some(candidate);
                    }
                } else {
                    self.min = Some(candidate);
                }
            }
            "MAX" => {
                let candidate = runtime_to_property_value(&value);
                if let Some(current) = &self.max {
                    if compare_property_values(&candidate, current)
                        .map(|ordering| ordering == std::cmp::Ordering::Greater)
                        .unwrap_or(false)
                    {
                        self.max = Some(candidate);
                    }
                } else {
                    self.max = Some(candidate);
                }
            }
            "COLLECT" => self.collect.push(runtime_to_property_value(&value)),
            _ => {}
        }
    }

    fn finish(&mut self) -> PropertyValue {
        match self.function.name.to_ascii_uppercase().as_str() {
            "COUNT" => PropertyValue::I64(self.count),
            "SUM" => {
                if self.sum_is_float {
                    PropertyValue::F64(self.sum)
                } else {
                    PropertyValue::I64(self.sum as i64)
                }
            }
            "AVG" => {
                if self.count == 0 {
                    PropertyValue::F64(0.0)
                } else {
                    PropertyValue::F64(self.sum / self.count as f64)
                }
            }
            "MIN" => self
                .min
                .clone()
                .unwrap_or_else(|| PropertyValue::String("null".to_string())),
            "MAX" => self
                .max
                .clone()
                .unwrap_or_else(|| PropertyValue::String("null".to_string())),
            "COLLECT" => {
                let value = self
                    .collect
                    .iter()
                    .map(format_property_value)
                    .collect::<Vec<_>>()
                    .join(", ");
                PropertyValue::String(format!("[{value}]"))
            }
            _ => PropertyValue::String("null".to_string()),
        }
    }
}

/// EVAL-RUST-QUALITY-CYCLE2 H7: returns the tokens or a parse error;
/// discarding the result silently swallows lex failures.
#[must_use = "ignoring the result discards the token stream and any ParseError"]
pub fn lex_cypher(input: &str) -> Result<Vec<Token>, ParseError> {
    let mut tokens = Vec::<Token>::new();
    let mut remaining = input;
    let mut offset = 0usize;

    while !remaining.is_empty() {
        let before = remaining.len();
        let _ = multispace0::<_, winnow::error::InputError<&str>>(&mut remaining);
        let consumed_whitespace = before.saturating_sub(remaining.len());
        offset += consumed_whitespace;
        if remaining.is_empty() {
            break;
        }

        let start = offset;

        if remaining.starts_with("//") {
            let end = remaining.find('\n').unwrap_or(remaining.len());
            let comment = remaining[2..end].to_string();
            let end_offset = start + end;
            tokens.push(Token {
                kind: TokenKind::Comment(comment),
                span: span_for(input, start, end_offset),
            });
            remaining = &remaining[end..];
            offset = end_offset;
            continue;
        }

        if remaining.starts_with("/*") {
            if let Some(end_idx) = remaining.find("*/") {
                let end = end_idx + 2;
                let comment = remaining[2..end_idx].to_string();
                let end_offset = start + end;
                tokens.push(Token {
                    kind: TokenKind::Comment(comment),
                    span: span_for(input, start, end_offset),
                });
                remaining = &remaining[end..];
                offset = end_offset;
                continue;
            }
            return Err(ParseError::new(input, start, "unterminated block comment"));
        }

        if let Some((kind, consumed)) = parse_multi_char_punctuation_or_operator(remaining) {
            let end_offset = start + consumed;
            tokens.push(Token {
                kind,
                span: span_for(input, start, end_offset),
            });
            remaining = &remaining[consumed..];
            offset = end_offset;
            continue;
        }

        let first = remaining
            .chars()
            .next()
            .expect("remaining is guaranteed non-empty");

        if first == '\'' || first == '"' {
            let (value, consumed) = parse_string_literal(input, remaining, start)?;
            let end_offset = start + consumed;
            tokens.push(Token {
                kind: TokenKind::StringLiteral(value),
                span: span_for(input, start, end_offset),
            });
            remaining = &remaining[consumed..];
            offset = end_offset;
            continue;
        }

        if first == '$' {
            let mut param_input = &remaining[1..];
            let parsed = parse_identifier_fragment(&mut param_input).ok_or_else(|| {
                ParseError::new(input, start + 1, "expected parameter name after '$'")
            })?;
            let consumed = 1 + remaining[1..].len().saturating_sub(param_input.len());
            let end_offset = start + consumed;
            tokens.push(Token {
                kind: TokenKind::Parameter(parsed.to_string()),
                span: span_for(input, start, end_offset),
            });
            remaining = &remaining[consumed..];
            offset = end_offset;
            continue;
        }

        if first.is_ascii_digit() {
            let (kind, consumed) = parse_numeric_literal(input, remaining, start)?;
            let end_offset = start + consumed;
            tokens.push(Token {
                kind,
                span: span_for(input, start, end_offset),
            });
            remaining = &remaining[consumed..];
            offset = end_offset;
            continue;
        }

        if first.is_ascii_alphabetic() || first == '_' {
            let mut ident_input = remaining;
            let ident = parse_identifier_fragment(&mut ident_input)
                .expect("identifier parse should succeed after leading-char guard");
            let consumed = remaining.len().saturating_sub(ident_input.len());
            let end_offset = start + consumed;
            let kind = keyword_from_identifier(ident)
                .map(TokenKind::Keyword)
                .unwrap_or_else(|| TokenKind::Identifier(ident.to_string()));
            tokens.push(Token {
                kind,
                span: span_for(input, start, end_offset),
            });
            remaining = &remaining[consumed..];
            offset = end_offset;
            continue;
        }

        if let Some(kind) = parse_single_char_token(first) {
            let end_offset = start + first.len_utf8();
            tokens.push(Token {
                kind,
                span: span_for(input, start, end_offset),
            });
            remaining = &remaining[first.len_utf8()..];
            offset = end_offset;
            continue;
        }

        return Err(ParseError::new(
            input,
            start,
            format!("unexpected character '{}'", first),
        ));
    }

    Ok(tokens)
}

/// EVAL-RUST-QUALITY-CYCLE2 H7: returns the AST or a parse error;
/// discarding the result silently swallows parse failures.
#[must_use = "ignoring the result discards the AST and any ParseError"]
pub fn parse_cypher(query: &str) -> Result<CypherAst, ParseError> {
    let tokens = lex_cypher(query)?;
    let mut parser = CypherParser::new(query, tokens);
    parser.parse_query()
}

fn parse_identifier_fragment<'a>(input: &mut &'a str) -> Option<&'a str> {
    let mut probe = *input;
    let parsed: &str = take_while::<_, _, winnow::error::InputError<&str>>(1.., |c: char| {
        c.is_ascii_alphanumeric() || c == '_'
    })
    .parse_next(&mut probe)
    .ok()?;
    let starts_with_digit = parsed
        .chars()
        .next()
        .map(|c| c.is_ascii_digit())
        .unwrap_or(false);
    if starts_with_digit {
        return None;
    }
    *input = probe;
    Some(parsed)
}

fn parse_multi_char_punctuation_or_operator(remaining: &str) -> Option<(TokenKind, usize)> {
    if remaining.starts_with("<->") {
        return Some((TokenKind::Operator(CypherOperator::VectorDistance), 3));
    }
    if remaining.starts_with("..") {
        return Some((TokenKind::Punctuation(CypherPunctuation::Range), 2));
    }
    if remaining.starts_with("<=") {
        return Some((TokenKind::Operator(CypherOperator::LessThanOrEqual), 2));
    }
    if remaining.starts_with(">=") {
        return Some((TokenKind::Operator(CypherOperator::GreaterThanOrEqual), 2));
    }
    if remaining.starts_with("<>") {
        return Some((TokenKind::Operator(CypherOperator::NotEq), 2));
    }
    if remaining.starts_with("=~") {
        return Some((TokenKind::Operator(CypherOperator::RegexMatch), 2));
    }
    None
}

fn parse_single_char_token(ch: char) -> Option<TokenKind> {
    match ch {
        '+' => Some(TokenKind::Operator(CypherOperator::Plus)),
        '-' => Some(TokenKind::Operator(CypherOperator::Minus)),
        '*' => Some(TokenKind::Operator(CypherOperator::Multiply)),
        '/' => Some(TokenKind::Operator(CypherOperator::Divide)),
        '=' => Some(TokenKind::Operator(CypherOperator::Eq)),
        '<' => Some(TokenKind::Operator(CypherOperator::LessThan)),
        '>' => Some(TokenKind::Operator(CypherOperator::GreaterThan)),
        '.' => Some(TokenKind::Punctuation(CypherPunctuation::Dot)),
        ',' => Some(TokenKind::Punctuation(CypherPunctuation::Comma)),
        '(' => Some(TokenKind::Punctuation(CypherPunctuation::LeftParen)),
        ')' => Some(TokenKind::Punctuation(CypherPunctuation::RightParen)),
        '[' => Some(TokenKind::Punctuation(CypherPunctuation::LeftBracket)),
        ']' => Some(TokenKind::Punctuation(CypherPunctuation::RightBracket)),
        '{' => Some(TokenKind::Punctuation(CypherPunctuation::LeftBrace)),
        '}' => Some(TokenKind::Punctuation(CypherPunctuation::RightBrace)),
        ':' => Some(TokenKind::Punctuation(CypherPunctuation::Colon)),
        '|' => Some(TokenKind::Punctuation(CypherPunctuation::Pipe)),
        _ => None,
    }
}

fn parse_string_literal(
    input: &str,
    remaining: &str,
    absolute_start: usize,
) -> Result<(String, usize), ParseError> {
    let mut chars = remaining.char_indices();
    let (_, quote) = chars
        .next()
        .expect("string parser called on non-empty input");
    let mut out = String::new();
    let mut escaped = false;

    for (idx, ch) in chars {
        if escaped {
            let mapped = match ch {
                'n' => '\n',
                'r' => '\r',
                't' => '\t',
                '\\' => '\\',
                '\'' => '\'',
                '"' => '"',
                other => other,
            };
            out.push(mapped);
            escaped = false;
            continue;
        }
        if ch == '\\' {
            escaped = true;
            continue;
        }
        if ch == quote {
            return Ok((out, idx + ch.len_utf8()));
        }
        out.push(ch);
    }

    Err(ParseError::new(
        input,
        absolute_start,
        "unterminated string literal",
    ))
}

fn parse_numeric_literal(
    input: &str,
    remaining: &str,
    absolute_start: usize,
) -> Result<(TokenKind, usize), ParseError> {
    let mut probe = remaining;
    let int_part: &str = digit1::<_, winnow::error::InputError<&str>>(&mut probe)
        .map_err(|_| ParseError::new(input, absolute_start, "expected numeric literal"))?;
    let int_consumed = remaining.len().saturating_sub(probe.len());

    if let Some(after_dot) = probe.strip_prefix('.') {
        let mut fraction_probe = after_dot;
        if let Ok(frac_part) = digit1::<_, winnow::error::InputError<&str>>(&mut fraction_probe) {
            let consumed = int_consumed + 1 + after_dot.len().saturating_sub(fraction_probe.len());
            let literal = format!("{int_part}.{frac_part}");
            let value = literal
                .parse::<f64>()
                .expect("digit-only float literal should always parse");
            return Ok((TokenKind::FloatLiteral(value), consumed));
        }
    }

    let value = int_part
        .parse::<i64>()
        .map_err(|_| ParseError::new(input, absolute_start, "integer literal out of range"))?;
    Ok((TokenKind::IntegerLiteral(value), int_consumed))
}

fn keyword_from_identifier(identifier: &str) -> Option<CypherKeyword> {
    match identifier.to_ascii_uppercase().as_str() {
        "MATCH" => Some(CypherKeyword::Match),
        "WHERE" => Some(CypherKeyword::Where),
        "AT" => Some(CypherKeyword::At),
        "TIME" => Some(CypherKeyword::Time),
        "SYSTEM" => Some(CypherKeyword::System),
        "RETURN" => Some(CypherKeyword::Return),
        "CREATE" => Some(CypherKeyword::Create),
        "DELETE" => Some(CypherKeyword::Delete),
        "SET" => Some(CypherKeyword::Set),
        "REMOVE" => Some(CypherKeyword::Remove),
        "WITH" => Some(CypherKeyword::With),
        "ORDER" => Some(CypherKeyword::Order),
        "BY" => Some(CypherKeyword::By),
        "LIMIT" => Some(CypherKeyword::Limit),
        "SKIP" => Some(CypherKeyword::Skip),
        "OPTIONAL" => Some(CypherKeyword::Optional),
        "MERGE" => Some(CypherKeyword::Merge),
        "ON" => Some(CypherKeyword::On),
        "AS" => Some(CypherKeyword::As),
        "AND" => Some(CypherKeyword::And),
        "OR" => Some(CypherKeyword::Or),
        "XOR" => Some(CypherKeyword::Xor),
        "NOT" => Some(CypherKeyword::Not),
        "IN" => Some(CypherKeyword::In),
        "IS" => Some(CypherKeyword::Is),
        "NULL" => Some(CypherKeyword::Null),
        "TRUE" => Some(CypherKeyword::True),
        "FALSE" => Some(CypherKeyword::False),
        "DISTINCT" => Some(CypherKeyword::Distinct),
        "UNION" => Some(CypherKeyword::Union),
        "ALL" => Some(CypherKeyword::All),
        "EXISTS" => Some(CypherKeyword::Exists),
        "CASE" => Some(CypherKeyword::Case),
        "WHEN" => Some(CypherKeyword::When),
        "THEN" => Some(CypherKeyword::Then),
        "ELSE" => Some(CypherKeyword::Else),
        "END" => Some(CypherKeyword::End),
        "DESC" => Some(CypherKeyword::Desc),
        "ASC" => Some(CypherKeyword::Asc),
        "DETACH" => Some(CypherKeyword::Detach),
        "UNWIND" => Some(CypherKeyword::Unwind),
        "CALL" => Some(CypherKeyword::Call),
        "YIELD" => Some(CypherKeyword::Yield),
        "CONTAINS" => Some(CypherKeyword::Contains),
        "TEXT" => Some(CypherKeyword::Text),
        _ => None,
    }
}

fn line_col_for_offset(input: &str, offset: usize) -> (usize, usize) {
    let bounded = offset.min(input.len());
    let mut line = 1usize;
    let mut column = 1usize;
    for ch in input[..bounded].chars() {
        if ch == '\n' {
            line += 1;
            column = 1;
        } else {
            column += 1;
        }
    }
    (line, column)
}

fn span_for(input: &str, start: usize, end: usize) -> SourceSpan {
    let (line, column) = line_col_for_offset(input, start);
    SourceSpan {
        start,
        end,
        line,
        column,
    }
}

#[derive(Debug)]
struct CypherParser<'a> {
    input: &'a str,
    tokens: Vec<Token>,
    index: usize,
}

impl<'a> CypherParser<'a> {
    fn new(input: &'a str, tokens: Vec<Token>) -> Self {
        let filtered = tokens
            .into_iter()
            .filter(|token| !matches!(token.kind, TokenKind::Comment(_)))
            .collect::<Vec<_>>();
        Self {
            input,
            tokens: filtered,
            index: 0,
        }
    }

    fn from_tokens(input: &'a str, tokens: Vec<Token>) -> Self {
        Self {
            input,
            tokens,
            index: 0,
        }
    }

    fn parse_query(&mut self) -> Result<CypherQuery, ParseError> {
        if self.tokens.is_empty() {
            return Err(ParseError::new(self.input, 0, "empty query"));
        }

        let mut clauses = Vec::<CypherClause>::new();
        let mut return_clause = None;

        while !self.is_eof() {
            if self.check_keyword(CypherKeyword::Return) {
                return_clause = Some(self.parse_return_clause()?);
                break;
            }

            let clause = if self.check_keyword(CypherKeyword::Optional)
                || self.check_keyword(CypherKeyword::Match)
            {
                CypherClause::Match(self.parse_match_clause()?)
            } else if self.check_keyword(CypherKeyword::Create) {
                self.parse_create_clause()?
            } else if self.check_keyword(CypherKeyword::Detach)
                || self.check_keyword(CypherKeyword::Delete)
            {
                CypherClause::Delete(self.parse_delete_clause()?)
            } else if self.check_keyword(CypherKeyword::Set) {
                CypherClause::Set(self.parse_set_clause()?)
            } else if self.check_keyword(CypherKeyword::Remove) {
                CypherClause::Remove(self.parse_remove_clause()?)
            } else if self.check_keyword(CypherKeyword::With) {
                CypherClause::With(self.parse_with_clause()?)
            } else if self.check_keyword(CypherKeyword::Unwind) {
                CypherClause::Unwind(self.parse_unwind_clause()?)
            } else if self.check_keyword(CypherKeyword::Merge) {
                CypherClause::Merge(self.parse_merge_clause()?)
            } else {
                return Err(self.error_here("unexpected token while parsing clause"));
            };
            clauses.push(clause);
        }

        if !self.is_eof() {
            return Err(self.error_here("unexpected token after end of query"));
        }

        Ok(CypherQuery {
            clauses,
            return_clause,
        })
    }

    fn parse_match_clause(&mut self) -> Result<MatchClause, ParseError> {
        let optional = if self.match_keyword(CypherKeyword::Optional) {
            self.expect_keyword(CypherKeyword::Match)?;
            true
        } else {
            self.expect_keyword(CypherKeyword::Match)?;
            false
        };

        let patterns = self.parse_pattern_list()?;
        let where_predicate = if self.match_keyword(CypherKeyword::Where) {
            Some(self.parse_expression()?)
        } else {
            None
        };
        let temporal_filter = if self.match_keyword(CypherKeyword::At) {
            Some(self.parse_match_temporal_filter()?)
        } else {
            None
        };

        Ok(MatchClause {
            optional,
            patterns,
            where_predicate,
            temporal_filter,
        })
    }

    fn parse_match_temporal_filter(&mut self) -> Result<TemporalFilter, ParseError> {
        let scope = if self.match_keyword(CypherKeyword::System) {
            TemporalScope::SystemTime
        } else {
            TemporalScope::ValidTime
        };
        self.expect_keyword(CypherKeyword::Time)?;
        let timestamp_millis = self.parse_i64_literal("for AT TIME timestamp")?;
        Ok(TemporalFilter {
            scope,
            timestamp_millis,
        })
    }

    fn parse_create_clause(&mut self) -> Result<CypherClause, ParseError> {
        self.expect_keyword(CypherKeyword::Create)?;
        if self.match_identifier_text("INDEX") {
            return Ok(CypherClause::CreateIndex(self.parse_create_index_clause()?));
        }
        let patterns = self.parse_pattern_list()?;
        Ok(CypherClause::Create(CreateClause { patterns }))
    }

    fn parse_create_index_clause(&mut self) -> Result<CreateIndexClause, ParseError> {
        let parse_legacy_on = |parser: &mut Self| -> Result<CreateIndexClause, ParseError> {
            parser.expect_punctuation(CypherPunctuation::Colon)?;
            let label = parser.parse_identifier("for index label")?;
            parser.expect_punctuation(CypherPunctuation::LeftParen)?;
            let mut property_keys = Vec::<String>::new();
            loop {
                property_keys.push(parser.parse_identifier("for index property key")?);
                if !parser.match_punctuation(CypherPunctuation::Comma) {
                    break;
                }
            }
            parser.expect_punctuation(CypherPunctuation::RightParen)?;
            Ok(CreateIndexClause {
                label,
                property_keys,
            })
        };

        if self.match_keyword(CypherKeyword::On) {
            return parse_legacy_on(self);
        }

        if self.match_identifier_text("FOR") {
            self.expect_punctuation(CypherPunctuation::LeftParen)?;
            let pattern_variable = self.parse_identifier("for index pattern variable")?;
            self.expect_punctuation(CypherPunctuation::Colon)?;
            let label = self.parse_identifier("for index label")?;
            self.expect_punctuation(CypherPunctuation::RightParen)?;
            self.expect_keyword(CypherKeyword::On)?;
            self.expect_punctuation(CypherPunctuation::LeftParen)?;
            let mut property_keys = Vec::<String>::new();
            loop {
                let property_variable = self.parse_identifier("for index property variable")?;
                if !property_variable.eq_ignore_ascii_case(&pattern_variable) {
                    return Err(self.error_here(
                        "CREATE INDEX FOR variable must match variable used in ON expression",
                    ));
                }
                self.expect_punctuation(CypherPunctuation::Dot)?;
                property_keys.push(self.parse_identifier("for index property key")?);
                if !self.match_punctuation(CypherPunctuation::Comma) {
                    break;
                }
            }
            self.expect_punctuation(CypherPunctuation::RightParen)?;
            return Ok(CreateIndexClause {
                label,
                property_keys,
            });
        }

        Err(self.error_here("expected ON or FOR in CREATE INDEX clause"))
    }

    fn parse_delete_clause(&mut self) -> Result<DeleteClause, ParseError> {
        let detach = self.match_keyword(CypherKeyword::Detach);
        self.expect_keyword(CypherKeyword::Delete)?;
        let expressions = self.parse_expression_list()?;
        Ok(DeleteClause {
            detach,
            expressions,
        })
    }

    fn parse_set_clause(&mut self) -> Result<SetClause, ParseError> {
        self.expect_keyword(CypherKeyword::Set)?;
        let assignments = self.parse_set_assignments()?;
        Ok(SetClause { assignments })
    }

    fn parse_remove_clause(&mut self) -> Result<RemoveClause, ParseError> {
        self.expect_keyword(CypherKeyword::Remove)?;
        let mut targets = Vec::<CypherExpression>::new();
        loop {
            let target = self.parse_set_target()?;
            if !matches!(target, CypherExpression::PropertyAccess { .. }) {
                return Err(self.error_here("REMOVE supports property targets only"));
            }
            targets.push(target);
            if !self.match_punctuation(CypherPunctuation::Comma) {
                break;
            }
        }
        Ok(RemoveClause { targets })
    }

    fn parse_with_clause(&mut self) -> Result<WithClause, ParseError> {
        self.expect_keyword(CypherKeyword::With)?;
        let distinct = self.match_keyword(CypherKeyword::Distinct);
        let items = self.parse_projection_items()?;
        let where_predicate = if self.match_keyword(CypherKeyword::Where) {
            Some(self.parse_expression()?)
        } else {
            None
        };
        Ok(WithClause {
            distinct,
            items,
            where_predicate,
        })
    }

    fn parse_unwind_clause(&mut self) -> Result<UnwindClause, ParseError> {
        self.expect_keyword(CypherKeyword::Unwind)?;
        let expression = self.parse_expression()?;
        self.expect_keyword(CypherKeyword::As)?;
        let variable = self.parse_identifier("for UNWIND alias")?;
        Ok(UnwindClause {
            expression,
            variable,
        })
    }

    fn parse_merge_clause(&mut self) -> Result<MergeClause, ParseError> {
        self.expect_keyword(CypherKeyword::Merge)?;
        let pattern = self.parse_pattern()?;
        let mut on_create_set = Vec::<SetAssignment>::new();
        let mut on_match_set = Vec::<SetAssignment>::new();

        loop {
            if !self.match_keyword(CypherKeyword::On) {
                break;
            }
            if self.match_keyword(CypherKeyword::Create) {
                self.expect_keyword(CypherKeyword::Set)?;
                on_create_set.extend(self.parse_set_assignments()?);
            } else if self.match_keyword(CypherKeyword::Match) {
                self.expect_keyword(CypherKeyword::Set)?;
                on_match_set.extend(self.parse_set_assignments()?);
            } else {
                return Err(self.error_here("expected CREATE or MATCH after ON"));
            }
        }

        Ok(MergeClause {
            pattern,
            on_create_set,
            on_match_set,
        })
    }

    fn parse_return_clause(&mut self) -> Result<ReturnClause, ParseError> {
        self.expect_keyword(CypherKeyword::Return)?;
        let distinct = self.match_keyword(CypherKeyword::Distinct);
        let items = self.parse_projection_items()?;
        let order_by = self.parse_order_by_items()?;
        let skip = if self.match_keyword(CypherKeyword::Skip) {
            Some(self.parse_non_negative_integer("for SKIP")?)
        } else {
            None
        };
        let limit = if self.match_keyword(CypherKeyword::Limit) {
            Some(self.parse_non_negative_integer("for LIMIT")?)
        } else {
            None
        };
        Ok(ReturnClause {
            distinct,
            items,
            order_by,
            skip,
            limit,
        })
    }

    fn parse_projection_items(&mut self) -> Result<Vec<ProjectionItem>, ParseError> {
        let mut items = Vec::<ProjectionItem>::new();
        loop {
            let expression = self.parse_expression()?;
            let alias = if self.match_keyword(CypherKeyword::As) {
                Some(self.parse_identifier("after AS")?)
            } else {
                None
            };
            items.push(ProjectionItem { expression, alias });
            if !self.match_punctuation(CypherPunctuation::Comma) {
                break;
            }
        }
        Ok(items)
    }

    fn parse_order_by_items(&mut self) -> Result<Vec<OrderByItem>, ParseError> {
        if !self.match_keyword(CypherKeyword::Order) {
            return Ok(Vec::new());
        }
        self.expect_keyword(CypherKeyword::By)?;
        let mut items = Vec::<OrderByItem>::new();
        loop {
            let expression = self.parse_expression()?;
            let descending = if self.match_keyword(CypherKeyword::Desc) {
                true
            } else {
                let _ = self.match_keyword(CypherKeyword::Asc);
                false
            };
            items.push(OrderByItem {
                expression,
                descending,
            });
            if !self.match_punctuation(CypherPunctuation::Comma) {
                break;
            }
        }
        Ok(items)
    }

    fn parse_pattern_list(&mut self) -> Result<Vec<Pattern>, ParseError> {
        let mut patterns = Vec::<Pattern>::new();
        loop {
            patterns.push(self.parse_pattern()?);
            if !self.match_punctuation(CypherPunctuation::Comma) {
                break;
            }
        }
        Ok(patterns)
    }

    fn parse_pattern(&mut self) -> Result<Pattern, ParseError> {
        let start = self.parse_node_pattern()?;
        let mut chains = Vec::<PatternChain>::new();
        while self.check_operator(CypherOperator::Minus)
            || self.check_operator(CypherOperator::LessThan)
        {
            let relationship = self.parse_relationship_pattern()?;
            let node = self.parse_node_pattern()?;
            chains.push(PatternChain { relationship, node });
        }
        Ok(Pattern { start, chains })
    }

    fn parse_node_pattern(&mut self) -> Result<NodePattern, ParseError> {
        self.expect_punctuation(CypherPunctuation::LeftParen)?;
        let variable = if self.check_identifier() {
            Some(self.parse_identifier("for node pattern variable")?)
        } else {
            None
        };
        let mut labels = Vec::<String>::new();
        while self.match_punctuation(CypherPunctuation::Colon) {
            labels.push(self.parse_identifier("for node label")?);
        }
        let properties = if self.check_punctuation(CypherPunctuation::LeftBrace) {
            Some(self.parse_map_literal_entries()?)
        } else {
            None
        };
        self.expect_punctuation(CypherPunctuation::RightParen)?;
        Ok(NodePattern {
            variable,
            labels,
            properties,
        })
    }

    fn parse_relationship_pattern(&mut self) -> Result<RelationshipPattern, ParseError> {
        let incoming = if self.match_operator(CypherOperator::LessThan) {
            self.expect_operator(CypherOperator::Minus)?;
            true
        } else {
            self.expect_operator(CypherOperator::Minus)?;
            false
        };

        let (variable, rel_type, properties, length) =
            match self.match_punctuation(CypherPunctuation::LeftBracket) {
                true => self.parse_bracketed_relationship_pattern_parts()?,
                false => (None, None, None, None),
            };

        self.expect_operator(CypherOperator::Minus)?;
        let direction = if incoming {
            if self.match_operator(CypherOperator::GreaterThan) {
                return Err(self.error_here("unexpected '>' in incoming relationship pattern"));
            }
            RelationshipDirection::RightToLeft
        } else if self.match_operator(CypherOperator::GreaterThan) {
            RelationshipDirection::LeftToRight
        } else {
            RelationshipDirection::Undirected
        };

        Ok(RelationshipPattern {
            variable,
            rel_type,
            direction,
            properties,
            length,
        })
    }

    fn parse_bracketed_relationship_pattern_parts(
        &mut self,
    ) -> Result<RelationshipPatternParts, ParseError> {
        let mut variable = None;
        let mut rel_type = None;
        let mut properties = None;
        let mut length = None;

        if self.check_identifier() {
            variable = Some(self.parse_identifier("for relationship variable")?);
        }
        if self.match_punctuation(CypherPunctuation::Colon) {
            rel_type = Some(self.parse_identifier("for relationship type")?);
        }
        if self.match_operator(CypherOperator::Multiply) {
            length = Some(self.parse_pattern_length()?);
        }
        if self.check_punctuation(CypherPunctuation::LeftBrace) {
            properties = Some(self.parse_map_literal_entries()?);
        }
        self.expect_punctuation(CypherPunctuation::RightBracket)?;

        Ok((variable, rel_type, properties, length))
    }

    fn parse_pattern_length(&mut self) -> Result<PatternLength, ParseError> {
        let min_hops = if self.check_integer_literal() {
            Some(self.parse_u32_literal("for relationship length lower bound")?)
        } else {
            None
        };
        let max_hops = if self.match_punctuation(CypherPunctuation::Range) {
            if self.check_integer_literal() {
                Some(self.parse_u32_literal("for relationship length upper bound")?)
            } else {
                None
            }
        } else {
            min_hops
        };
        Ok(PatternLength { min_hops, max_hops })
    }

    fn parse_map_literal_entries(&mut self) -> Result<Vec<(String, CypherExpression)>, ParseError> {
        self.expect_punctuation(CypherPunctuation::LeftBrace)?;
        let mut entries = Vec::<(String, CypherExpression)>::new();
        if self.match_punctuation(CypherPunctuation::RightBrace) {
            return Ok(entries);
        }
        loop {
            let key = self.parse_identifier("for map key")?;
            self.expect_punctuation(CypherPunctuation::Colon)?;
            let value = self.parse_expression()?;
            entries.push((key, value));
            if self.match_punctuation(CypherPunctuation::Comma) {
                continue;
            }
            self.expect_punctuation(CypherPunctuation::RightBrace)?;
            break;
        }
        Ok(entries)
    }

    fn parse_set_assignments(&mut self) -> Result<Vec<SetAssignment>, ParseError> {
        let mut assignments = Vec::<SetAssignment>::new();
        loop {
            let target = self.parse_set_target()?;
            self.expect_operator(CypherOperator::Eq)?;
            let value = self.parse_expression()?;
            assignments.push(SetAssignment { target, value });
            if !self.match_punctuation(CypherPunctuation::Comma) {
                break;
            }
        }
        Ok(assignments)
    }

    fn parse_set_target(&mut self) -> Result<CypherExpression, ParseError> {
        if !self.check_identifier() {
            return Err(self.error_here("expected property or variable on left side of SET"));
        }
        let mut target = CypherExpression::Identifier(self.parse_identifier("for SET target")?);
        while self.match_punctuation(CypherPunctuation::Dot) {
            let property = self.parse_identifier("for SET property")?;
            target = CypherExpression::PropertyAccess {
                target: Box::new(target),
                property,
            };
        }
        Ok(target)
    }

    fn parse_expression_list(&mut self) -> Result<Vec<CypherExpression>, ParseError> {
        let mut expressions = Vec::<CypherExpression>::new();
        loop {
            expressions.push(self.parse_expression()?);
            if !self.match_punctuation(CypherPunctuation::Comma) {
                break;
            }
        }
        Ok(expressions)
    }

    fn parse_expression(&mut self) -> Result<CypherExpression, ParseError> {
        self.parse_xor_expression()
    }

    fn parse_xor_expression(&mut self) -> Result<CypherExpression, ParseError> {
        let mut expr = self.parse_or_expression()?;
        while self.match_keyword(CypherKeyword::Xor) {
            let right = self.parse_or_expression()?;
            expr = CypherExpression::BinaryOp {
                left: Box::new(expr),
                op: CypherBinaryOperator::Xor,
                right: Box::new(right),
            };
        }
        Ok(expr)
    }

    fn parse_or_expression(&mut self) -> Result<CypherExpression, ParseError> {
        let mut expr = self.parse_and_expression()?;
        while self.match_keyword(CypherKeyword::Or) {
            let right = self.parse_and_expression()?;
            expr = CypherExpression::BinaryOp {
                left: Box::new(expr),
                op: CypherBinaryOperator::Or,
                right: Box::new(right),
            };
        }
        Ok(expr)
    }

    fn parse_and_expression(&mut self) -> Result<CypherExpression, ParseError> {
        let mut expr = self.parse_comparison_expression()?;
        while self.match_keyword(CypherKeyword::And) {
            let right = self.parse_comparison_expression()?;
            expr = CypherExpression::BinaryOp {
                left: Box::new(expr),
                op: CypherBinaryOperator::And,
                right: Box::new(right),
            };
        }
        Ok(expr)
    }

    fn parse_comparison_expression(&mut self) -> Result<CypherExpression, ParseError> {
        let mut expr = self.parse_additive_expression()?;
        loop {
            let operator = if self.match_operator(CypherOperator::Eq) {
                Some(CypherBinaryOperator::Eq)
            } else if self.match_operator(CypherOperator::NotEq) {
                Some(CypherBinaryOperator::NotEq)
            } else if self.match_operator(CypherOperator::LessThan) {
                Some(CypherBinaryOperator::LessThan)
            } else if self.match_operator(CypherOperator::GreaterThan) {
                Some(CypherBinaryOperator::GreaterThan)
            } else if self.match_operator(CypherOperator::LessThanOrEqual) {
                Some(CypherBinaryOperator::LessThanOrEqual)
            } else if self.match_operator(CypherOperator::GreaterThanOrEqual) {
                Some(CypherBinaryOperator::GreaterThanOrEqual)
            } else if self.match_operator(CypherOperator::RegexMatch) {
                Some(CypherBinaryOperator::RegexMatch)
            } else if self.match_operator(CypherOperator::VectorDistance) {
                Some(CypherBinaryOperator::VectorDistance)
            } else if self.match_keyword(CypherKeyword::Contains) {
                let _ = self.match_keyword(CypherKeyword::Text);
                Some(CypherBinaryOperator::ContainsText)
            } else if self.match_keyword(CypherKeyword::In) {
                Some(CypherBinaryOperator::In)
            } else if self.match_keyword(CypherKeyword::Is) {
                if self.match_keyword(CypherKeyword::Not) {
                    Some(CypherBinaryOperator::IsNot)
                } else {
                    Some(CypherBinaryOperator::Is)
                }
            } else {
                None
            };

            let Some(op) = operator else {
                break;
            };
            let right = self.parse_additive_expression()?;
            expr = CypherExpression::BinaryOp {
                left: Box::new(expr),
                op,
                right: Box::new(right),
            };
        }
        Ok(expr)
    }

    fn parse_additive_expression(&mut self) -> Result<CypherExpression, ParseError> {
        let mut expr = self.parse_multiplicative_expression()?;
        loop {
            let op = if self.match_operator(CypherOperator::Plus) {
                Some(CypherBinaryOperator::Add)
            } else if self.match_operator(CypherOperator::Minus) {
                Some(CypherBinaryOperator::Subtract)
            } else {
                None
            };
            let Some(op) = op else {
                break;
            };
            let right = self.parse_multiplicative_expression()?;
            expr = CypherExpression::BinaryOp {
                left: Box::new(expr),
                op,
                right: Box::new(right),
            };
        }
        Ok(expr)
    }

    fn parse_multiplicative_expression(&mut self) -> Result<CypherExpression, ParseError> {
        let mut expr = self.parse_unary_expression()?;
        loop {
            let op = if self.match_operator(CypherOperator::Multiply) {
                Some(CypherBinaryOperator::Multiply)
            } else if self.match_operator(CypherOperator::Divide) {
                Some(CypherBinaryOperator::Divide)
            } else {
                None
            };
            let Some(op) = op else {
                break;
            };
            let right = self.parse_unary_expression()?;
            expr = CypherExpression::BinaryOp {
                left: Box::new(expr),
                op,
                right: Box::new(right),
            };
        }
        Ok(expr)
    }

    fn parse_unary_expression(&mut self) -> Result<CypherExpression, ParseError> {
        if self.match_keyword(CypherKeyword::Not) {
            let expr = self.parse_unary_expression()?;
            return Ok(CypherExpression::UnaryOp {
                op: CypherUnaryOperator::Not,
                expr: Box::new(expr),
            });
        }
        if self.match_operator(CypherOperator::Minus) {
            let expr = self.parse_unary_expression()?;
            return Ok(CypherExpression::UnaryOp {
                op: CypherUnaryOperator::Negate,
                expr: Box::new(expr),
            });
        }
        if self.match_operator(CypherOperator::Plus) {
            let expr = self.parse_unary_expression()?;
            return Ok(CypherExpression::UnaryOp {
                op: CypherUnaryOperator::Positive,
                expr: Box::new(expr),
            });
        }
        self.parse_postfix_expression()
    }

    fn parse_postfix_expression(&mut self) -> Result<CypherExpression, ParseError> {
        let mut expr = self.parse_primary_expression()?;
        loop {
            if self.match_punctuation(CypherPunctuation::Dot) {
                let property = self.parse_identifier("for property access")?;
                expr = CypherExpression::PropertyAccess {
                    target: Box::new(expr),
                    property,
                };
                continue;
            }
            if self.match_punctuation(CypherPunctuation::LeftBracket) {
                if self.match_punctuation(CypherPunctuation::RightBracket) {
                    return Err(self.error_here("expected index expression in subscript"));
                }
                let index = self.parse_expression()?;
                let end = if self.match_punctuation(CypherPunctuation::Range) {
                    Some(Box::new(self.parse_expression()?))
                } else {
                    None
                };
                self.expect_punctuation(CypherPunctuation::RightBracket)?;
                expr = CypherExpression::Subscript {
                    base: Box::new(expr),
                    index: Box::new(index),
                    end,
                };
                continue;
            }
            if self.check_punctuation(CypherPunctuation::LeftBrace) {
                let checkpoint = self.index;
                self.index += 1;
                let mut keys = Vec::<String>::new();
                let mut is_projection = true;

                if !self.match_punctuation(CypherPunctuation::RightBrace) {
                    loop {
                        let key = match self.peek_kind() {
                            Some(TokenKind::Identifier(key)) => {
                                let key = key.clone();
                                self.index += 1;
                                key
                            }
                            _ => {
                                is_projection = false;
                                break;
                            }
                        };

                        if self.check_punctuation(CypherPunctuation::Colon) {
                            is_projection = false;
                            break;
                        }

                        keys.push(key);

                        if self.match_punctuation(CypherPunctuation::Comma) {
                            continue;
                        }
                        if self.match_punctuation(CypherPunctuation::RightBrace) {
                            break;
                        }

                        is_projection = false;
                        break;
                    }
                }

                if is_projection {
                    expr = CypherExpression::MapProjection {
                        base: Box::new(expr),
                        keys,
                    };
                    continue;
                }

                self.index = checkpoint;
                break;
            }
            break;
        }
        Ok(expr)
    }

    fn parse_primary_expression(&mut self) -> Result<CypherExpression, ParseError> {
        if self.match_keyword(CypherKeyword::Null) {
            return Ok(CypherExpression::Literal(CypherLiteral::Null));
        }
        if self.match_keyword(CypherKeyword::True) {
            return Ok(CypherExpression::Literal(CypherLiteral::Boolean(true)));
        }
        if self.match_keyword(CypherKeyword::False) {
            return Ok(CypherExpression::Literal(CypherLiteral::Boolean(false)));
        }

        if let Some(value) = self.match_integer_literal() {
            return Ok(CypherExpression::Literal(CypherLiteral::Integer(value)));
        }
        if let Some(value) = self.match_float_literal() {
            return Ok(CypherExpression::Literal(CypherLiteral::Float(value)));
        }
        if let Some(value) = self.match_string_literal() {
            return Ok(CypherExpression::Literal(CypherLiteral::String(value)));
        }
        if let Some(value) = self.match_parameter() {
            return Ok(CypherExpression::Parameter(value));
        }

        if self.match_keyword(CypherKeyword::Case) {
            return self.parse_case_expression();
        }

        if self.check_keyword(CypherKeyword::Exists) {
            return self.parse_exists_subquery_expression();
        }

        if self.match_punctuation(CypherPunctuation::LeftParen) {
            let expr = self.parse_expression()?;
            self.expect_punctuation(CypherPunctuation::RightParen)?;
            return Ok(expr);
        }

        if self.match_punctuation(CypherPunctuation::LeftBracket) {
            return self.parse_list_expression();
        }

        if self.check_punctuation(CypherPunctuation::LeftBrace) {
            let entries = self.parse_map_literal_entries()?;
            return Ok(CypherExpression::MapLiteral(entries));
        }

        if self.check_identifier() {
            let name = self.parse_identifier("for expression")?;
            if self.match_punctuation(CypherPunctuation::LeftParen) {
                return self.parse_function_call_expression(name);
            }
            return Ok(CypherExpression::Identifier(name));
        }

        Err(self.error_here("expected expression"))
    }

    fn parse_function_call_expression(
        &mut self,
        name: String,
    ) -> Result<CypherExpression, ParseError> {
        let distinct = self.match_keyword(CypherKeyword::Distinct);
        let mut arguments = Vec::<CypherExpression>::new();
        if self.match_punctuation(CypherPunctuation::RightParen) {
            return Ok(CypherExpression::FunctionCall {
                name,
                distinct,
                arguments,
            });
        }
        loop {
            arguments.push(self.parse_expression()?);
            if self.match_punctuation(CypherPunctuation::Comma) {
                continue;
            }
            self.expect_punctuation(CypherPunctuation::RightParen)?;
            break;
        }
        Ok(CypherExpression::FunctionCall {
            name,
            distinct,
            arguments,
        })
    }

    fn parse_case_expression(&mut self) -> Result<CypherExpression, ParseError> {
        let base = if self.check_keyword(CypherKeyword::When) {
            None
        } else {
            Some(Box::new(self.parse_expression()?))
        };
        let mut when_then = Vec::<(CypherExpression, CypherExpression)>::new();
        while self.match_keyword(CypherKeyword::When) {
            let when_expr = self.parse_expression()?;
            self.expect_keyword(CypherKeyword::Then)?;
            let then_expr = self.parse_expression()?;
            when_then.push((when_expr, then_expr));
        }
        if when_then.is_empty() {
            return Err(self.error_here("CASE expression requires at least one WHEN ... THEN arm"));
        }
        let else_expr = if self.match_keyword(CypherKeyword::Else) {
            Some(Box::new(self.parse_expression()?))
        } else {
            None
        };
        self.expect_keyword(CypherKeyword::End)?;
        Ok(CypherExpression::CaseExpression {
            base,
            when_then,
            else_expr,
        })
    }

    fn parse_exists_subquery_expression(&mut self) -> Result<CypherExpression, ParseError> {
        self.expect_keyword(CypherKeyword::Exists)?;
        self.expect_punctuation(CypherPunctuation::LeftBrace)?;
        let start_idx = self.index;
        let mut depth = 1usize;
        while let Some(token) = self.peek_token() {
            match token.kind {
                TokenKind::Punctuation(CypherPunctuation::LeftBrace) => {
                    depth += 1;
                }
                TokenKind::Punctuation(CypherPunctuation::RightBrace) => {
                    depth -= 1;
                    if depth == 0 {
                        break;
                    }
                }
                _ => {}
            }
            self.index += 1;
        }
        if depth != 0 {
            return Err(self.error_here("expected '}' to close EXISTS subquery"));
        }
        let end_idx = self.index;
        let sub_tokens = self.tokens[start_idx..end_idx].to_vec();
        self.index += 1;
        let mut nested = CypherParser::from_tokens(self.input, sub_tokens);
        let query = nested.parse_query()?;
        Ok(CypherExpression::ExistsSubquery {
            query: Box::new(query),
        })
    }

    fn parse_list_expression(&mut self) -> Result<CypherExpression, ParseError> {
        if self.match_punctuation(CypherPunctuation::RightBracket) {
            return Ok(CypherExpression::ListLiteral(Vec::new()));
        }

        let checkpoint = self.index;
        if self.check_punctuation(CypherPunctuation::LeftParen) {
            if let Ok(pattern) = self.parse_pattern() {
                let predicate = if self.match_keyword(CypherKeyword::Where) {
                    Some(Box::new(self.parse_expression()?))
                } else {
                    None
                };
                if self.match_punctuation(CypherPunctuation::Pipe) {
                    let projection = Box::new(self.parse_expression()?);
                    self.expect_punctuation(CypherPunctuation::RightBracket)?;
                    return Ok(CypherExpression::PatternComprehension {
                        pattern,
                        predicate,
                        projection,
                    });
                }
            }
            self.index = checkpoint;
        }

        let is_comprehension = matches!(self.peek_kind(), Some(TokenKind::Identifier(_)))
            && matches!(
                self.peek_n_kind(1),
                Some(TokenKind::Keyword(CypherKeyword::In))
            );

        if is_comprehension {
            let variable = self.parse_identifier("for list comprehension variable")?;
            self.expect_keyword(CypherKeyword::In)?;
            let list = self.parse_expression()?;
            let predicate = if self.match_keyword(CypherKeyword::Where) {
                Some(Box::new(self.parse_expression()?))
            } else {
                None
            };
            let projection = if self.match_punctuation(CypherPunctuation::Pipe) {
                Some(Box::new(self.parse_expression()?))
            } else {
                None
            };
            self.expect_punctuation(CypherPunctuation::RightBracket)?;
            return Ok(CypherExpression::ListComprehension {
                variable,
                list: Box::new(list),
                predicate,
                projection,
            });
        }

        let mut values = Vec::<CypherExpression>::new();
        loop {
            values.push(self.parse_expression()?);
            if self.match_punctuation(CypherPunctuation::Comma) {
                continue;
            }
            self.expect_punctuation(CypherPunctuation::RightBracket)?;
            break;
        }
        Ok(CypherExpression::ListLiteral(values))
    }

    fn parse_non_negative_integer(&mut self, context: &str) -> Result<u64, ParseError> {
        let value = self.parse_i64_literal(context)?;
        u64::try_from(value)
            .map_err(|_| self.error_here(format!("expected non-negative integer {context}")))
    }

    fn parse_u32_literal(&mut self, context: &str) -> Result<u32, ParseError> {
        let value = self.parse_i64_literal(context)?;
        u32::try_from(value)
            .map_err(|_| self.error_here(format!("integer literal out of range {context}")))
    }

    fn parse_i64_literal(&mut self, context: &str) -> Result<i64, ParseError> {
        match self.peek_kind() {
            Some(TokenKind::IntegerLiteral(value)) => {
                let value = *value;
                self.index += 1;
                Ok(value)
            }
            _ => Err(self.error_here(format!("expected integer literal {context}"))),
        }
    }

    fn parse_identifier(&mut self, context: &str) -> Result<String, ParseError> {
        match self.peek_kind() {
            Some(TokenKind::Identifier(value)) => {
                let value = value.clone();
                self.index += 1;
                Ok(value)
            }
            _ => Err(self.error_here(format!("expected identifier {context}"))),
        }
    }

    fn expect_keyword(&mut self, keyword: CypherKeyword) -> Result<(), ParseError> {
        if self.match_keyword(keyword) {
            return Ok(());
        }
        Err(self.error_here(format!("expected keyword {:?}", keyword)))
    }

    fn expect_operator(&mut self, operator: CypherOperator) -> Result<(), ParseError> {
        if self.match_operator(operator) {
            return Ok(());
        }
        Err(self.error_here(format!("expected operator {:?}", operator)))
    }

    fn expect_punctuation(&mut self, punctuation: CypherPunctuation) -> Result<(), ParseError> {
        if self.match_punctuation(punctuation) {
            return Ok(());
        }
        Err(self.error_here(format!("expected punctuation {:?}", punctuation)))
    }

    fn check_identifier(&self) -> bool {
        matches!(self.peek_kind(), Some(TokenKind::Identifier(_)))
    }

    fn check_identifier_text(&self, expected: &str) -> bool {
        matches!(
            self.peek_kind(),
            Some(TokenKind::Identifier(value)) if value.eq_ignore_ascii_case(expected)
        )
    }

    fn check_integer_literal(&self) -> bool {
        matches!(self.peek_kind(), Some(TokenKind::IntegerLiteral(_)))
    }

    fn check_keyword(&self, keyword: CypherKeyword) -> bool {
        matches!(
            self.peek_kind(),
            Some(TokenKind::Keyword(current)) if *current == keyword
        )
    }

    fn check_operator(&self, operator: CypherOperator) -> bool {
        matches!(
            self.peek_kind(),
            Some(TokenKind::Operator(current)) if *current == operator
        )
    }

    fn check_punctuation(&self, punctuation: CypherPunctuation) -> bool {
        matches!(
            self.peek_kind(),
            Some(TokenKind::Punctuation(current)) if *current == punctuation
        )
    }

    fn match_keyword(&mut self, keyword: CypherKeyword) -> bool {
        if self.check_keyword(keyword) {
            self.index += 1;
            return true;
        }
        false
    }

    fn match_identifier_text(&mut self, expected: &str) -> bool {
        if self.check_identifier_text(expected) {
            self.index += 1;
            return true;
        }
        false
    }

    fn match_operator(&mut self, operator: CypherOperator) -> bool {
        if self.check_operator(operator) {
            self.index += 1;
            return true;
        }
        false
    }

    fn match_punctuation(&mut self, punctuation: CypherPunctuation) -> bool {
        if self.check_punctuation(punctuation) {
            self.index += 1;
            return true;
        }
        false
    }

    fn match_integer_literal(&mut self) -> Option<i64> {
        if let Some(TokenKind::IntegerLiteral(value)) = self.peek_kind() {
            let value = *value;
            self.index += 1;
            return Some(value);
        }
        None
    }

    fn match_float_literal(&mut self) -> Option<f64> {
        if let Some(TokenKind::FloatLiteral(value)) = self.peek_kind() {
            let value = *value;
            self.index += 1;
            return Some(value);
        }
        None
    }

    fn match_string_literal(&mut self) -> Option<String> {
        if let Some(TokenKind::StringLiteral(value)) = self.peek_kind() {
            let value = value.clone();
            self.index += 1;
            return Some(value);
        }
        None
    }

    fn match_parameter(&mut self) -> Option<String> {
        if let Some(TokenKind::Parameter(value)) = self.peek_kind() {
            let value = value.clone();
            self.index += 1;
            return Some(value);
        }
        None
    }

    fn peek_kind(&self) -> Option<&TokenKind> {
        self.tokens.get(self.index).map(|token| &token.kind)
    }

    fn peek_n_kind(&self, n: usize) -> Option<&TokenKind> {
        self.tokens.get(self.index + n).map(|token| &token.kind)
    }

    fn peek_token(&self) -> Option<&Token> {
        self.tokens.get(self.index)
    }

    fn is_eof(&self) -> bool {
        self.index >= self.tokens.len()
    }

    fn error_here(&self, message: impl Into<String>) -> ParseError {
        if let Some(token) = self.tokens.get(self.index) {
            return ParseError::from_span(token.span, message);
        }
        ParseError::new(self.input, self.input.len(), message)
    }
}

