#[cfg(feature = "vector-search")]
#[derive(Clone)]
struct BuiltHnsw {
    map: std::sync::Arc<HnswMap<HnswVectorPoint, u64>>,
}

/// Returns `true` if an HNSW map was actually built (i.e. entries ≥
/// `HNSW_MIN_N`). Returns `false` when the index falls through to the
/// brute-force path because the corpus is too small. Callers use the
/// return value to bump `Database::vector_index_rebuilds_total` only on
/// real builds, so the EVAL-PERF-RELEASE Finding 2 counter is meaningful.
#[cfg(feature = "vector-search")]
fn build_hnsw_from_entries(runtime: &mut VectorIndexRuntime) -> bool {
    if runtime.entries.len() < HNSW_MIN_N {
        runtime.hnsw = None;
        return false;
    }
    let metric = runtime.definition.metric;
    let (points, values): (Vec<_>, Vec<_>) = runtime
        .entries
        .iter()
        .map(|(node_id, vector)| {
            (
                HnswVectorPoint {
                    values: vector.clone(),
                    metric,
                },
                *node_id,
            )
        })
        .unzip();
    let map = HnswBuilder::default()
        .ef_construction(HNSW_EF_CONSTRUCTION)
        .ef_search(HNSW_EF_SEARCH)
        .seed(HNSW_BUILDER_SEED)
        .build(points, values);
    runtime.hnsw = Some(BuiltHnsw {
        map: std::sync::Arc::new(map),
    });
    true
}

#[derive(Debug)]
struct LoadedMetaStore {
    meta: MetaStore,
    legacy_node_properties: Vec<PropertyMap>,
    node_temporal_versions: Vec<Vec<TemporalNodeVersion>>,
}

impl MetaStore {
    fn to_persisted(
        &self,
        node_temporal_versions: &[Vec<TemporalNodeVersion>],
    ) -> PersistedMetaStore {
        PersistedMetaStore {
            format_version: META_FORMAT_VERSION,
            node_labels: self
                .node_labels
                .iter()
                .map(|labels| labels.iter().cloned().collect())
                .collect(),
            node_properties: Vec::new(),
            node_temporal_versions: node_temporal_versions.to_vec(),
            edge_types: self.edge_types.clone(),
            edge_properties: self.edge_properties.clone(),
            edge_valid_from: self.edge_valid_from.clone(),
            edge_valid_to: self.edge_valid_to.clone(),
            edge_transaction_time_millis: self.edge_transaction_time_millis.clone(),
            labels_registry: self.labels_registry.iter().cloned().collect(),
            edge_type_registry: self.edge_type_registry.iter().cloned().collect(),
            property_key_registry: self.property_key_registry.iter().cloned().collect(),
            index_catalog: self.index_catalog.iter().cloned().collect(),
            vector_index_catalog: self.vector_index_catalog.iter().cloned().collect(),
            fulltext_index_catalog: self.fulltext_index_catalog.iter().cloned().collect(),
            users: self
                .users
                .iter()
                .map(|(user, entry)| {
                    (
                        user.clone(),
                        PersistedUserCatalogEntry {
                            token: entry.token.clone(),
                            roles: entry.roles.iter().copied().collect(),
                        },
                    )
                })
                .collect(),
            audit_log: self.audit_log.clone(),
        }
    }

    fn from_persisted(value: PersistedMetaStore) -> Result<LoadedMetaStore, DbError> {
        if value.format_version != META_FORMAT_VERSION {
            return Err(DbError::Corrupt(format!(
                "invalid meta format version: {}",
                value.format_version
            )));
        }
        Ok(LoadedMetaStore {
            meta: Self {
                node_labels: value
                    .node_labels
                    .into_iter()
                    .map(|labels| labels.into_iter().collect())
                    .collect(),
                edge_types: value.edge_types,
                edge_properties: value.edge_properties,
                edge_valid_from: value.edge_valid_from,
                edge_valid_to: value.edge_valid_to,
                edge_transaction_time_millis: value.edge_transaction_time_millis,
                labels_registry: value.labels_registry.into_iter().collect(),
                edge_type_registry: value.edge_type_registry.into_iter().collect(),
                property_key_registry: value.property_key_registry.into_iter().collect(),
                index_catalog: value.index_catalog.into_iter().collect(),
                vector_index_catalog: value.vector_index_catalog.into_iter().collect(),
                fulltext_index_catalog: value.fulltext_index_catalog.into_iter().collect(),
                label_membership: HashMap::new(),
                users: value
                    .users
                    .into_iter()
                    .map(|(user, entry)| {
                        (
                            user,
                            UserCatalogEntry {
                                token: entry.token,
                                roles: entry.roles.into_iter().collect(),
                            },
                        )
                    })
                    .collect(),
                audit_log: value.audit_log,
            },
            legacy_node_properties: value.node_properties,
            node_temporal_versions: value.node_temporal_versions,
        })
    }
}

