#[derive(Debug, Clone, Copy)]
struct NodePropertyStoreHeader {
    format_version: u32,
    page_size: u32,
}

impl NodePropertyStoreHeader {
    fn encode(self) -> [u8; NODE_PROPERTY_STORE_HEADER_SIZE] {
        let mut out = [0u8; NODE_PROPERTY_STORE_HEADER_SIZE];
        out[..8].copy_from_slice(&NODE_PROPERTY_STORE_MAGIC);
        out[8..12].copy_from_slice(&self.format_version.to_le_bytes());
        out[12..16].copy_from_slice(&self.page_size.to_le_bytes());
        out
    }

    fn decode(bytes: &[u8]) -> Result<Self, DbError> {
        if bytes.len() < NODE_PROPERTY_STORE_HEADER_SIZE {
            return Err(DbError::Corrupt(
                "node property store header shorter than expected size".to_string(),
            ));
        }
        if bytes[..8] != NODE_PROPERTY_STORE_MAGIC {
            return Err(DbError::Corrupt(
                "invalid node property store file magic".to_string(),
            ));
        }

        let mut format_bytes = [0u8; 4];
        format_bytes.copy_from_slice(&bytes[8..12]);
        let mut page_size_bytes = [0u8; 4];
        page_size_bytes.copy_from_slice(&bytes[12..16]);
        let format_version = u32::from_le_bytes(format_bytes);
        let page_size = u32::from_le_bytes(page_size_bytes);
        if format_version != NODE_PROPERTY_STORE_FORMAT_VERSION {
            return Err(DbError::Corrupt(format!(
                "invalid node property store format version: {format_version}"
            )));
        }
        if page_size < MIN_PAGE_SIZE || !page_size.is_power_of_two() {
            return Err(DbError::Corrupt(
                "invalid node property store page size".to_string(),
            ));
        }
        Ok(Self {
            format_version,
            page_size,
        })
    }
}

