#[derive(Debug, Clone, Default)]
struct FreeList {
    pages: BTreeSet<u64>,
}

impl FreeList {
    fn to_persisted(&self) -> PersistedFreeList {
        PersistedFreeList {
            format_version: FREE_LIST_FORMAT_VERSION,
            free_pages: self.pages.iter().copied().collect(),
        }
    }

    fn from_persisted(value: PersistedFreeList) -> Result<Self, DbError> {
        if value.format_version != FREE_LIST_FORMAT_VERSION {
            return Err(DbError::Corrupt(format!(
                "invalid free list format version: {}",
                value.format_version
            )));
        }
        Ok(Self {
            pages: value.free_pages.into_iter().collect(),
        })
    }

    fn allocate(&mut self) -> Option<u64> {
        let page_id = self.pages.iter().next().copied()?;
        self.pages.remove(&page_id);
        Some(page_id)
    }

    fn free(&mut self, page_id: u64) -> Result<(), DbError> {
        if !self.pages.insert(page_id) {
            return Err(DbError::InvalidArgument(format!(
                "page already free: page_id={page_id}"
            )));
        }
        Ok(())
    }

    fn compact_to_page_count(&mut self, page_count: u64) -> u64 {
        self.pages.retain(|page_id| *page_id < page_count);
        let mut new_page_count = page_count;
        while new_page_count > 0 {
            let tail_page_id = new_page_count - 1;
            if self.pages.remove(&tail_page_id) {
                new_page_count -= 1;
                continue;
            }
            break;
        }
        new_page_count
    }
}

