    pub fn node_properties_at_time(
        &self,
        node_id: u64,
        timestamp_millis: i64,
    ) -> Option<&PropertyMap> {
        let idx = node_id as usize;
        if idx >= self.node_temporal_versions.len() {
            return None;
        }
        let chain = &self.node_temporal_versions[idx];
        chain
            .iter()
            .rev()
            .find(|version| {
                version.valid_from <= timestamp_millis
                    && version
                        .valid_to
                        .map(|valid_to| timestamp_millis < valid_to)
                        .unwrap_or(true)
            })
            .map(|version| &version.properties)
    }

    pub fn node_temporal_version_count(&self, node_id: u64) -> usize {
        self.node_temporal_versions
            .get(node_id as usize)
            .map_or(0, |chain| chain.len())
    }

