    pub fn create_user(&mut self, username: &str, token: Option<&str>) -> Result<(), DbError> {
        let username = username.trim();
        if username.is_empty() {
            return Err(DbError::InvalidArgument(
                "username cannot be empty".to_string(),
            ));
        }
        if self.meta.users.contains_key(username) {
            return Err(DbError::AlreadyExists(PathBuf::from(username)));
        }
        let token = token
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string);
        self.meta.users.insert(
            username.to_string(),
            UserCatalogEntry {
                token,
                roles: BTreeSet::from([DbRole::ReadOnly]),
            },
        );
        self.sync_meta()
    }

    pub fn drop_user(&mut self, username: &str) -> Result<(), DbError> {
        let username = username.trim();
        if username.is_empty() {
            return Err(DbError::InvalidArgument(
                "username cannot be empty".to_string(),
            ));
        }
        self.meta.users.remove(username);
        self.sync_meta()
    }

    pub fn grant_role(&mut self, username: &str, role: DbRole) -> Result<(), DbError> {
        let username = username.trim();
        let user = self
            .meta
            .users
            .get_mut(username)
            .ok_or_else(|| DbError::InvalidArgument(format!("unknown user: {username}")))?;
        user.roles.insert(role);
        self.sync_meta()
    }

    pub fn revoke_role(&mut self, username: &str, role: DbRole) -> Result<(), DbError> {
        let username = username.trim();
        let user = self
            .meta
            .users
            .get_mut(username)
            .ok_or_else(|| DbError::InvalidArgument(format!("unknown user: {username}")))?;
        user.roles.remove(&role);
        self.sync_meta()
    }

    pub fn authenticate_token(&self, token: &str) -> Option<String> {
        let token = token.trim();
        if token.is_empty() {
            return None;
        }
        self.meta.users.iter().find_map(|(username, entry)| {
            if entry.token.as_deref() == Some(token) {
                Some(username.clone())
            } else {
                None
            }
        })
    }

    pub fn has_any_users(&self) -> bool {
        !self.meta.users.is_empty()
    }

    pub fn audit_log_since(&self, since_timestamp_millis: i64) -> Vec<AuditEntry> {
        self.meta
            .audit_log
            .iter()
            .filter(|entry| entry.timestamp_millis >= since_timestamp_millis)
            .cloned()
            .collect()
    }

    fn append_audit_entry(&mut self, user: &str, operation: &str) -> Result<(), DbError> {
        self.meta.audit_log.push(AuditEntry {
            timestamp_millis: current_unix_millis(),
            user: user.to_string(),
            operation: operation.to_string(),
        });
        self.sync_meta()
    }

    fn user_can_write(&self, username: &str) -> bool {
        if username == "anonymous" {
            return true;
        }
        self.meta
            .users
            .get(username)
            .map(|entry| {
                entry.roles.contains(&DbRole::Admin) || entry.roles.contains(&DbRole::ReadWrite)
            })
            .unwrap_or(false)
    }

    pub fn query_as_user(
        &mut self,
        username: &str,
        query: &str,
    ) -> Result<QueryResult, QueryError> {
        let username = username.trim();
        if username.is_empty() {
            return Err(QueryError::new("user cannot be empty"));
        }
        if username != "anonymous" && !self.meta.users.contains_key(username) {
            return Err(QueryError::new(format!("unknown user: {username}")));
        }
        let write_query = query_requires_write_access(query);
        if write_query && !self.user_can_write(username) {
            return Err(QueryError::new(format!(
                "permission denied for user '{username}': write query requires read_write or admin role"
            )));
        }
        let result = self.query(query)?;
        if write_query {
            self.append_audit_entry(username, query_operation_kind(query))
                .map_err(QueryError::from)?;
        }
        Ok(result)
    }

