    pub fn store_episode(
        &mut self,
        agent_id: &str,
        session_id: &str,
        content: &str,
        embedding: &[f32],
        timestamp: i64,
        metadata: &str,
    ) -> Result<u64, DbError> {
        let agent_id = agent_id.trim();
        if agent_id.is_empty() {
            return Err(DbError::InvalidArgument(
                "agent_id cannot be empty".to_string(),
            ));
        }
        let session_id = session_id.trim();
        if session_id.is_empty() {
            return Err(DbError::InvalidArgument(
                "session_id cannot be empty".to_string(),
            ));
        }
        let content = content.trim();
        if content.is_empty() {
            return Err(DbError::InvalidArgument(
                "content cannot be empty".to_string(),
            ));
        }
        if embedding.is_empty() || embedding.len() > VECTOR_MAX_DIMENSIONS {
            return Err(DbError::InvalidArgument(format!(
                "embedding dimensions must be between 1 and {VECTOR_MAX_DIMENSIONS}"
            )));
        }
        let metadata_value = serde_json::from_str::<serde_json::Value>(metadata).map_err(|e| {
            DbError::InvalidArgument(format!("metadata must be valid json string: {e}"))
        })?;
        let metadata_json = serde_json::to_string(&metadata_value)
            .map_err(|e| DbError::InvalidArgument(format!("metadata serialization failed: {e}")))?;

        self.ensure_episode_indexes(embedding.len())?;
        let labels = vec![EPISODE_LABEL.to_string()];
        let properties = PropertyMap::from([
            (
                EPISODE_AGENT_ID_KEY.to_string(),
                PropertyValue::String(agent_id.to_string()),
            ),
            (
                EPISODE_SESSION_ID_KEY.to_string(),
                PropertyValue::String(session_id.to_string()),
            ),
            (
                EPISODE_CONTENT_KEY.to_string(),
                PropertyValue::String(content.to_string()),
            ),
            (
                EPISODE_EMBEDDING_KEY.to_string(),
                PropertyValue::Vector(embedding.to_vec()),
            ),
            (
                EPISODE_TIMESTAMP_KEY.to_string(),
                PropertyValue::I64(timestamp),
            ),
            (
                EPISODE_METADATA_KEY.to_string(),
                PropertyValue::String(metadata_json),
            ),
        ]);
        self.create_node_with(&labels, &properties)
    }

