    pub fn forget_episodes(
        &mut self,
        agent_id: &str,
        before_timestamp: i64,
    ) -> Result<(), DbError> {
        let agent_id = agent_id.trim();
        if agent_id.is_empty() {
            return Err(DbError::InvalidArgument(
                "agent_id cannot be empty".to_string(),
            ));
        }
        let snapshot_txn_id = self.current_snapshot_txn_id();
        let mut to_forget = self
            .find_nodes_by_label_at(EPISODE_LABEL, snapshot_txn_id)
            .into_iter()
            .filter_map(|node_id| {
                self.episode_from_node_at(node_id, snapshot_txn_id)
                    .ok()
                    .flatten()
                    .filter(|episode| {
                        episode.agent_id == agent_id && episode.timestamp < before_timestamp
                    })
                    .map(|episode| episode.episode_id)
            })
            .collect::<Vec<_>>();
        if to_forget.is_empty() {
            return Ok(());
        }
        to_forget.sort_unstable();
        let mut tx = self.begin_write();
        for node_id in to_forget {
            tx.set_node_labels(node_id, Vec::new())?;
            tx.set_node_properties(node_id, PropertyMap::new())?;
        }
        let _ = tx.commit()?;
        Ok(())
    }

