    fn analyze_cypher_query(db: &Database, query: &str) -> Result<SemanticModel, AnalysisError> {
        let ast = db.parse_cypher(query).expect("query should parse");
        db.analyze_cypher(&ast)
    }

    fn plan_cypher_query(db: &Database, query: &str) -> Result<LogicalPlan, PlanError> {
        let ast = db.parse_cypher(query).expect("query should parse");
        let semantic = db.analyze_cypher(&ast).expect("query should analyze");
        db.plan_cypher(&semantic)
    }

    fn expect_match_clause(clause: &CypherClause) -> &MatchClause {
        match clause {
            CypherClause::Match(value) => value,
            other => panic!("expected MATCH clause, got {other:?}"),
        }
    }

    fn expect_create_clause(clause: &CypherClause) -> &CreateClause {
        match clause {
            CypherClause::Create(value) => value,
            other => panic!("expected CREATE clause, got {other:?}"),
        }
    }

    fn expect_delete_clause(clause: &CypherClause) -> &DeleteClause {
        match clause {
            CypherClause::Delete(value) => value,
            other => panic!("expected DELETE clause, got {other:?}"),
        }
    }

    fn expect_set_clause(clause: &CypherClause) -> &SetClause {
        match clause {
            CypherClause::Set(value) => value,
            other => panic!("expected SET clause, got {other:?}"),
        }
    }

    fn expect_remove_clause(clause: &CypherClause) -> &RemoveClause {
        match clause {
            CypherClause::Remove(value) => value,
            other => panic!("expected REMOVE clause, got {other:?}"),
        }
    }

    fn expect_with_clause(clause: &CypherClause) -> &WithClause {
        match clause {
            CypherClause::With(value) => value,
            other => panic!("expected WITH clause, got {other:?}"),
        }
    }

    fn expect_unwind_clause(clause: &CypherClause) -> &UnwindClause {
        match clause {
            CypherClause::Unwind(value) => value,
            other => panic!("expected UNWIND clause, got {other:?}"),
        }
    }

    fn expect_merge_clause(clause: &CypherClause) -> &MergeClause {
        match clause {
            CypherClause::Merge(value) => value,
            other => panic!("expected MERGE clause, got {other:?}"),
        }
    }

    fn expect_binary_expr(
        expr: &CypherExpression,
        expected: CypherBinaryOperator,
    ) -> (&CypherExpression, &CypherExpression) {
        match expr {
            CypherExpression::BinaryOp { left, op, right } if *op == expected => {
                (left.as_ref(), right.as_ref())
            }
            other => panic!("expected binary op {expected:?}, got {other:?}"),
        }
    }

    fn limit_parts(plan: LogicalPlan) -> Option<(Box<LogicalPlan>, u64)> {
        match plan {
            LogicalPlan::Limit { input, count } => Some((input, count)),
            _ => None,
        }
    }

    fn skip_parts(plan: &LogicalPlan) -> Option<(&LogicalPlan, u64)> {
        match plan {
            LogicalPlan::Skip { input, count } => Some((input.as_ref(), *count)),
            _ => None,
        }
    }

    fn sort_parts(plan: &LogicalPlan) -> Option<(&LogicalPlan, &Vec<OrderByItem>)> {
        match plan {
            LogicalPlan::Sort { input, keys } => Some((input.as_ref(), keys)),
            _ => None,
        }
    }

    fn project_parts(plan: &LogicalPlan) -> Option<(&LogicalPlan, &Vec<ProjectionItem>, bool)> {
        match plan {
            LogicalPlan::Project {
                input,
                expressions,
                distinct,
            } => Some((input.as_ref(), expressions, *distinct)),
            _ => None,
        }
    }

    fn expand_parts(
        plan: &LogicalPlan,
    ) -> Option<(&LogicalPlan, &str, Option<&str>, RelationshipDirection)> {
        match plan {
            LogicalPlan::Expand {
                input,
                from,
                edge_type,
                direction,
                ..
            } => Some((input.as_ref(), from, edge_type.as_deref(), *direction)),
            _ => None,
        }
    }

    fn filter_parts(plan: &LogicalPlan) -> Option<&LogicalPlan> {
        match plan {
            LogicalPlan::Filter { input, .. } => Some(input.as_ref()),
            _ => None,
        }
    }

    fn scan_parts(plan: &LogicalPlan) -> Option<(Option<&str>, Option<&str>)> {
        match plan {
            LogicalPlan::Scan { label, variable } => Some((label.as_deref(), variable.as_deref())),
            LogicalPlan::VectorScan {
                label, variable, ..
            }
            | LogicalPlan::TextSearch {
                label, variable, ..
            } => Some((label.as_deref(), variable.as_deref())),
            _ => None,
        }
    }

    fn aggregate_parts(
        plan: &LogicalPlan,
    ) -> Option<(&Vec<CypherExpression>, &Vec<AggregateFunction>)> {
        match plan {
            LogicalPlan::Aggregate {
                group_keys,
                aggregates,
                ..
            } => Some((group_keys, aggregates)),
            _ => None,
        }
    }

    fn physical_scan_parts(plan: &PhysicalPlan) -> Option<(PhysicalScanStrategy, Option<&str>)> {
        match plan {
            PhysicalPlan::PhysicalScan {
                scan_strategy,
                label,
                ..
            } => Some((*scan_strategy, label.as_deref())),
            PhysicalPlan::PhysicalVectorScan { label, .. }
            | PhysicalPlan::PhysicalTextSearch { label, .. } => {
                Some((PhysicalScanStrategy::IndexScan, label.as_deref()))
            }
            PhysicalPlan::PhysicalExpand { input, .. }
            | PhysicalPlan::PhysicalFactorizedExpand { input, .. }
            | PhysicalPlan::PhysicalFilter { input, .. }
            | PhysicalPlan::PhysicalProject { input, .. }
            | PhysicalPlan::PhysicalSort { input, .. }
            | PhysicalPlan::PhysicalLimit { input, .. }
            | PhysicalPlan::PhysicalAggregation { input, .. }
            | PhysicalPlan::PhysicalDelete { input, .. }
            | PhysicalPlan::PhysicalSet { input, .. }
            | PhysicalPlan::PhysicalRemove { input, .. }
            | PhysicalPlan::PhysicalWcojJoin { input, .. } => physical_scan_parts(input.as_ref()),
            PhysicalPlan::PhysicalCartesianProduct { left, right, .. } => {
                physical_scan_parts(left.as_ref()).or_else(|| physical_scan_parts(right.as_ref()))
            }
            PhysicalPlan::PhysicalCreate { input, .. } => {
                input.as_ref().and_then(|value| physical_scan_parts(value))
            }
            PhysicalPlan::PhysicalMerge { input, .. } => {
                input.as_ref().and_then(|value| physical_scan_parts(value))
            }
            PhysicalPlan::PhysicalUnwind { input, .. } => {
                input.as_ref().and_then(|value| physical_scan_parts(value))
            }
            PhysicalPlan::PhysicalCreateIndex { .. } => None,
        }
    }

    fn physical_expand_parts(plan: &PhysicalPlan) -> Option<PhysicalJoinStrategy> {
        match plan {
            PhysicalPlan::PhysicalExpand { join_strategy, .. } => Some(*join_strategy),
            PhysicalPlan::PhysicalFactorizedExpand { .. } => Some(PhysicalJoinStrategy::HashJoin),
            PhysicalPlan::PhysicalWcojJoin { .. } => Some(PhysicalJoinStrategy::WcojJoin),
            PhysicalPlan::PhysicalFilter { input, .. }
            | PhysicalPlan::PhysicalProject { input, .. }
            | PhysicalPlan::PhysicalSort { input, .. }
            | PhysicalPlan::PhysicalLimit { input, .. }
            | PhysicalPlan::PhysicalAggregation { input, .. }
            | PhysicalPlan::PhysicalDelete { input, .. }
            | PhysicalPlan::PhysicalSet { input, .. }
            | PhysicalPlan::PhysicalRemove { input, .. } => physical_expand_parts(input.as_ref()),
            PhysicalPlan::PhysicalCartesianProduct { left, right, .. } => {
                physical_expand_parts(left.as_ref())
                    .or_else(|| physical_expand_parts(right.as_ref()))
            }
            PhysicalPlan::PhysicalCreate { input, .. } => input
                .as_ref()
                .and_then(|value| physical_expand_parts(value)),
            PhysicalPlan::PhysicalMerge { input, .. } => input
                .as_ref()
                .and_then(|value| physical_expand_parts(value)),
            PhysicalPlan::PhysicalUnwind { input, .. } => input
                .as_ref()
                .and_then(|value| physical_expand_parts(value)),
            PhysicalPlan::PhysicalScan { .. }
            | PhysicalPlan::PhysicalVectorScan { .. }
            | PhysicalPlan::PhysicalTextSearch { .. }
            | PhysicalPlan::PhysicalCreateIndex { .. } => None,
        }
    }

    fn first_batch_column<'a>(result: &'a QueryResult, column: &str) -> &'a Vec<PropertyValue> {
        result
            .batches
            .first()
            .and_then(|batch| batch.columns.get(column))
            .expect("column must exist in first batch")
    }

