    fn poison_shared_write_lock(shared: &SharedDatabase) {
        let inner = shared.inner.clone();
        let _ = thread::spawn(move || {
            let _guard = inner.write().expect("acquire write lock");
            panic!("poison shared lock");
        })
        .join();
    }

    fn assert_with_write_lock_poisoned<T, F>(writer: F)
    where
        F: FnOnce(&mut Database) -> Result<T, DbError>,
        T: std::fmt::Debug,
    {
        let path = temp_db_path("shared-with-write-poison");
        let shared = SharedDatabase::init(&path, Header::default_v1()).expect("init shared");
        poison_shared_write_lock(&shared);
        let err = shared
            .with_write(writer)
            .expect_err("poisoned write lock should fail");
        assert_corrupt(&err);
        assert!(err.to_string().contains("write lock poisoned"));
        cleanup_db_artifacts(&path);
    }

    fn assert_with_write_transaction_lock_poisoned<T, F>(writer: F)
    where
        F: FnOnce(WriteTransaction<'_>) -> Result<T, DbError>,
        T: std::fmt::Debug,
    {
        let path = temp_db_path("shared-with-write-tx-poison");
        let shared = SharedDatabase::init(&path, Header::default_v1()).expect("init shared");
        poison_shared_write_lock(&shared);
        let err = shared
            .with_write_transaction(writer)
            .expect_err("poisoned write transaction lock should fail");
        assert_corrupt(&err);
        assert!(err.to_string().contains("write transaction lock poisoned"));
        cleanup_db_artifacts(&path);
    }

