    #[test]
    fn clause_expect_helpers_panic_on_wrong_variant() {
        let base_clause = CypherClause::Create(CreateClause {
            patterns: Vec::new(),
        });
        assert!(panic::catch_unwind(|| expect_match_clause(&base_clause)).is_err());
        assert!(panic::catch_unwind(|| expect_delete_clause(&base_clause)).is_err());
        assert!(panic::catch_unwind(|| expect_set_clause(&base_clause)).is_err());
        assert!(panic::catch_unwind(|| expect_with_clause(&base_clause)).is_err());
        assert!(panic::catch_unwind(|| expect_unwind_clause(&base_clause)).is_err());
        assert!(panic::catch_unwind(|| expect_merge_clause(&base_clause)).is_err());

        let match_clause = CypherClause::Match(MatchClause {
            optional: false,
            patterns: Vec::new(),
            where_predicate: None,
            temporal_filter: None,
        });
        assert!(panic::catch_unwind(|| expect_create_clause(&match_clause)).is_err());

        let expr = CypherExpression::Identifier("n".to_string());
        assert!(
            panic::catch_unwind(|| expect_binary_expr(&expr, CypherBinaryOperator::Eq)).is_err()
        );
    }

