    #[test]
    fn init_open_and_backup_accept_owned_path_types() {
        let path = temp_db_path("owned-path-types");
        let db = Database::init(path.clone(), Header::default_v1()).expect("init with PathBuf");
        assert_eq!(db.node_count(), 0);

        let path_string = path.display().to_string();
        let mut reopened = Database::open(path_string.clone()).expect("open with String");
        assert_eq!(reopened.edge_count(), 0);

        let backup_path = temp_db_path("owned-path-types-backup");
        let backup_path_string = backup_path.display().to_string();
        reopened
            .backup(backup_path_string.clone())
            .expect("backup with String");

        let backup_open = Database::open(backup_path.clone()).expect("open backup with PathBuf");
        assert_eq!(backup_open.node_count(), 0);
        assert_eq!(backup_open.edge_count(), 0);

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
        fs::remove_file(&backup_path).expect("cleanup backup db");
        fs::remove_file(wal_path_for_db(&backup_path)).expect("cleanup backup wal");
    }

