    #[test]
    fn node_property_store_header_decode_validates_inputs() {
        let short = vec![0u8; NODE_PROPERTY_STORE_HEADER_SIZE - 1];
        let err =
            NodePropertyStoreHeader::decode(&short).expect_err("short props header must fail");
        assert!(matches!(err, DbError::Corrupt(_)));
        assert!(err
            .to_string()
            .contains("node property store header shorter"));

        let mut bad_magic = NodePropertyStoreHeader {
            format_version: NODE_PROPERTY_STORE_FORMAT_VERSION,
            page_size: Header::default_v1().page_size,
        }
        .encode();
        bad_magic[..8].copy_from_slice(b"BADPROP!");
        let err = NodePropertyStoreHeader::decode(&bad_magic)
            .expect_err("invalid props file magic must fail");
        assert!(matches!(err, DbError::Corrupt(_)));
        assert!(err
            .to_string()
            .contains("invalid node property store file magic"));

        let mut bad_version = NodePropertyStoreHeader {
            format_version: NODE_PROPERTY_STORE_FORMAT_VERSION,
            page_size: Header::default_v1().page_size,
        }
        .encode();
        bad_version[8..12].copy_from_slice(&(NODE_PROPERTY_STORE_FORMAT_VERSION + 1).to_le_bytes());
        let err = NodePropertyStoreHeader::decode(&bad_version)
            .expect_err("invalid props format version must fail");
        assert!(matches!(err, DbError::Corrupt(_)));
        assert!(err
            .to_string()
            .contains("invalid node property store format version"));

        let mut bad_page_size = NodePropertyStoreHeader {
            format_version: NODE_PROPERTY_STORE_FORMAT_VERSION,
            page_size: Header::default_v1().page_size,
        }
        .encode();
        bad_page_size[12..16].copy_from_slice(&32u32.to_le_bytes());
        let err = NodePropertyStoreHeader::decode(&bad_page_size)
            .expect_err("invalid props page size must fail");
        assert!(matches!(err, DbError::Corrupt(_)));
        assert!(err
            .to_string()
            .contains("invalid node property store page size"));
    }

