    #[test]
    fn node_property_store_internal_paths_cover_error_and_recycle_branches() {
        let path = temp_db_path("props-internals");
        let store = NodePropertyStore::open_or_init(&path, 64, 1).expect("open props");
        store.ensure_row_count(2).expect("create row pages");
        assert_eq!(
            store.read_properties(0).expect("empty row"),
            PropertyMap::new()
        );
        assert!(store
            .read_overflow_chain(NODE_PROPERTY_NO_OVERFLOW_PAGE, 0)
            .expect("zero remaining overflow")
            .is_empty());
        assert!(store
            .collect_overflow_pages(NODE_PROPERTY_NO_OVERFLOW_PAGE)
            .expect("no overflow pages")
            .is_empty());
        store.free_pages(&[]).expect("free empty page list");

        let row0 = store.row_page_id(0).expect("row0 page");
        let row1 = store.row_page_id(1).expect("row1 page");
        let err = store
            .row_page_id(99)
            .expect_err("unknown row page lookup must fail");
        assert!(matches!(err, DbError::InvalidArgument(_)));
        let err = NodePropertyStore::decode_row_descriptor(&[])
            .expect_err("short row descriptor must fail");
        assert!(matches!(err, DbError::Corrupt(_)));

        let err = store
            .read_page(row0, &mut [0u8; 63])
            .expect_err("wrong read buffer length must fail");
        assert!(matches!(err, DbError::InvalidArgument(_)));
        let err = store
            .write_page(row0, &[0u8; 63])
            .expect_err("wrong write buffer length must fail");
        assert!(matches!(err, DbError::InvalidArgument(_)));
        let err = store
            .read_page(999, &mut [0u8; 64])
            .expect_err("out-of-bounds read must fail");
        assert!(matches!(err, DbError::PageOutOfBounds { .. }));
        let err = store
            .write_page(999, &[0u8; 64])
            .expect_err("out-of-bounds write must fail");
        assert!(matches!(err, DbError::PageOutOfBounds { .. }));

        let dirty_a = vec![0xAAu8; 64];
        store.write_page(row0, &dirty_a).expect("write dirty row0");
        store
            .read_page(row1, &mut [0u8; 64])
            .expect("read row1 triggers eviction flush path");
        store.write_page(row0, &dirty_a).expect("write dirty row0");
        let dirty_b = vec![0xBBu8; 64];
        store
            .write_page(row1, &dirty_b)
            .expect("write row1 triggers eviction flush path");

        let err = store
            .read_overflow_chain(NODE_PROPERTY_NO_OVERFLOW_PAGE, 1)
            .expect_err("missing overflow head must fail");
        assert!(matches!(err, DbError::Corrupt(_)));

        let bad_overflow_page = store
            .allocate_page()
            .expect("allocate corrupt overflow page");
        let mut corrupt_overflow = vec![0u8; 64];
        corrupt_overflow[..8].copy_from_slice(&NODE_PROPERTY_NO_OVERFLOW_PAGE.to_le_bytes());
        corrupt_overflow[8..12]
            .copy_from_slice(&((store.overflow_payload_capacity() + 1) as u32).to_le_bytes());
        store
            .write_page(bad_overflow_page, &corrupt_overflow)
            .expect("write overflow too large");
        store
            .flush_buffer_pool_page(bad_overflow_page)
            .expect("flush overflow too large");
        let err = store
            .read_overflow_chain(bad_overflow_page, 1)
            .expect_err("overflow chunk larger than capacity must fail");
        assert!(matches!(err, DbError::Corrupt(_)));

        corrupt_overflow[8..12].copy_from_slice(&0u32.to_le_bytes());
        store
            .write_page(bad_overflow_page, &corrupt_overflow)
            .expect("write overflow empty chunk");
        store
            .flush_buffer_pool_page(bad_overflow_page)
            .expect("flush overflow empty chunk");
        let err = store
            .read_overflow_chain(bad_overflow_page, 1)
            .expect_err("overflow chunk len zero must fail");
        assert!(matches!(err, DbError::Corrupt(_)));

        corrupt_overflow[8..12].copy_from_slice(&2u32.to_le_bytes());
        store
            .write_page(bad_overflow_page, &corrupt_overflow)
            .expect("write overflow chunk larger than remaining");
        store
            .flush_buffer_pool_page(bad_overflow_page)
            .expect("flush overflow chunk larger than remaining");
        let err = store
            .read_overflow_chain(bad_overflow_page, 1)
            .expect_err("overflow chain exceeding expected length must fail");
        assert!(matches!(err, DbError::Corrupt(_)));

        corrupt_overflow[8..12].copy_from_slice(&1u32.to_le_bytes());
        store
            .write_page(bad_overflow_page, &corrupt_overflow)
            .expect("write truncated overflow chain");
        store
            .flush_buffer_pool_page(bad_overflow_page)
            .expect("flush truncated overflow chain");
        let err = store
            .read_overflow_chain(bad_overflow_page, 2)
            .expect_err("truncated overflow chain must fail");
        assert!(matches!(err, DbError::Corrupt(_)));

        let err = store
            .collect_overflow_pages(9_999)
            .expect_err("out-of-bounds overflow head must fail");
        assert!(matches!(err, DbError::Corrupt(_)));
        let err = store
            .free_pages(&[9_999])
            .expect_err("out-of-bounds free page must fail");
        assert!(matches!(err, DbError::PageOutOfBounds { .. }));

        let mut invalid_inline = vec![0u8; 64];
        invalid_inline[..8].copy_from_slice(&1u64.to_le_bytes());
        invalid_inline[8..16].copy_from_slice(&NODE_PROPERTY_NO_OVERFLOW_PAGE.to_le_bytes());
        invalid_inline[16..20].copy_from_slice(&2u32.to_le_bytes());
        store
            .write_page(row0, &invalid_inline)
            .expect("write invalid inline row page");
        store
            .flush_buffer_pool_page(row0)
            .expect("flush invalid inline row page");
        let err = store
            .read_properties(0)
            .expect_err("invalid inline metadata must fail");
        assert!(matches!(err, DbError::Corrupt(_)));

        let large_props = PropertyMap::from([(
            "payload".to_string(),
            PropertyValue::String("x".repeat(256)),
        )]);
        store
            .write_properties(0, &large_props)
            .expect("write large props");
        store
            .write_properties(0, &PropertyMap::new())
            .expect("write small props and free overflow pages");
        store
            .write_properties(0, &large_props)
            .expect("write large props and recycle free pages");
        store.checkpoint().expect("checkpoint props store");

        cleanup_db_artifacts(&path);
    }

    #[test]
    fn node_property_store_lock_poison_paths_return_corrupt_errors() {
        let free_list_path = temp_db_path("props-poison-free-list");
        let store =
            Arc::new(NodePropertyStore::open_or_init(&free_list_path, 64, 1).expect("open"));
        let cloned = Arc::clone(&store);
        let _ = thread::spawn(move || {
            let _guard = cloned.free_list.lock().expect("lock free list");
            panic!("poison free list");
        })
        .join();
        let err = store
            .lock_free_list()
            .expect_err("poisoned free-list lock must fail");
        assert!(matches!(err, DbError::Corrupt(_)));
        cleanup_db_artifacts(&free_list_path);

        let buffer_pool_path = temp_db_path("props-poison-buffer-pool");
        let store = Arc::new(
            NodePropertyStore::open_or_init(&buffer_pool_path, 64, 1).expect("open buffer pool"),
        );
        let cloned = Arc::clone(&store);
        let _ = thread::spawn(move || {
            let _guard = cloned.buffer_pool.lock().expect("lock buffer pool");
            panic!("poison buffer pool");
        })
        .join();
        let err = store
            .lock_buffer_pool()
            .expect_err("poisoned buffer-pool lock must fail");
        assert!(matches!(err, DbError::Corrupt(_)));
        cleanup_db_artifacts(&buffer_pool_path);
    }

