    #[test]
    #[cfg(not(coverage))]
    #[ignore = "helper test executed in a subprocess by crash-acceptance tests"]
    fn crash_helper_abort_during_wal_write() {
        if std::env::var("OGDB_RUN_CRASH_HELPER").ok().as_deref() != Some("1") {
            return;
        }

        let path = PathBuf::from(std::env::var("OGDB_CRASH_DB_PATH").expect("crash db path env"));
        let mode = std::env::var("OGDB_CRASH_MODE").expect("crash mode env");
        let wal_path = wal_path_for_db(&path);
        let mut wal = OpenOptions::new()
            .append(true)
            .open(&wal_path)
            .expect("open wal for crash helper");

        match mode.as_str() {
            "partial_add_edge" => {
                wal.write_all(&[WAL_RECORD_ADD_EDGE])
                    .expect("write add-edge record type");
                wal.write_all(&0u64.to_le_bytes())
                    .expect("write partial add-edge record bytes");
                wal.sync_data().expect("sync partial add-edge wal bytes");
            }
            "partial_create_node" => {
                wal.write_all(&[WAL_RECORD_CREATE_NODE])
                    .expect("write create-node record type");
                wal.write_all(&0u32.to_le_bytes())
                    .expect("write partial create-node record bytes");
                wal.sync_data().expect("sync partial create-node wal bytes");
            }
            other => panic!("unknown crash helper mode: {other}"),
        }

        std::process::abort();
    }

    #[test]
    #[cfg(not(coverage))]
    fn crash_during_wal_write_keeps_partial_edge_write_invisible() {
        let path = temp_db_path("crash-partial-wal-add-edge");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        let _ = db.create_node().expect("n0");
        let _ = db.create_node().expect("n1");
        db.checkpoint().expect("checkpoint baseline graph");
        drop(db);

        let status = spawn_crash_helper(&path, "partial_add_edge");
        assert!(
            !status.success(),
            "crash helper should terminate abnormally"
        );

        let reopened = Database::open(&path).expect("recover after simulated crash");
        assert_eq!(reopened.node_count(), 2);
        assert_eq!(reopened.edge_count(), 0);
        assert!(reopened
            .neighbors(0)
            .expect("neighbors after recovery")
            .is_empty());

        cleanup_db_artifacts(&path);
    }

