    #[test]
    #[cfg(not(coverage))]
    fn backup_after_crash_recovery_matches_recovered_state() {
        let path = temp_db_path("backup-after-crash-src");
        let dst = temp_db_path("backup-after-crash-dst");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        let n0 = db.create_node().expect("n0");
        let n1 = db.create_node().expect("n1");
        let _ = db.add_edge(n0, n1).expect("seed edge");
        db.checkpoint().expect("checkpoint baseline graph");
        drop(db);

        let status = spawn_crash_helper(&path, "partial_create_node");
        assert!(
            !status.success(),
            "crash helper should terminate abnormally"
        );

        let mut recovered = Database::open(&path).expect("open recovered graph");
        recovered.backup(&dst).expect("backup after recovery");
        let restored = Database::open(&dst).expect("open backup after recovery");

        assert_eq!(restored.node_count(), recovered.node_count());
        assert_eq!(restored.edge_count(), recovered.edge_count());
        assert_eq!(
            restored.neighbors(0).expect("restored neighbors"),
            recovered.neighbors(0).expect("recovered neighbors")
        );

        cleanup_db_artifacts(&path);
        cleanup_db_artifacts(&dst);
    }

