    #[test]
    fn free_page_reallocates_freed_pages_before_appending() {
        let path = temp_db_path("free-page-reuse");
        let db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        let p0 = db.allocate_page().expect("allocate p0");
        let p1 = db.allocate_page().expect("allocate p1");
        let p2 = db.allocate_page().expect("allocate p2");
        assert_eq!((p0, p1, p2), (0, 1, 2));

        let page_size = db.header().page_size as usize;
        let dirty = vec![0xAB; page_size];
        db.write_page(p1, &dirty).expect("write page before free");
        db.free_page(p2).expect("free p2");
        db.free_page(p1).expect("free p1");

        let recycled_first = db.allocate_page().expect("recycle first");
        let recycled_second = db.allocate_page().expect("recycle second");
        assert_eq!(recycled_first, 1);
        assert_eq!(recycled_second, 2);
        assert_eq!(db.page_count().expect("page count"), 3);

        let mut recycled_page = vec![1u8; page_size];
        db.read_page(recycled_first, &mut recycled_page)
            .expect("read recycled page");
        assert!(recycled_page.iter().all(|byte| *byte == 0));

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
        fs::remove_file(meta_path_for_db(&path)).expect("cleanup meta");
        fs::remove_file(free_list_path_for_db(&path)).expect("cleanup free list");
    }

