    #[test]
    fn compression_decode_falls_back_for_invalid_envelope_lengths() {
        let mut page = vec![0u8; 256];
        let page_len = page.len();
        page[..8].copy_from_slice(&PAGE_COMPRESSION_MAGIC);
        page[8] = PAGE_COMPRESSION_CODEC_LZ4;
        page[10..14].copy_from_slice(&(page_len as u32).to_le_bytes());
        page[14..18].copy_from_slice(&0u32.to_le_bytes());

        let decoded = decode_page_from_storage(&page).expect("decode fallback");
        assert_eq!(decoded, page);
    }

    #[test]
    fn compression_decode_handles_none_and_unknown_codec_paths() {
        let mut page = vec![0u8; 256];
        let page_len = page.len();
        page[..8].copy_from_slice(&PAGE_COMPRESSION_MAGIC);
        page[8] = PAGE_COMPRESSION_CODEC_NONE;
        page[10..14].copy_from_slice(&(page_len as u32).to_le_bytes());
        page[14..18].copy_from_slice(&1u32.to_le_bytes());
        page[PAGE_COMPRESSION_HEADER_SIZE] = 0xAA;

        let decoded_none = decode_page_from_storage(&page).expect("none codec decode");
        assert_eq!(decoded_none, page);

        let mut unknown = page.clone();
        unknown[8] = 0xFF;
        let err = decode_page_from_storage(&unknown).expect_err("unknown codec should fail");
        assert!(matches!(err, DbError::Corrupt(_)));
        assert!(err
            .to_string()
            .contains("unknown page compression codec id"));
    }

    #[test]
    fn database_hot_pages_are_persisted_with_lz4_compression() {
        let path = temp_db_path("compression-lz4-hot-pages");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        db.set_compression_config(CompressionConfig {
            hot_warm: CompressionSetting {
                algorithm: CompressionAlgorithm::Lz4,
                level: 1,
            },
            cold: CompressionSetting {
                algorithm: CompressionAlgorithm::Zstd,
                level: 3,
            },
        })
        .expect("set compression config");

        let page_id = db.allocate_page().expect("allocate page");
        let page_size = db.header().page_size as usize;
        let mut data = vec![0u8; page_size];
        for (idx, byte) in data.iter_mut().enumerate() {
            *byte = (idx % 199) as u8;
        }
        db.write_page(page_id, &data).expect("write page");
        db.checkpoint().expect("flush page");

        let encoded = read_page_encoded_from_disk(&path, db.header(), page_id);
        assert_eq!(&encoded[..8], &PAGE_COMPRESSION_MAGIC);
        assert_eq!(encoded[8], PAGE_COMPRESSION_CODEC_LZ4);

        let decoded = read_page_direct_from_disk(&path, db.header(), page_id);
        assert_eq!(decoded, data);

        cleanup_db_artifacts(&path);
    }

    #[test]
    fn compression_config_sidecar_defaults_and_backup_paths_are_covered() {
        let path = temp_db_path("compression-sidecar");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");

        let config = CompressionConfig {
            hot_warm: CompressionSetting {
                algorithm: CompressionAlgorithm::Lz4,
                level: 1,
            },
            cold: CompressionSetting {
                algorithm: CompressionAlgorithm::Zstd,
                level: 3,
            },
        };
        db.set_compression_config(config)
            .expect("persist compression config");
        assert_eq!(db.compression_config(), config);

        let compression_path = compression_path_for_db(&path);
        assert!(compression_path.exists());

        let reopen_path = temp_db_path("compression-sidecar-empty");
        let _ = Database::init(&reopen_path, Header::default_v1()).expect("init empty sidecar db");
        fs::write(compression_path_for_db(&reopen_path), "\n")
            .expect("write empty compression sidecar");
        let reopened = Database::open(&reopen_path).expect("open with empty compression sidecar");
        assert_eq!(reopened.compression_config(), CompressionConfig::default());

        let dst = temp_db_path("compression-backup-dst");
        db.backup(&dst)
            .expect("backup should copy compression sidecar");
        assert!(compression_path_for_db(&dst).exists());

        let dst_existing = temp_db_path("compression-backup-existing-sidecar");
        let dst_existing_sidecar = compression_path_for_db(&dst_existing);
        fs::write(&dst_existing_sidecar, "{}\n").expect("create destination compression sidecar");
        let err = db
            .backup(&dst_existing)
            .expect_err("existing destination compression sidecar must fail backup");
        assert!(matches!(err, DbError::AlreadyExists(_)));
        assert!(err
            .to_string()
            .contains(&dst_existing_sidecar.display().to_string()));

        cleanup_db_artifacts(&path);
        cleanup_db_artifacts(&reopen_path);
        cleanup_db_artifacts(&dst);
        cleanup_file_if_exists(dst_existing_sidecar);
    }

    #[test]
    fn node_property_overflow_pages_use_cold_zstd_compression() {
        let path = temp_db_path("compression-zstd-cold-overflow");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        db.set_compression_config(CompressionConfig {
            hot_warm: CompressionSetting {
                algorithm: CompressionAlgorithm::Lz4,
                level: 1,
            },
            cold: CompressionSetting {
                algorithm: CompressionAlgorithm::Zstd,
                level: 3,
            },
        })
        .expect("set compression config");

        let node = db.create_node().expect("create node");
        let mut props = PropertyMap::new();
        props.insert(
            "payload".to_string(),
            PropertyValue::String("x".repeat(32_000)),
        );
        db.set_node_properties(node, &props)
            .expect("set large properties");
        db.checkpoint().expect("checkpoint properties");

        let state = NodePropertyStore::load_or_init_state(&path).expect("load props state");
        let row_pages = state.row_pages.into_iter().collect::<BTreeSet<_>>();
        let props_path = node_props_path(&path);
        let file = File::open(&props_path).expect("open props store");
        let file_len = file.metadata().expect("props metadata").len();
        let page_size = db.header().page_size as usize;
        let data_len = file_len
            .checked_sub(NODE_PROPERTY_STORE_HEADER_SIZE as u64)
            .expect("props file includes header");
        let page_count = data_len / page_size as u64;

        let found_cold_zstd_page = (0..page_count)
            .filter(|page_id| !row_pages.contains(page_id))
            .any(|page_id| {
                let mut page = vec![0u8; page_size];
                let offset = NODE_PROPERTY_STORE_HEADER_SIZE as u64 + page_id * page_size as u64;
                read_exact_at(&file, &mut page, offset).expect("read props page");
                page.starts_with(&PAGE_COMPRESSION_MAGIC) && page[8] == PAGE_COMPRESSION_CODEC_ZSTD
            });
        assert!(
            found_cold_zstd_page,
            "expected at least one overflow page persisted with ZSTD compression"
        );

        cleanup_db_artifacts(&path);
    }

