    #[test]
    fn buffer_pool_metrics_track_read_hits_and_misses() {
        let path = temp_db_path("buffer-pool-hit-miss");
        let mut setup = Database::init_with_buffer_pool_capacity(&path, Header::default_v1(), 2)
            .expect("init with custom buffer pool");
        let page_id = setup.allocate_page().expect("allocate page");
        let page_size = setup.header().page_size as usize;
        let page = vec![0xAB; page_size];
        setup.write_page(page_id, &page).expect("write page");
        setup.checkpoint().expect("flush page to disk");
        drop(setup);

        let db =
            Database::open_with_buffer_pool_capacity(&path, 2).expect("reopen with custom pool");

        let before = db.metrics().expect("metrics before reads");
        let mut out = vec![0u8; page_size];
        db.read_page(page_id, &mut out).expect("first read");
        let after_first = db.metrics().expect("metrics after first read");
        db.read_page(page_id, &mut out).expect("second read");
        let after_second = db.metrics().expect("metrics after second read");

        assert_eq!(
            after_first.buffer_pool_misses,
            before.buffer_pool_misses + 1
        );
        assert_eq!(after_first.buffer_pool_hits, before.buffer_pool_hits);
        assert_eq!(
            after_second.buffer_pool_hits,
            after_first.buffer_pool_hits + 1
        );
        assert_eq!(
            after_second.buffer_pool_misses,
            after_first.buffer_pool_misses
        );
        assert_eq!(out, page);

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
        fs::remove_file(meta_path_for_db(&path)).expect("cleanup meta");
    }

    #[test]
    fn buffer_pool_lru_eviction_removes_least_recent_page() {
        let path = temp_db_path("buffer-pool-eviction");
        let db = Database::init_with_buffer_pool_capacity(&path, Header::default_v1(), 2)
            .expect("init with custom buffer pool");
        for _ in 0..3 {
            let _ = db.allocate_page().expect("allocate page");
        }
        drop(db);

        let reopened = Database::open_with_buffer_pool_capacity(&path, 2)
            .expect("reopen with custom buffer pool");
        let page_size = reopened.header().page_size as usize;
        let mut out = vec![0u8; page_size];

        let before = reopened.metrics().expect("metrics before reads");
        reopened.read_page(0, &mut out).expect("read p0");
        reopened.read_page(1, &mut out).expect("read p1");
        reopened.read_page(0, &mut out).expect("read p0 again");
        reopened.read_page(2, &mut out).expect("read p2");
        reopened
            .read_page(1, &mut out)
            .expect("read p1 should miss after eviction");
        let after = reopened.metrics().expect("metrics after reads");

        assert_eq!(after.buffer_pool_hits - before.buffer_pool_hits, 1);
        assert_eq!(after.buffer_pool_misses - before.buffer_pool_misses, 4);

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
        fs::remove_file(meta_path_for_db(&path)).expect("cleanup meta");
    }

    #[test]
    fn buffer_pool_remove_pages_from_drops_matching_frames() {
        let mut pool = BufferPool::new(4, 16).expect("create pool");
        let page = vec![0xAB; 16];
        pool.write_page(0, &page, ok_flush).expect("write p0");
        pool.write_page(2, &page, ok_flush).expect("write p2");
        pool.write_page(3, &page, ok_flush).expect("write p3");
        assert!(pool.frames.contains_key(&0));
        assert!(pool.frames.contains_key(&2));
        assert!(pool.frames.contains_key(&3));

        pool.remove_pages_from(2);
        assert!(pool.frames.contains_key(&0));
        assert!(!pool.frames.contains_key(&2));
        assert!(!pool.frames.contains_key(&3));
        assert!(pool.lru.iter().all(|page_id| *page_id < 2));
    }

