    #[test]
    fn buffer_pool_supports_concurrent_read_access() {
        let path = temp_db_path("buffer-pool-concurrent-read");
        let mut setup = Database::init_with_buffer_pool_capacity(&path, Header::default_v1(), 4)
            .expect("init with custom buffer pool");
        let _ = setup.allocate_page().expect("allocate p0");
        let page_size = setup.header().page_size as usize;
        let mut seeded = vec![0u8; page_size];
        seeded[0] = 0x5A;
        seeded[page_size - 1] = 0xE1;
        setup.write_page(0, &seeded).expect("seed page");
        setup.checkpoint().expect("flush seed page");
        drop(setup);

        let db = Arc::new(
            Database::open_with_buffer_pool_capacity(&path, 4).expect("open with custom pool"),
        );
        let before = db.metrics().expect("metrics before concurrent reads");

        let mut handles = Vec::new();
        let threads = 8usize;
        let iterations = 64usize;
        for _ in 0..threads {
            let db = Arc::clone(&db);
            handles.push(thread::spawn(move || {
                let mut out = vec![0u8; page_size];
                for _ in 0..iterations {
                    db.read_page(0, &mut out).expect("concurrent read");
                    assert_eq!(out[0], 0x5A);
                    assert_eq!(out[page_size - 1], 0xE1);
                }
            }));
        }
        for handle in handles {
            handle.join().expect("thread join");
        }

        let after = db.metrics().expect("metrics after concurrent reads");
        let expected_reads = (threads * iterations) as u64;
        assert!(after.buffer_pool_hits - before.buffer_pool_hits >= expected_reads - 1);
        assert!(after.buffer_pool_misses - before.buffer_pool_misses <= 1);

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
        fs::remove_file(meta_path_for_db(&path)).expect("cleanup meta");
    }

