    #[test]
    fn label_projections_track_rows_and_csr_offsets_and_update_on_compaction() {
        let path = temp_db_path("label-projections-csr-offsets");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");

        let _ = db
            .create_node_with(&["Person".to_string()], &PropertyMap::new())
            .expect("create node 0");
        let _ = db
            .create_node_with(&["Person".to_string()], &PropertyMap::new())
            .expect("create node 1");
        let _ = db
            .create_node_with(&["Admin".to_string()], &PropertyMap::new())
            .expect("create node 2");

        let person_projection = db
            .label_projections
            .get("Person")
            .expect("person projection exists");
        assert_eq!(
            person_projection
                .iter()
                .map(|entry| entry._id)
                .collect::<Vec<u64>>(),
            vec![0, 1]
        );
        for entry in person_projection {
            assert_eq!(entry._row, entry._id as usize);
            assert_eq!(entry._csr_offset, db.adjacency.offsets[entry._id as usize]);
        }

        let _ = db.add_edge(0, 1).expect("add edge");
        let _ = db
            .compact_delta_buffers_and_persist(true)
            .expect("force compaction");
        let person_projection_after = db
            .label_projections
            .get("Person")
            .expect("person projection after compaction");
        let by_id = person_projection_after
            .iter()
            .map(|entry| (entry._id, entry._csr_offset))
            .collect::<BTreeMap<u64, usize>>();
        assert_eq!(by_id.get(&0), Some(&0));
        assert_eq!(by_id.get(&1), Some(&1));

        db.set_node_labels(1, &["Admin".to_string()])
            .expect("replace labels");
        assert_eq!(
            db.label_projections
                .get("Person")
                .expect("person projection")
                .iter()
                .map(|entry| entry._id)
                .collect::<Vec<u64>>(),
            vec![0]
        );
        assert_eq!(
            db.label_projections
                .get("Admin")
                .expect("admin projection")
                .iter()
                .map(|entry| entry._id)
                .collect::<Vec<u64>>(),
            vec![1, 2]
        );
        assert!(db
            .find_nodes_by_label_and_property("   ", "age", &PropertyValue::I64(1))
            .is_empty());

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
        fs::remove_file(meta_path_for_db(&path)).expect("cleanup meta");
        fs::remove_file(node_props_path(&path)).expect("cleanup node props file");
        fs::remove_file(node_props_meta_path(&path)).expect("cleanup node props meta");
        fs::remove_file(node_props_free_list_path(&path)).expect("cleanup node props free list");
    }

