    #[test]
    fn auto_index_creates_index_after_threshold_queries_and_uses_property_scan() {
        let path = temp_db_path("auto-index-threshold");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");
        db.set_auto_index_threshold(Some(3));
        assert_eq!(db.auto_index_threshold(), Some(3));

        let _ = db
            .create_node_with(
                &["Person".to_string()],
                &PropertyMap::from([(
                    "name".to_string(),
                    PropertyValue::String("Alice".to_string()),
                )]),
            )
            .expect("create node 0");
        let _ = db
            .create_node_with(
                &["Person".to_string()],
                &PropertyMap::from([(
                    "name".to_string(),
                    PropertyValue::String("Bob".to_string()),
                )]),
            )
            .expect("create node 1");

        assert!(db.list_indexes().is_empty());
        for _ in 0..2 {
            db.query("MATCH (p:Person) WHERE p.name = 'Alice' RETURN p")
                .expect("query before threshold");
        }
        assert!(db.list_indexes().is_empty());
        assert_eq!(
            db.query_property_access_counts()
                .get(&("Person".to_string(), "name".to_string()))
                .copied(),
            Some(2)
        );

        db.query("MATCH (p:Person) WHERE p.name = 'Alice' RETURN p")
            .expect("query hits threshold");
        let indexes = db.list_indexes();
        assert_eq!(indexes.len(), 1);
        assert!(indexes.iter().any(|entry| {
            entry.label == "Person" && entry.property_keys == vec!["name".to_string()]
        }));

        let procedure_rows = db
            .query("CALL db.indexes()")
            .expect("indexes call")
            .to_rows();
        assert!(procedure_rows.iter().any(|row| {
            row.get("label") == Some(&PropertyValue::String("Person".to_string()))
                && row.get("propertyKeys") == Some(&PropertyValue::String("[\"name\"]".to_string()))
        }));

        let ast = db
            .parse_cypher("MATCH (p:Person) WHERE p.name = 'Alice' RETURN p")
            .expect("parse");
        let semantic = db.analyze_cypher(&ast).expect("analyze");
        let logical = db.plan_cypher(&semantic).expect("plan");
        let physical = db.physical_plan_cypher(&logical).expect("physical plan");
        let (scan_strategy, scan_label) = physical_scan_parts(&physical).expect("scan in plan");
        assert_eq!(scan_strategy, PhysicalScanStrategy::PropertyIndexScan);
        assert_eq!(scan_label, Some("Person"));

        cleanup_db_artifacts(&path);
    }

