    #[test]
    fn auto_index_tracks_multiple_properties_independently_and_supports_reset() {
        let path = temp_db_path("auto-index-multi-reset");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");
        db.set_auto_index_threshold(Some(3));

        let _ = db
            .create_node_with(
                &["Person".to_string()],
                &PropertyMap::from([
                    (
                        "name".to_string(),
                        PropertyValue::String("Alice".to_string()),
                    ),
                    ("age".to_string(), PropertyValue::I64(30)),
                ]),
            )
            .expect("create node");

        for _ in 0..2 {
            db.query("MATCH (p:Person) WHERE p.name = 'Alice' RETURN p")
                .expect("name query");
        }
        db.query("MATCH (p:Person) WHERE p.age = 30 RETURN p")
            .expect("age query");

        assert_eq!(
            db.query_property_access_counts()
                .get(&("Person".to_string(), "name".to_string()))
                .copied(),
            Some(2)
        );
        assert_eq!(
            db.query_property_access_counts()
                .get(&("Person".to_string(), "age".to_string()))
                .copied(),
            Some(1)
        );
        assert!(db.list_indexes().is_empty());

        db.query("MATCH (p:Person) WHERE p.name = 'Alice' RETURN p")
            .expect("name threshold query");
        assert_eq!(db.list_indexes().len(), 1);
        assert!(db.list_indexes().iter().any(|entry| {
            entry.label == "Person" && entry.property_keys == vec!["name".to_string()]
        }));

        db.reset_query_property_access_counts();
        assert!(db.query_property_access_counts().is_empty());

        for _ in 0..3 {
            db.query("MATCH (p:Person) WHERE p.age = 30 RETURN p")
                .expect("age query after reset");
        }
        assert_eq!(db.list_indexes().len(), 2);
        assert!(db.list_indexes().iter().any(|entry| {
            entry.label == "Person" && entry.property_keys == vec!["age".to_string()]
        }));

        cleanup_db_artifacts(&path);
    }

