    #[test]
    fn property_index_rebuild_lookup_and_find_cover_remaining_lines() {
        let path = temp_db_path("index-rebuild-lookup-find-lines");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");
        let unlabeled = db.create_node().expect("unlabeled");
        let person = db
            .create_node_with(
                &["Person".to_string()],
                &PropertyMap::from([
                    ("age".to_string(), PropertyValue::I64(33)),
                    ("a".to_string(), PropertyValue::I64(1)),
                    ("b".to_string(), PropertyValue::I64(2)),
                ]),
            )
            .expect("person");
        let _ = db
            .create_node_with(&["Person".to_string()], &PropertyMap::new())
            .expect("person without properties");

        db.create_index("Person", "age").expect("create age index");
        db.create_composite_index("Person", &["a".to_string(), "b".to_string()])
            .expect("create composite a,b");
        db.create_composite_index("Person", &["b".to_string(), "a".to_string()])
            .expect("create composite b,a");
        db.rebuild_property_indexes_from_catalog()
            .expect("rebuild indexes");

        let age_predicate = CypherExpression::BinaryOp {
            left: Box::new(CypherExpression::PropertyAccess {
                target: Box::new(CypherExpression::Identifier("n".to_string())),
                property: "age".to_string(),
            }),
            op: CypherBinaryOperator::Eq,
            right: Box::new(CypherExpression::Literal(CypherLiteral::Integer(33))),
        };
        let snapshot_txn_id = db.current_snapshot_txn_id();
        let (age_strategy, age_candidates) = db
            .lookup_indexed_nodes_for_filter_scan("Person", "n", &age_predicate, snapshot_txn_id)
            .expect("age lookup should use index");
        assert_eq!(age_strategy, PhysicalScanStrategy::PropertyIndexScan);
        assert_eq!(age_candidates, vec![person]);

        let a_predicate = CypherExpression::BinaryOp {
            left: Box::new(CypherExpression::PropertyAccess {
                target: Box::new(CypherExpression::Identifier("n".to_string())),
                property: "a".to_string(),
            }),
            op: CypherBinaryOperator::Eq,
            right: Box::new(CypherExpression::Literal(CypherLiteral::Integer(1))),
        };
        let (a_strategy, a_candidates) = db
            .lookup_indexed_nodes_for_filter_scan("Person", "n", &a_predicate, snapshot_txn_id)
            .expect("a lookup should use composite index");
        assert_eq!(a_strategy, PhysicalScanStrategy::CompositeIndexScan);
        assert_eq!(a_candidates, vec![person]);

        let age_definition = IndexDefinition {
            label: "Person".to_string(),
            property_keys: vec!["age".to_string()],
        };
        let composite_ab_definition = IndexDefinition {
            label: "Person".to_string(),
            property_keys: vec!["a".to_string(), "b".to_string()],
        };
        db.materialized_indexes.insert(
            age_definition.clone(),
            MaterializedIndex::Composite(CompositeIndex::default()),
        );
        let _ =
            db.lookup_indexed_nodes_for_filter_scan("Person", "n", &age_predicate, snapshot_txn_id);
        let _ = db.find_nodes_by_label_and_property("Person", "age", &PropertyValue::I64(33));
        db.materialized_indexes.insert(
            age_definition.clone(),
            MaterializedIndex::Single(BTreeIndex {
                entries: BTreeMap::from([(PropertyValue::I64(33), vec![person])]),
            }),
        );
        db.materialized_indexes.insert(
            composite_ab_definition.clone(),
            MaterializedIndex::Single(BTreeIndex::default()),
        );
        let _ =
            db.lookup_indexed_nodes_for_filter_scan("Person", "n", &a_predicate, snapshot_txn_id);
        let _ = db.find_nodes_by_label_and_property("Person", "a", &PropertyValue::I64(1));
        db.materialized_indexes.insert(
            composite_ab_definition,
            MaterializedIndex::Composite(CompositeIndex {
                entries: BTreeMap::from([(
                    vec![PropertyValue::I64(1), PropertyValue::I64(2)],
                    vec![person],
                )]),
            }),
        );

        assert_eq!(
            db.find_nodes_by_label_and_property("Person", "a", &PropertyValue::I64(1)),
            vec![person]
        );

        db.materialized_indexes.insert(
            IndexDefinition {
                label: "Person".to_string(),
                property_keys: vec!["age".to_string()],
            },
            MaterializedIndex::Single(BTreeIndex {
                entries: BTreeMap::from([(PropertyValue::I64(33), vec![unlabeled, person])]),
            }),
        );
        assert_eq!(
            db.find_nodes_by_label_and_property("Person", "age", &PropertyValue::I64(33)),
            vec![person]
        );
        assert!(db
            .find_nodes_by_label_and_property("Person", "ghost", &PropertyValue::I64(9))
            .is_empty());
        let _ = db.find_nodes_by_label_and_property_at(
            "Person",
            "age",
            &PropertyValue::I64(33),
            snapshot_txn_id.saturating_sub(1),
        );

        cleanup_db_artifacts(&path);
    }

