    #[test]
    fn add_edge_and_neighbors_round_trip() {
        let path = temp_db_path("add-edge-neighbors");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        let a = db.create_node().expect("node a");
        let b = db.create_node().expect("node b");
        let c = db.create_node().expect("node c");

        let e0 = db.add_edge(a, b).expect("add edge a->b");
        let e1 = db.add_edge(a, c).expect("add edge a->c");
        let e2 = db.add_edge(b, c).expect("add edge b->c");
        assert_eq!(e0, 0);
        assert_eq!(e1, 1);
        assert_eq!(e2, 2);
        assert_eq!(db.edge_count(), 3);

        assert_eq!(db.neighbors(a).expect("neighbors for a"), vec![b, c]);
        assert_eq!(db.neighbors(b).expect("neighbors for b"), vec![c]);
        assert!(db.neighbors(c).expect("neighbors for c").is_empty());

        let reopened = Database::open(&path).expect("open must succeed");
        assert_eq!(reopened.edge_count(), 3);
        assert_eq!(
            reopened.neighbors(a).expect("neighbors after reopen"),
            vec![b, c]
        );

        fs::remove_file(path).expect("cleanup");
    }

