    #[test]
    fn export_snapshots_include_node_and_edge_metadata() {
        let path = temp_db_path("export-snapshots-include-metadata");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");

        let mut alice_props = PropertyMap::new();
        alice_props.insert(
            "name".to_string(),
            PropertyValue::String("Alice".to_string()),
        );
        alice_props.insert("age".to_string(), PropertyValue::I64(41));
        let _ = db
            .create_node_with(
                &["Person".to_string(), "Employee".to_string()],
                &alice_props,
            )
            .expect("create alice");

        let mut bob_props = PropertyMap::new();
        bob_props.insert("name".to_string(), PropertyValue::String("Bob".to_string()));
        let _ = db
            .create_node_with(&["Person".to_string()], &bob_props)
            .expect("create bob");

        let mut edge_props = PropertyMap::new();
        edge_props.insert("since".to_string(), PropertyValue::I64(2020));
        let _ = db
            .add_typed_edge(0, 1, "KNOWS", &edge_props)
            .expect("add typed edge");

        let nodes = db.export_nodes().expect("export nodes");
        assert_eq!(nodes.len(), 2);
        assert_eq!(nodes[0].id, 0);
        assert_eq!(
            nodes[0].labels,
            vec!["Employee".to_string(), "Person".to_string()]
        );
        assert_eq!(
            nodes[0].properties.get("name"),
            Some(&PropertyValue::String("Alice".to_string()))
        );
        assert_eq!(nodes[1].id, 1);
        assert_eq!(nodes[1].labels, vec!["Person".to_string()]);

        let edges = db.export_edges().expect("export edges");
        assert_eq!(edges.len(), 1);
        assert_eq!(edges[0].id, 0);
        assert_eq!(edges[0].src, 0);
        assert_eq!(edges[0].dst, 1);
        assert_eq!(edges[0].edge_type, Some("KNOWS".to_string()));
        assert_eq!(
            edges[0].properties.get("since"),
            Some(&PropertyValue::I64(2020))
        );

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
        fs::remove_file(meta_path_for_db(&path)).expect("cleanup meta");
    }

    #[test]
    fn export_snapshot_helpers_skip_invisible_nodes_and_edges() {
        let path = temp_db_path("export-snapshots-visibility");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        let _ = db.create_node().expect("n0");
        let _ = db.create_node().expect("n1");
        let _ = db.add_edge(0, 1).expect("edge0");
        let _ = db.add_edge(1, 1).expect("edge1");

        db.node_versions[0].committed = false;
        let nodes_snapshot_zero = db.export_nodes_at(0).expect("export nodes at snapshot");
        assert!(nodes_snapshot_zero.is_empty());

        db.node_versions[0].committed = true;
        db.node_versions[1].committed = true;
        db.edge_versions[0].committed = false;
        let edges_with_hidden_edge = db
            .export_edges_at(db.current_snapshot_txn_id())
            .expect("export edges with hidden edge");
        assert_eq!(edges_with_hidden_edge.len(), 1);
        assert_eq!(edges_with_hidden_edge[0].id, 1);

        db.edge_versions[0].committed = true;
        db.node_versions[1].committed = false;
        let edges_with_hidden_node = db
            .export_edges_at(db.current_snapshot_txn_id())
            .expect("export edges with hidden node");
        assert!(edges_with_hidden_node.is_empty());

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
        fs::remove_file(meta_path_for_db(&path)).expect("cleanup meta");
    }

