    #[test]
    fn physical_expand_hash_join_uses_lookup_with_temporal_filter_pushdown() {
        let path = temp_db_path("physical-expand-hash-join-temporal");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        let _ = db.create_node().expect("n0");
        let _ = db.create_node().expect("n1");
        let _ = db.create_node().expect("n2");
        db.add_typed_edge(
            0,
            1,
            "KNOWS",
            &PropertyMap::from([
                (
                    "valid_from".to_string(),
                    PropertyValue::I64(1_700_000_000_000),
                ),
                (
                    "valid_to".to_string(),
                    PropertyValue::I64(1_800_000_000_000),
                ),
            ]),
        )
        .expect("edge valid at 1750");
        db.add_typed_edge(
            0,
            2,
            "KNOWS",
            &PropertyMap::from([
                (
                    "valid_from".to_string(),
                    PropertyValue::I64(1_800_000_000_000),
                ),
                (
                    "valid_to".to_string(),
                    PropertyValue::I64(1_900_000_000_000),
                ),
            ]),
        )
        .expect("edge invalid at 1750");

        let plan = PhysicalPlan::PhysicalExpand {
            input: Box::new(PhysicalPlan::PhysicalScan {
                label: None,
                variable: Some("a".to_string()),
                scan_strategy: PhysicalScanStrategy::SequentialScan,
                estimated_rows: 3,
                estimated_cost: 1.0,
            }),
            from: "a".to_string(),
            edge_type: Some("KNOWS".to_string()),
            direction: RelationshipDirection::LeftToRight,
            to: Some("b".to_string()),
            edge_variable: Some("r".to_string()),
            temporal_filter: Some(TemporalFilter {
                scope: TemporalScope::ValidTime,
                timestamp_millis: 1_750_000_000_000,
            }),
            join_strategy: PhysicalJoinStrategy::HashJoin,
            estimated_rows: 1,
            estimated_cost: 1.0,
        };
        let batches = db
            .execute_physical_plan_batches(&plan, db.current_snapshot_txn_id())
            .expect("execute physical expand hash join");
        let rows = rows_from_batches(&batches);
        assert_eq!(rows.len(), 1);
        assert_eq!(rows[0].get("a"), Some(&RuntimeValue::Node(0)));
        assert_eq!(rows[0].get("b"), Some(&RuntimeValue::Node(1)));
        assert!(matches!(rows[0].get("r"), Some(RuntimeValue::Edge(_))));

        fs::remove_file(path).expect("cleanup");
    }

