    #[test]
    fn metadata_validates_unknown_ids_and_empty_edge_type() {
        let path = temp_db_path("metadata-validation");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        let _ = db.create_node().expect("n0");
        let _ = db.create_node().expect("n1");

        let label_err = db
            .set_node_labels(7, &["Person".to_string()])
            .expect_err("unknown node labels should fail");
        assert!(matches!(label_err, DbError::InvalidArgument(_)));

        let mut node_props = PropertyMap::new();
        node_props.insert("name".to_string(), PropertyValue::String("x".to_string()));
        let prop_err = db
            .set_node_properties(9, &node_props)
            .expect_err("unknown node properties should fail");
        assert!(matches!(prop_err, DbError::InvalidArgument(_)));

        let labels_lookup_err = db
            .node_labels(11)
            .expect_err("unknown node labels lookup should fail");
        assert!(matches!(labels_lookup_err, DbError::InvalidArgument(_)));

        let props_lookup_err = db
            .node_properties(11)
            .expect_err("unknown node properties lookup should fail");
        assert!(matches!(props_lookup_err, DbError::InvalidArgument(_)));

        let edge_type_err = db
            .add_typed_edge(0, 1, "   ", &PropertyMap::new())
            .expect_err("empty edge type should fail");
        assert!(matches!(edge_type_err, DbError::InvalidArgument(_)));
        assert!(edge_type_err
            .to_string()
            .contains("edge type cannot be empty"));

        let _ = db.add_edge(0, 1).expect("seed edge");

        let edge_lookup_err = db
            .edge_type(3)
            .expect_err("unknown edge type lookup should fail");
        assert!(matches!(edge_lookup_err, DbError::InvalidArgument(_)));

        let edge_props_lookup_err = db
            .edge_properties(7)
            .expect_err("unknown edge properties lookup should fail");
        assert!(matches!(edge_props_lookup_err, DbError::InvalidArgument(_)));

        let edge_valid_window_lookup_err = db
            .edge_valid_window(5)
            .expect_err("unknown edge valid window lookup should fail");
        assert!(matches!(
            edge_valid_window_lookup_err,
            DbError::InvalidArgument(_)
        ));

        let edge_tx_lookup_err = db
            .edge_transaction_time_millis(5)
            .expect_err("unknown edge transaction time lookup should fail");
        assert!(matches!(edge_tx_lookup_err, DbError::InvalidArgument(_)));

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
        fs::remove_file(meta_path_for_db(&path)).expect("cleanup meta");
    }

