    #[test]
    fn hop_levels_detects_corrupt_edge_node_reference() {
        let path = temp_db_path("hop-corrupt-edge");
        let mut db = Database::init(
            &path,
            Header {
                format_version: 1,
                page_size: 64,
                next_node_id: 0,
                edge_count: 0,
            },
        )
        .expect("init must succeed");
        let n0 = db.create_node().expect("n0");
        let n1 = db.create_node().expect("n1");
        let _ = db.add_edge(n0, n1).expect("n0->n1");

        let mut page = vec![0u8; db.header().page_size as usize];
        db.read_page(0, &mut page).expect("read edge page");
        page[8..16].copy_from_slice(&99u64.to_le_bytes());
        db.write_page(0, &page).expect("write corrupted edge page");
        db.checkpoint().expect("flush corrupted edge page");
        let err = Database::open(&path).expect_err("open must fail on corrupt edge reference");
        assert!(matches!(err, DbError::Corrupt(_)));
        assert!(err.to_string().contains("non-existent node"));

        fs::remove_file(path).expect("cleanup");
    }

