    #[test]
    fn backup_copies_database_and_sidecars() {
        let path = temp_db_path("backup-src");
        let dst = temp_db_path("backup-dst");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        let n0 = db.create_node().expect("n0");
        let n1 = db.create_node().expect("n1");
        let mut props = PropertyMap::new();
        props.insert(
            "name".to_string(),
            PropertyValue::String("alice".to_string()),
        );
        db.set_node_properties(n0, &props)
            .expect("set node props before backup");
        let _ = db.add_edge(n0, n1).expect("n0->n1");
        let recycled = db.allocate_page().expect("allocate recyclable page");
        db.free_page(recycled).expect("free recyclable page");

        db.backup(&dst).expect("backup must succeed");
        assert!(node_props_path(&dst).exists());
        assert!(node_props_meta_path(&dst).exists());
        assert!(node_props_free_list_path(&dst).exists());

        let restored = Database::open(&dst).expect("open backup");
        assert_eq!(restored.node_count(), 2);
        assert_eq!(restored.edge_count(), 1);
        assert_eq!(restored.neighbors(0).expect("neighbors"), vec![1]);
        assert_eq!(restored.node_properties(0).expect("props"), props);
        assert!(wal_path_for_db(&dst).exists());
        assert!(meta_path_for_db(&dst).exists());
        assert!(free_list_path_for_db(&dst).exists());
        assert!(node_props_path(&dst).exists());
        assert!(node_props_meta_path(&dst).exists());
        assert!(node_props_free_list_path(&dst).exists());
        assert_eq!(
            restored
                .allocate_page()
                .expect("allocate recycled page from backup"),
            recycled
        );

        fs::remove_file(&path).expect("cleanup src db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup src wal");
        fs::remove_file(meta_path_for_db(&path)).expect("cleanup src meta");
        fs::remove_file(free_list_path_for_db(&path)).expect("cleanup src free list");
        fs::remove_file(node_props_path(&path)).expect("cleanup src node props");
        fs::remove_file(node_props_meta_path(&path)).expect("cleanup src node props meta");
        fs::remove_file(node_props_free_list_path(&path))
            .expect("cleanup src node props free list");
        fs::remove_file(&dst).expect("cleanup dst db");
        fs::remove_file(wal_path_for_db(&dst)).expect("cleanup dst wal");
        fs::remove_file(meta_path_for_db(&dst)).expect("cleanup dst meta");
        fs::remove_file(free_list_path_for_db(&dst)).expect("cleanup dst free list");
        fs::remove_file(node_props_path(&dst)).expect("cleanup dst node props");
        fs::remove_file(node_props_meta_path(&dst)).expect("cleanup dst node props meta");
        fs::remove_file(node_props_free_list_path(&dst)).expect("cleanup dst node props free list");
    }

