    #[test]
    fn backup_online_reports_progress_and_creates_restorable_copy() {
        let path = temp_db_path("backup-online-src");
        let dst = temp_db_path("backup-online-dst");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        let a = db.create_node().expect("node a");
        let b = db.create_node().expect("node b");
        let _ = db.add_edge(a, b).expect("add edge");

        let mut progress = Vec::<(u64, u64)>::new();
        db.backup_online(&dst, |copied, total| progress.push((copied, total)))
            .expect("backup online");
        assert!(!progress.is_empty(), "progress callback should be invoked");
        let (copied, total) = progress[progress.len() - 1];
        assert_eq!(copied, total);
        assert!(total > 0);

        let restored = Database::open(&dst).expect("open online backup");
        assert_eq!(restored.node_count(), 2);
        assert_eq!(restored.edge_count(), 1);
        assert_eq!(restored.neighbors(0).expect("neighbors"), vec![1]);

        cleanup_db_artifacts(&path);
        cleanup_db_artifacts(&dst);
    }

