    #[test]
    fn write_transaction_propagates_internal_helper_errors() {
        let path = temp_db_path("write-tx-propagates-errors");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        let _ = db.create_node().expect("seed n0");
        let _ = db.create_node().expect("seed n1");

        {
            let mut tx = db.begin_write();

            let saved_next_node_id = tx.db.header.next_node_id;
            tx.db.header.next_node_id = u64::MAX;
            let create_err = tx.create_node().expect_err("create_node should propagate");
            assert!(create_err.to_string().contains("node id overflow"));
            tx.db.header.next_node_id = saved_next_node_id;

            tx.db.header.next_node_id = u64::MAX;
            let create_with_err = tx
                .create_node_with(vec!["Person".to_string()], PropertyMap::new())
                .expect_err("create_node_with should propagate");
            assert!(create_with_err.to_string().contains("node id overflow"));
            tx.db.header.next_node_id = saved_next_node_id;

            let saved_edge_count = tx.db.header.edge_count;
            tx.db.header.edge_count = u64::MAX;
            let add_edge_err = tx.add_edge(0, 1).expect_err("add_edge should propagate");
            assert!(add_edge_err.to_string().contains("edge id overflow"));
            let add_props_err = tx
                .add_edge_with_properties(0, 1, PropertyMap::new())
                .expect_err("add_edge_with_properties should propagate");
            assert!(add_props_err.to_string().contains("edge id overflow"));
            tx.db.header.edge_count = saved_edge_count;

            let add_typed_err = tx
                .add_typed_edge(0, 1, "   ".to_string(), PropertyMap::new())
                .expect_err("add_typed_edge should propagate");
            assert!(add_typed_err
                .to_string()
                .contains("edge type cannot be empty"));

            tx.rollback();
        }

        cleanup_db_artifacts(&path);
    }

    #[test]
    fn mvcc_internal_error_and_fallback_paths_are_covered() {
        let path = temp_db_path("mvcc-internal-paths");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        let _ = db.create_node().expect("n0");
        let _ = db.create_node().expect("n1");

        let mut undo_log = Vec::<UndoLogEntry>::new();
        let txn_id = db.allocate_txn_id();

        let old_next_node_id = db.header.next_node_id;
        db.header.next_node_id = u64::MAX;
        let node_overflow = db
            .create_node_with_in_txn(txn_id, &[], &PropertyMap::new(), &mut undo_log)
            .expect_err("node overflow must fail");
        assert!(node_overflow.to_string().contains("node id overflow"));
        db.header.next_node_id = old_next_node_id;

        let empty_type = db
            .add_edge_in_txn(
                txn_id,
                0,
                1,
                Some("   "),
                &PropertyMap::new(),
                &mut undo_log,
            )
            .expect_err("empty edge type must fail");
        assert!(empty_type.to_string().contains("edge type cannot be empty"));

        let bad_nodes = db
            .add_edge_in_txn(txn_id, 99, 100, None, &PropertyMap::new(), &mut undo_log)
            .expect_err("unknown edge nodes must fail");
        assert!(bad_nodes.to_string().contains("unknown node id for edge"));

        let old_edge_count = db.header.edge_count;
        db.header.edge_count = u64::MAX;
        let edge_overflow = db
            .add_edge_in_txn(txn_id, 0, 1, None, &PropertyMap::new(), &mut undo_log)
            .expect_err("edge overflow must fail");
        assert!(edge_overflow.to_string().contains("edge id overflow"));
        db.header.edge_count = old_edge_count;

        let bad_node_undo = db
            .undo_create_node(77, txn_id)
            .expect_err("out-of-order node rollback must fail");
        assert!(bad_node_undo
            .to_string()
            .contains("node rollback out of order"));
        let bad_edge_undo = db
            .undo_create_edge(77, txn_id)
            .expect_err("out-of-order edge rollback must fail");
        assert!(bad_edge_undo
            .to_string()
            .contains("edge rollback out of order"));

        db.edge_versions = vec![VersionStamp {
            txn_id: 5,
            committed: true,
        }];
        db.header.edge_count = 1;
        db.edge_records = vec![EdgeRecord { src: 0, dst: 1 }];
        db.last_committed_txn_id = 1;
        assert_eq!(db.edge_count_at(0), 0);

        db.last_committed_txn_id = 2;
        db.node_versions.clear();
        assert_eq!(db.node_count_at(2), db.node_count());
        db.edge_versions.clear();
        assert_eq!(db.edge_count_at(2), db.edge_count());

        let _ = db
            .add_typed_edge(0, 1, "KNOWS", &PropertyMap::new())
            .expect("typed edge");
        let _ = db
            .add_edge_with_properties(0, 1, &PropertyMap::new())
            .expect("edge with props");
        let add_typed_bad = db
            .add_typed_edge(9, 9, "KNOWS", &PropertyMap::new())
            .expect_err("typed wrapper must validate nodes");
        assert!(add_typed_bad
            .to_string()
            .contains("unknown node id for edge"));
        let add_props_bad = db
            .add_edge_with_properties(9, 9, &PropertyMap::new())
            .expect_err("properties wrapper must validate nodes");
        assert!(add_props_bad
            .to_string()
            .contains("unknown node id for edge"));

        db.edge_records.clear();
        db.edge_versions = vec![VersionStamp {
            txn_id: 0,
            committed: true,
        }];
        assert_eq!(db.edge_count_at(0), 0);
        assert_eq!(
            db.neighbors_at(0, db.current_snapshot_txn_id()).unwrap(),
            vec![1, 1]
        );
        assert_eq!(
            db.incoming_neighbors_at(1, db.current_snapshot_txn_id())
                .unwrap(),
            vec![0, 0]
        );
        assert!(!db.edge_records_match_loaded_adjacency(&[EdgeRecord { src: 99, dst: 0 }]));

        db.node_property_versions[0].clear();
        let _ = db
            .node_properties_at(0, db.current_snapshot_txn_id())
            .expect("fallback node properties");

        db.edge_type_versions[0].clear();
        db.meta.edge_types.clear();
        let type_missing = db
            .edge_type_at(0, db.current_snapshot_txn_id())
            .expect_err("missing edge type metadata must fail");
        assert!(type_missing
            .to_string()
            .contains("missing edge type metadata"));

        db.edge_property_versions[0].clear();
        db.meta.edge_properties[0] = PropertyMap::new();
        db.meta.edge_properties.clear();
        let props_missing = db
            .edge_properties_at(0, db.current_snapshot_txn_id())
            .expect_err("missing edge property metadata must fail");
        assert!(props_missing
            .to_string()
            .contains("missing edge property metadata"));

        let mut chain = vec![
            VersionedValue {
                txn_id: 1,
                committed: true,
                value: 10u64,
            },
            VersionedValue {
                txn_id: 3,
                committed: true,
                value: 20u64,
            },
        ];
        Database::gc_version_chain(&mut chain, 2);
        assert_eq!(chain.last().expect("latest value").value, 20);

        db.adjacency = AdjacencyIndex::empty(db.node_count());
        db.header.edge_count = 2;
        db.initialize_mvcc_state_from_latest()
            .expect("mvcc init fallback should read edge records");
        assert_eq!(db.edge_records.len(), 2);

        db.edge_type_versions = vec![vec![VersionedValue {
            txn_id,
            committed: false,
            value: None,
        }]];
        db.edge_property_versions = vec![vec![VersionedValue {
            txn_id,
            committed: false,
            value: PropertyMap::new(),
        }]];
        db.rollback_txn(txn_id, &mut Vec::new())
            .expect("rollback without entries");

        cleanup_db_artifacts(&path);
    }

    #[test]
    fn write_transaction_validates_staged_edge_nodes() {
        let path = temp_db_path("write-tx-validate");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");

        let mut tx = db.begin_write();
        let err = tx
            .add_edge(0, 0)
            .expect_err("staged edge without projected nodes must fail");
        assert!(matches!(err, DbError::InvalidArgument(_)));
        assert!(err.to_string().contains("projected_node_count=0"));

        let typed_err = tx
            .add_typed_edge(0, 0, "KNOWS".to_string(), PropertyMap::new())
            .expect_err("typed edge without projected nodes must fail");
        assert!(matches!(typed_err, DbError::InvalidArgument(_)));
        assert!(typed_err.to_string().contains("projected_node_count=0"));

        let props_err = tx
            .add_edge_with_properties(0, 0, PropertyMap::new())
            .expect_err("edge with properties without projected nodes must fail");
        assert!(matches!(props_err, DbError::InvalidArgument(_)));
        assert!(props_err.to_string().contains("projected_node_count=0"));

        let _ = tx.create_node().expect("stage n0");
        let _ = tx.create_node().expect("stage n1");
        let edge_id = tx
            .add_edge(0, 1)
            .expect("staged edge should succeed with projected nodes");
        assert_eq!(edge_id, 0);
        tx.rollback();

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
    }

