    #[test]
    fn metrics_returns_error_when_page_layout_is_corrupt() {
        let path = temp_db_path("metrics-corrupt-pages");
        let _ = Database::init(&path, Header::default_v1()).expect("init must succeed");
        let mut file = OpenOptions::new()
            .append(true)
            .open(&path)
            .expect("open db for append");
        file.write_all(&[0xAA]).expect("append misalignment byte");
        file.sync_data().expect("sync db append");

        let db = Database::open(&path).expect("open must succeed for zero-edge misalignment");
        let err = db
            .metrics()
            .expect_err("metrics should fail on non-page-aligned file");
        assert!(matches!(err, DbError::Corrupt(_)));
        assert!(err.to_string().contains("not page-aligned"));

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
    }

    #[test]
    fn query_profiled_reports_success_and_failure_paths() {
        let path = temp_db_path("query-profiled");
        let mut db = Database::init(&path, Header::default_v1()).expect("init must succeed");
        let _ = db.create_node().expect("n0");
        let _ = db.create_node().expect("n1");

        let success = db.query_profiled("add-edge", |inner| inner.add_edge(0, 1));
        assert!(success.profile.success);
        assert_eq!(success.profile.operation, "add-edge");
        assert_eq!(success.profile.node_count_before, 2);
        assert_eq!(success.profile.edge_count_before, 0);
        assert_eq!(success.profile.node_count_after, 2);
        assert_eq!(success.profile.edge_count_after, 1);
        let (edge_id, _profile_after_unwrap) = success.into_result().expect("success result");
        assert_eq!(edge_id, 0);

        let failed = db.query_profiled("bad-add-edge", |inner| inner.add_edge(7, 8));
        assert!(!failed.profile.success);
        assert_eq!(failed.profile.operation, "bad-add-edge");
        assert_eq!(failed.profile.edge_count_before, 1);
        assert_eq!(failed.profile.edge_count_after, 1);
        let err = failed
            .into_result()
            .expect_err("failed query should return underlying error");
        assert!(matches!(err, DbError::InvalidArgument(_)));
        assert!(err.to_string().contains("unknown node id for edge"));

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
    }

    #[test]
    #[allow(clippy::approx_constant)]
    fn cypher_lexer_tokenizes_keywords_literals_symbols_and_comments() {
        let tokens = lex_cypher(
            "MaTcH (n:Person)-[r:KNOWS*1..3]->(m) WHERE n.name =~ 'A.*' AND n.age >= 21 RETURN $param, 3.14, 7 // line\n/* block */",
        )
        .expect("lexer should succeed");
        assert!(!tokens.is_empty());
        assert_eq!(tokens[0].kind, TokenKind::Keyword(CypherKeyword::Match));
        assert!(tokens
            .iter()
            .any(|token| token.kind == TokenKind::Keyword(CypherKeyword::Where)));
        assert!(tokens
            .iter()
            .any(|token| token.kind == TokenKind::Keyword(CypherKeyword::Return)));
        assert!(tokens
            .iter()
            .any(|token| token.kind == TokenKind::Operator(CypherOperator::RegexMatch)));
        assert!(tokens
            .iter()
            .any(|token| token.kind == TokenKind::Operator(CypherOperator::GreaterThanOrEqual)));
        assert!(tokens
            .iter()
            .any(|token| token.kind == TokenKind::Punctuation(CypherPunctuation::Range)));
        assert!(tokens
            .iter()
            .any(|token| token.kind == TokenKind::Parameter("param".to_string())));
        assert!(tokens
            .iter()
            .any(|token| token.kind == TokenKind::FloatLiteral(3.14)));
        assert!(tokens
            .iter()
            .any(|token| token.kind == TokenKind::IntegerLiteral(7)));
        assert_eq!(
            tokens
                .iter()
                .filter(|token| matches!(token.kind, TokenKind::Comment(_)))
                .count(),
            2
        );
    }

    #[test]
    fn cypher_lexer_reports_unterminated_string_with_position() {
        let err = lex_cypher("RETURN 'Alice").expect_err("unterminated string should fail");
        assert!(err.message.contains("unterminated string"));
        assert_eq!(err.line, 1);
        assert!(err.column >= 8);
        assert!(err.position > 0);
    }

