    fn cypher_lexer_reports_unterminated_block_comment_with_position() {
        let err = lex_cypher("MATCH (n) /* no end").expect_err("unterminated comment should fail");
        assert!(err.message.contains("unterminated block comment"));
        assert_eq!(err.line, 1);
        assert!(err.column >= 11);
        assert!(err.position > 0);
    }

    #[test]
    fn parse_cypher_handles_simple_match_return_query() {
        let ast = parse_cypher_query("MATCH (n:Person) RETURN n");
        assert_eq!(ast.clauses.len(), 1);
        let clause = expect_match_clause(&ast.clauses[0]);
        assert!(!clause.optional);
        assert!(clause.where_predicate.is_none());
        assert_eq!(clause.patterns.len(), 1);
        let pattern = &clause.patterns[0];
        assert_eq!(pattern.start.variable.as_deref(), Some("n"));
        assert_eq!(pattern.start.labels, vec!["Person".to_string()]);
        assert!(pattern.start.properties.is_none());
        assert!(pattern.chains.is_empty());

        let return_clause = ast.return_clause.expect("return clause");
        assert!(!return_clause.distinct);
        assert_eq!(return_clause.items.len(), 1);
        assert!(matches!(
            return_clause.items[0].expression,
            CypherExpression::Identifier(ref value) if value == "n"
        ));
        assert!(return_clause.items[0].alias.is_none());
        assert!(return_clause.order_by.is_empty());
        assert!(return_clause.skip.is_none());
        assert!(return_clause.limit.is_none());
    }

    #[test]
    fn parse_cypher_handles_match_where_and_relationship_pattern() {
        let ast =
            parse_cypher_query("MATCH (a)-[r:KNOWS]->(b) WHERE a.name = 'Alice' RETURN b.name");
        assert_eq!(ast.clauses.len(), 1);
        let match_clause = expect_match_clause(&ast.clauses[0]);
        assert_eq!(match_clause.patterns.len(), 1);
        let pattern = &match_clause.patterns[0];
        assert_eq!(pattern.start.variable.as_deref(), Some("a"));
        assert_eq!(pattern.chains.len(), 1);
        let chain = &pattern.chains[0];
        assert_eq!(chain.relationship.variable.as_deref(), Some("r"));
        assert_eq!(chain.relationship.rel_type.as_deref(), Some("KNOWS"));
        assert_eq!(
            chain.relationship.direction,
            RelationshipDirection::LeftToRight
        );
        assert!(chain.relationship.length.is_none());
        assert_eq!(chain.node.variable.as_deref(), Some("b"));

        let where_expr = match_clause
            .where_predicate
            .as_ref()
            .expect("WHERE predicate");
        assert!(matches!(
            where_expr,
            CypherExpression::BinaryOp {
                op: CypherBinaryOperator::Eq,
                ..
            }
        ));

        let return_clause = ast.return_clause.expect("RETURN clause");
        assert_eq!(return_clause.items.len(), 1);
        assert!(matches!(
            return_clause.items[0].expression,
            CypherExpression::PropertyAccess { .. }
        ));
    }

