    #[test]
    fn parse_cypher_handles_return_order_skip_and_limit() {
        let ast = parse_cypher_query(
            "MATCH (n) WHERE n.age > 25 RETURN n.name AS name ORDER BY n.name DESC SKIP 2 LIMIT 10",
        );
        assert_eq!(ast.clauses.len(), 1);
        let return_clause = ast.return_clause.expect("return clause");
        assert_eq!(return_clause.items.len(), 1);
        assert_eq!(return_clause.items[0].alias.as_deref(), Some("name"));
        assert_eq!(return_clause.order_by.len(), 1);
        assert!(return_clause.order_by[0].descending);
        assert_eq!(return_clause.skip, Some(2));
        assert_eq!(return_clause.limit, Some(10));
    }

    #[test]
    fn parse_cypher_handles_relationship_length_ranges() {
        let ast = parse_cypher_query("MATCH (a:Person)-[:FRIENDS_WITH*1..3]->(b) RETURN b");
        let match_clause = expect_match_clause(&ast.clauses[0]);
        let rel = &match_clause.patterns[0].chains[0].relationship;
        assert_eq!(rel.rel_type.as_deref(), Some("FRIENDS_WITH"));
        let length = rel.length.as_ref().expect("relationship length");
        assert_eq!(length.min_hops, Some(1));
        assert_eq!(length.max_hops, Some(3));
    }

