    #[test]
    fn parse_cypher_handles_with_clause_and_where_predicate() {
        let ast =
            parse_cypher_query("MATCH (n) WITH n AS person WHERE person.age > 18 RETURN person");
        assert_eq!(ast.clauses.len(), 2);
        let with_clause = expect_with_clause(&ast.clauses[1]);
        assert_eq!(with_clause.items.len(), 1);
        assert_eq!(with_clause.items[0].alias.as_deref(), Some("person"));
        assert!(with_clause.where_predicate.is_some());
    }

