    #[test]
    fn parse_cypher_applies_not_comparison_and_or_xor_precedence() {
        let ast = parse_cypher_query("MATCH (n) WHERE a XOR b OR c AND NOT d = e RETURN n");
        let match_clause = expect_match_clause(&ast.clauses[0]);
        let root = match_clause.where_predicate.as_ref().expect("where");
        let (_, or_expr) = expect_binary_expr(root, CypherBinaryOperator::Xor);
        let (_, and_expr) = expect_binary_expr(or_expr, CypherBinaryOperator::Or);
        let (_, comparison_expr) = expect_binary_expr(and_expr, CypherBinaryOperator::And);
        let (unary_not_expr, _) = expect_binary_expr(comparison_expr, CypherBinaryOperator::Eq);
        assert!(matches!(
            unary_not_expr,
            CypherExpression::UnaryOp {
                op: CypherUnaryOperator::Not,
                ..
            }
        ));
    }

    #[test]
    fn parse_cypher_handles_list_comprehension_case_and_exists_subquery() {
        let ast = parse_cypher_query(
            "MATCH (n) WHERE EXISTS { MATCH (n)-[:KNOWS]->(m) RETURN m } RETURN [x IN [1, 2, 3] WHERE x > 1 | x * 2] AS xs, CASE WHEN n.age > 30 THEN 'old' ELSE 'young' END AS bucket",
        );
        let match_clause = expect_match_clause(&ast.clauses[0]);
        assert!(matches!(
            match_clause.where_predicate,
            Some(CypherExpression::ExistsSubquery { .. })
        ));

        let return_clause = ast.return_clause.expect("return clause");
        assert_eq!(return_clause.items.len(), 2);
        assert!(matches!(
            return_clause.items[0].expression,
            CypherExpression::ListComprehension { .. }
        ));
        assert!(matches!(
            return_clause.items[1].expression,
            CypherExpression::CaseExpression { .. }
        ));
    }

