    #[test]
    fn cypher_lexer_additional_paths_cover_keywords_symbols_and_display() {
        let whitespace_only = lex_cypher(" \n\t ").expect("whitespace-only lexer input");
        assert!(whitespace_only.is_empty());

        let missing_param = lex_cypher("$").expect_err("missing parameter name should fail");
        assert!(missing_param.message.contains("parameter name"));

        let escaped = lex_cypher("'a\\n\\r\\t\\\\\\'\\\"' \"b\\\"\" 'u\\x' + - * / = <> < > <= >= =~ . , ( ) [ ] { } : | .. 10 2.5")
            .expect("escaped literals and symbols should lex");
        assert!(escaped
            .iter()
            .any(|token| token.kind == TokenKind::StringLiteral("a\n\r\t\\'\"".to_string())));
        assert!(escaped
            .iter()
            .any(|token| token.kind == TokenKind::StringLiteral("b\"".to_string())));
        assert!(escaped
            .iter()
            .any(|token| token.kind == TokenKind::StringLiteral("ux".to_string())));
        assert!(escaped
            .iter()
            .any(|token| token.kind == TokenKind::IntegerLiteral(10)));
        assert!(escaped
            .iter()
            .any(|token| token.kind == TokenKind::FloatLiteral(2.5)));

        let keyword_text = "MATCH WHERE RETURN CREATE DELETE SET REMOVE WITH ORDER BY LIMIT SKIP OPTIONAL MERGE ON AS AND OR XOR NOT IN IS NULL TRUE FALSE DISTINCT UNION ALL EXISTS CASE WHEN THEN ELSE END DESC ASC DETACH UNWIND CALL YIELD";
        let keyword_tokens = lex_cypher(keyword_text).expect("all keywords should lex");
        let expected_keywords = [
            CypherKeyword::Match,
            CypherKeyword::Where,
            CypherKeyword::Return,
            CypherKeyword::Create,
            CypherKeyword::Delete,
            CypherKeyword::Set,
            CypherKeyword::Remove,
            CypherKeyword::With,
            CypherKeyword::Order,
            CypherKeyword::By,
            CypherKeyword::Limit,
            CypherKeyword::Skip,
            CypherKeyword::Optional,
            CypherKeyword::Merge,
            CypherKeyword::On,
            CypherKeyword::As,
            CypherKeyword::And,
            CypherKeyword::Or,
            CypherKeyword::Xor,
            CypherKeyword::Not,
            CypherKeyword::In,
            CypherKeyword::Is,
            CypherKeyword::Null,
            CypherKeyword::True,
            CypherKeyword::False,
            CypherKeyword::Distinct,
            CypherKeyword::Union,
            CypherKeyword::All,
            CypherKeyword::Exists,
            CypherKeyword::Case,
            CypherKeyword::When,
            CypherKeyword::Then,
            CypherKeyword::Else,
            CypherKeyword::End,
            CypherKeyword::Desc,
            CypherKeyword::Asc,
            CypherKeyword::Detach,
            CypherKeyword::Unwind,
            CypherKeyword::Call,
            CypherKeyword::Yield,
        ];
        for keyword in expected_keywords {
            assert!(keyword_tokens
                .iter()
                .any(|token| { token.kind == TokenKind::Keyword(keyword) }));
        }

        let mut digit_prefixed_ident = "1abc";
        assert!(parse_identifier_fragment(&mut digit_prefixed_ident).is_none());

        let numeric_err = parse_numeric_literal("x", "abc", 0)
            .expect_err("numeric parser should fail on non-digits");
        assert!(numeric_err.message.contains("numeric literal"));
        let huge_int_err = lex_cypher("999999999999999999999999999999")
            .expect_err("overflowing integer literal should fail");
        assert!(huge_int_err
            .message
            .contains("integer literal out of range"));

        for (text, keyword) in [
            ("MATCH", CypherKeyword::Match),
            ("RETURN", CypherKeyword::Return),
            ("WITH", CypherKeyword::With),
            ("XOR", CypherKeyword::Xor),
            ("YIELD", CypherKeyword::Yield),
        ] {
            assert_eq!(keyword_from_identifier(text), Some(keyword));
        }
        assert_eq!(keyword_from_identifier("NOT_A_KEYWORD"), None);

        let display = ParseError::new("a\nb", 2, "boom").to_string();
        assert!(display.contains("boom"));
        assert!(display.contains("line 2, column 1"));
    }

    #[test]
    fn cypher_parser_additional_success_and_error_paths_cover_branches() {
        let optional_ast = parse_cypher_query("OPTIONAL MATCH (n) RETURN n");
        let clause = expect_match_clause(&optional_ast.clauses[0]);
        assert!(clause.optional);

        let with_ast = parse_cypher_query("WITH DISTINCT n RETURN n ORDER BY n ASC");
        let clause = expect_with_clause(&with_ast.clauses[0]);
        assert!(clause.distinct);
        assert!(clause.where_predicate.is_none());
        let with_return = with_ast.return_clause.expect("WITH query return clause");
        assert_eq!(with_return.order_by.len(), 1);
        assert!(!with_return.order_by[0].descending);

        let multi_order = parse_cypher_query("RETURN n ORDER BY n ASC, n DESC");
        let multi_order_return = multi_order.return_clause.expect("multi-order return");
        assert_eq!(multi_order_return.order_by.len(), 2);

        let multi_pattern = parse_cypher_query("MATCH (a), (b) RETURN a");
        assert_eq!(
            expect_match_clause(&multi_pattern.clauses[0])
                .patterns
                .len(),
            2
        );

        let empty_props = parse_cypher_query("CREATE (:Person {})");
        let node = &expect_create_clause(&empty_props.clauses[0]).patterns[0].start;
        assert!(node.variable.is_none());
        assert_eq!(node.properties.as_ref().expect("empty map").len(), 0);

        let rel_variants = parse_cypher_query(
            "MATCH (a)<-[r:KNOWS]-(b), (x)-[s]-(y), (m)-[t:REL*..3 {v: 1}]-(n), (p)-[:REL*]->(q), (u)-[:REL*5]->(v), (k)-[:REL*1..]->(l) RETURN r, s, t",
        );
        let clause = expect_match_clause(&rel_variants.clauses[0]);
        assert_eq!(
            clause.patterns[0].chains[0].relationship.direction,
            RelationshipDirection::RightToLeft
        );
        assert_eq!(
            clause.patterns[1].chains[0].relationship.direction,
            RelationshipDirection::Undirected
        );
        let rel = &clause.patterns[2].chains[0].relationship;
        let length = rel.length.as_ref().expect("range length");
        assert_eq!(length.min_hops, None);
        assert_eq!(length.max_hops, Some(3));
        assert!(rel.properties.is_some());
        let star_rel = &clause.patterns[3].chains[0].relationship;
        let star_length = star_rel.length.as_ref().expect("star length");
        assert_eq!(star_length.min_hops, None);
        assert_eq!(star_length.max_hops, None);
        let exact_rel = &clause.patterns[4].chains[0].relationship;
        let exact_length = exact_rel.length.as_ref().expect("exact length");
        assert_eq!(exact_length.min_hops, Some(5));
        assert_eq!(exact_length.max_hops, Some(5));
        let open_ended_rel = &clause.patterns[5].chains[0].relationship;
        let open_ended_length = open_ended_rel.length.as_ref().expect("open-ended length");
        assert_eq!(open_ended_length.min_hops, Some(1));
        assert_eq!(open_ended_length.max_hops, None);

        let bracket_relationship = parse_cypher_query("MATCH (a)-[r]->(b) RETURN a");
        assert_eq!(
            expect_match_clause(&bracket_relationship.clauses[0]).patterns[0].chains[0]
                .relationship
                .variable
                .as_deref(),
            Some("r")
        );

        let delete_many = parse_cypher_query("MATCH (a), (b) DELETE a, b");
        assert_eq!(
            expect_delete_clause(&delete_many.clauses[1])
                .expressions
                .len(),
            2
        );

        let comparisons = parse_cypher_query(
            "MATCH (n) WHERE a <> b AND a < b AND a > b AND a <= b AND a >= b AND a =~ 'x' AND a IN [1] AND a IS NULL AND a IS NOT NULL RETURN n",
        );
        assert!(expect_match_clause(&comparisons.clauses[0])
            .where_predicate
            .is_some());

        let expression_variants = parse_cypher_query(
            "RETURN -1 + +2 / 1 - 3, NULL, TRUE, FALSE, 3.14, (1 + 2), {a: 1}, timestamp(), coalesce(a, b), [x IN [1,2,3]], [x, 1], [], CASE n.age WHEN 1 THEN 'one' END",
        );
        let return_clause = expression_variants
            .return_clause
            .expect("expression variants return");
        assert_eq!(return_clause.items.len(), 13);

        let exists_nested = parse_cypher_query("MATCH (n) WHERE EXISTS { RETURN {a: 1} } RETURN n");
        assert!(matches!(
            expect_match_clause(&exists_nested.clauses[0]).where_predicate,
            Some(CypherExpression::ExistsSubquery { .. })
        ));

        let optional_missing_match = parse_cypher_query_err("OPTIONAL (n) RETURN n");
        assert!(optional_missing_match.message.contains("expected keyword"));
        let bad_clause = parse_cypher_query_err("TRUE");
        assert!(bad_clause
            .message
            .contains("unexpected token while parsing clause"));
        let bad_set_target = parse_cypher_query_err("MATCH (n) SET 1 = 2 RETURN n");
        assert!(bad_set_target.message.contains("left side of SET"));
        let merge_on_error = parse_cypher_query_err("MERGE (n) ON WHERE SET n.x = 1 RETURN n");
        assert!(merge_on_error.message.contains("CREATE or MATCH"));
        let bad_incoming = parse_cypher_query_err("MATCH (a)<-[r]->(b) RETURN a");
        assert!(bad_incoming.message.contains("unexpected '>'"));
        let case_error = parse_cypher_query_err("RETURN CASE n.age END");
        assert!(case_error.message.contains("requires at least one WHEN"));
        let exists_error = parse_cypher_query_err("MATCH (n) WHERE EXISTS { RETURN n");
        assert!(exists_error.message.contains("close EXISTS subquery"));
        let overflow_len = parse_cypher_query_err("MATCH (a)-[:REL*4294967296]->(b) RETURN b");
        assert!(overflow_len.message.contains("out of range"));
        let missing_right_paren = parse_cypher_query_err("RETURN (1");
        assert!(missing_right_paren.message.contains("RightParen"));
        let missing_operator = parse_cypher_query_err("MATCH (a)<[r]-(b) RETURN a");
        assert!(missing_operator.message.contains("expected operator"));
        let expected_expression = parse_cypher_query_err("RETURN )");
        assert!(expected_expression.message.contains("expected expression"));
        let empty_query = parse_cypher_query_err(" \n\t");
        assert!(empty_query.message.contains("empty query"));
    }

    #[test]
    fn cypher_parser_internal_helpers_cover_remaining_error_paths() {
        let span = SourceSpan {
            start: 0,
            end: 1,
            line: 1,
            column: 1,
        };
        let token = |kind: TokenKind| Token { kind, span };

        let mut parser = CypherParser::from_tokens("", vec![]);
        let keyword_err = parser
            .expect_keyword(CypherKeyword::Match)
            .expect_err("keyword expectation should fail");
        assert!(keyword_err.message.contains("expected keyword"));
        let op_err = parser
            .expect_operator(CypherOperator::Eq)
            .expect_err("operator expectation should fail");
        assert!(op_err.message.contains("expected operator"));
        let punct_err = parser
            .expect_punctuation(CypherPunctuation::RightParen)
            .expect_err("punctuation expectation should fail");
        assert!(punct_err.message.contains("expected punctuation"));

        let mut parser = CypherParser::from_tokens("", vec![token(TokenKind::IntegerLiteral(-1))]);
        let non_negative = parser
            .parse_non_negative_integer("for SKIP")
            .expect_err("negative integer should fail");
        assert!(non_negative.message.contains("non-negative"));

        let mut parser = CypherParser::from_tokens(
            "",
            vec![token(TokenKind::IntegerLiteral(i64::from(u32::MAX) + 1))],
        );
        let u32_err = parser
            .parse_u32_literal("for relationship length")
            .expect_err("u32 overflow should fail");
        assert!(u32_err.message.contains("out of range"));

        let mut parser =
            CypherParser::from_tokens("", vec![token(TokenKind::Identifier("x".into()))]);
        let int_err = parser
            .parse_i64_literal("for test")
            .expect_err("missing integer should fail");
        assert!(int_err.message.contains("expected integer literal"));

        let mut parser =
            CypherParser::from_tokens("", vec![token(TokenKind::Keyword(CypherKeyword::Match))]);
        let ident_err = parser
            .parse_identifier("for test")
            .expect_err("missing identifier should fail");
        assert!(ident_err.message.contains("expected identifier"));

        let mut parser = CypherParser::from_tokens("", vec![token(TokenKind::FloatLiteral(9.5))]);
        assert_eq!(parser.match_float_literal(), Some(9.5));
        assert_eq!(parser.match_float_literal(), None);

        let parser = CypherParser::from_tokens(
            "x",
            vec![Token {
                kind: TokenKind::Identifier("x".to_string()),
                span,
            }],
        );
        let at_token = parser.error_here("boom");
        assert_eq!(at_token.position, 0);
        let at_eof = CypherParser::from_tokens("", vec![]).error_here("boom");
        assert_eq!(at_eof.position, 0);
    }

    #[test]
    fn cypher_semantic_analysis_resolves_catalog_bindings_and_infers_types() {
        let path = temp_db_path("cypher-semantic-bindings");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");
        let person = db
            .create_node_with(
                &["Person".to_string()],
                &PropertyMap::from([("age".to_string(), PropertyValue::I64(42))]),
            )
            .expect("person node");
        let other = db
            .create_node_with(
                &["Person".to_string()],
                &PropertyMap::from([("name".to_string(), PropertyValue::String("B".to_string()))]),
            )
            .expect("other node");
        let _ = db
            .add_typed_edge(
                person,
                other,
                "KNOWS",
                &PropertyMap::from([("since".to_string(), PropertyValue::I64(2020))]),
            )
            .expect("typed edge");

        let model = analyze_cypher_query(
            &db,
            "MATCH (a:Person)-[r:KNOWS]->(b:Ghost) WHERE a.age >= 21 RETURN a.age = 42 AS ok, b.name AS name",
        )
        .expect("semantic analysis should succeed");

        assert!(model
            .warnings
            .iter()
            .any(|warning| warning.contains("unknown label") && warning.contains("Ghost")));
        assert!(model
            .catalog_bindings
            .labels
            .iter()
            .any(|binding| binding.name == "Person" && binding.exists));
        assert!(model
            .catalog_bindings
            .labels
            .iter()
            .any(|binding| binding.name == "Ghost" && !binding.exists));
        assert!(model
            .catalog_bindings
            .edge_types
            .iter()
            .any(|binding| binding.name == "KNOWS" && binding.exists));
        assert!(model
            .catalog_bindings
            .property_keys
            .iter()
            .any(|binding| binding.name == "age" && binding.exists));
        assert!(model
            .catalog_bindings
            .property_keys
            .iter()
            .any(|binding| binding.name == "name" && binding.exists));
        assert!(model
            .expression_types
            .iter()
            .any(|entry| entry.inferred_type == SemanticType::PropertyValue));
        assert!(model
            .expression_types
            .iter()
            .any(|entry| entry.inferred_type == SemanticType::Boolean));
        assert!(!model.scope_bindings.is_empty());
        assert!(model.scope_bindings[0]
            .bound_variables
            .iter()
            .any(|name| name == "a"));
        assert!(model.scope_bindings[0]
            .bound_variables
            .iter()
            .any(|name| name == "b"));
        assert!(model.scope_bindings[0]
            .bound_variables
            .iter()
            .any(|name| name == "r"));

        cleanup_db_artifacts(&path);
    }

