    #[test]
    fn cypher_physical_plan_uses_real_cardinality_and_join_strategy() {
        let path = temp_db_path("cypher-physical-plan");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");
        let labels = ["Person".to_string()];
        let n0 = db
            .create_node_with(
                &labels,
                &PropertyMap::from([("age".to_string(), PropertyValue::I64(10))]),
            )
            .expect("n0");
        let n1 = db
            .create_node_with(
                &labels,
                &PropertyMap::from([("age".to_string(), PropertyValue::I64(20))]),
            )
            .expect("n1");
        let n2 = db
            .create_node_with(
                &labels,
                &PropertyMap::from([("age".to_string(), PropertyValue::I64(30))]),
            )
            .expect("n2");
        let _ = db
            .add_typed_edge(n0, n1, "KNOWS", &PropertyMap::new())
            .expect("edge 1");
        let _ = db
            .add_typed_edge(n1, n2, "KNOWS", &PropertyMap::new())
            .expect("edge 2");

        let ast = db
            .parse_cypher("MATCH (a:Person)-[:KNOWS]->(b) RETURN a, b")
            .expect("parse");
        let semantic = db.analyze_cypher(&ast).expect("analyze");
        let logical = db.plan_cypher(&semantic).expect("logical");
        let physical = db.physical_plan_cypher(&logical).expect("physical");

        let (scan_strategy, scan_label) =
            physical_scan_parts(&physical).expect("scan operator should exist");
        assert_eq!(scan_strategy, PhysicalScanStrategy::IndexScan);
        assert_eq!(scan_label, Some("Person"));
        assert!(matches!(
            physical_expand_parts(&physical),
            Some(PhysicalJoinStrategy::NestedLoop) | Some(PhysicalJoinStrategy::HashJoin)
        ));
        assert!(physical.estimated_cost() > 0.0);
        assert!(physical.estimated_rows() > 0);

        cleanup_db_artifacts(&path);
    }

