    #[test]
    fn cypher_match_with_two_patterns_filters_before_create() {
        let path = temp_db_path("cypher-match-two-pattern-create");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");

        db.query("CREATE (p:Person {name: 'Alice', age: 30})")
            .expect("create alice");
        db.query("CREATE (p:Person {name: 'Bob', age: 35})")
            .expect("create bob");
        db.query("CREATE (p:Person {name: 'Charlie', age: 28})")
            .expect("create charlie");
        db.query("CREATE (p:Person {name: 'Diana', age: 32})")
            .expect("create diana");
        db.query("CREATE (c:Company {name: 'TechCorp'})")
            .expect("create company");

        let filtered = db
            .query("MATCH (p:Person {name: 'Alice'}) RETURN p.name AS name, p.age AS age")
            .expect("single filtered match")
            .to_rows();
        assert_eq!(filtered.len(), 1);
        assert_eq!(
            filtered[0].get("name"),
            Some(&PropertyValue::String("Alice".to_string()))
        );
        assert_eq!(filtered[0].get("age"), Some(&PropertyValue::I64(30)));

        let pair_rows = db
            .query(
                "MATCH (a:Person {name: 'Alice'}), (c:Company {name: 'TechCorp'}) RETURN a.name AS a_name, c.name AS c_name",
            )
            .expect("two-pattern filtered match")
            .to_rows();
        assert_eq!(pair_rows.len(), 1);
        assert_eq!(
            pair_rows[0].get("a_name"),
            Some(&PropertyValue::String("Alice".to_string()))
        );
        assert_eq!(
            pair_rows[0].get("c_name"),
            Some(&PropertyValue::String("TechCorp".to_string()))
        );

        let create_rows = db
            .query(
                "MATCH (a:Person {name: 'Alice'}), (c:Company {name: 'TechCorp'}) CREATE (a)-[:WORKS_AT]->(c)",
            )
            .expect("match + create")
            .to_rows();
        assert_eq!(create_rows.len(), 1);
        assert_eq!(db.node_count(), 5);
        assert_eq!(db.edge_count(), 1);

        let works_at_rows = db
            .query(
                "MATCH (p:Person)-[:WORKS_AT]->(c:Company) RETURN p.name AS p_name, c.name AS c_name",
            )
            .expect("traverse created edge")
            .to_rows();
        assert_eq!(works_at_rows.len(), 1);
        assert_eq!(
            works_at_rows[0].get("p_name"),
            Some(&PropertyValue::String("Alice".to_string()))
        );
        assert_eq!(
            works_at_rows[0].get("c_name"),
            Some(&PropertyValue::String("TechCorp".to_string()))
        );

        cleanup_db_artifacts(&path);
    }

