    #[test]
    fn shared_database_supports_multi_reader_and_blocks_writer_until_snapshot_drop() {
        let path = temp_db_path("shared-reader-writer");
        let shared = SharedDatabase::init(&path, Header::default_v1()).expect("init shared");
        let seed_node = |db: &mut Database| -> Result<(), DbError> {
            let _ = db.create_node()?;
            Ok(())
        };
        shared.with_write(seed_node).expect("seed node");
        assert_with_write_lock_poisoned(seed_node);

        let snapshot = shared.read_snapshot().expect("primary snapshot");

        let shared_for_reader = shared.clone();
        let reader_handle = thread::spawn(move || {
            let second_snapshot = shared_for_reader
                .read_snapshot()
                .expect("secondary snapshot");
            second_snapshot.node_count()
        });
        let secondary_count = reader_handle.join().expect("reader join");
        assert_eq!(secondary_count, 1);

        let shared_for_writer = shared.clone();
        let (started_tx, started_rx) = mpsc::channel::<()>();
        let (done_tx, done_rx) = mpsc::channel::<Result<u64, DbError>>();
        let writer = |db: &mut Database| -> Result<u64, DbError> {
            let _ = db.create_node()?;
            Ok(db.node_count())
        };
        let writer_for_poison = writer;
        let writer_handle = thread::spawn(move || {
            started_tx.send(()).expect("send started");
            let outcome = shared_for_writer.with_write(writer);
            done_tx.send(outcome).expect("send write outcome");
        });

        started_rx
            .recv_timeout(Duration::from_secs(1))
            .expect("writer should start");
        assert!(done_rx.recv_timeout(Duration::from_millis(100)).is_err());
        drop(snapshot);

        let write_outcome = done_rx
            .recv_timeout(Duration::from_secs(1))
            .expect("writer should complete after snapshot release")
            .expect("writer should succeed");
        assert_eq!(write_outcome, 2);
        writer_handle.join().expect("writer join");
        assert_with_write_lock_poisoned(writer_for_poison);

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
    }

