    #[test]
    fn shared_database_timeout_methods_report_lock_acquisition_timeouts() {
        let path = temp_db_path("shared-timeout-contention");
        let shared = SharedDatabase::init(&path, Header::default_v1()).expect("init shared");
        let seed_node = |db: &mut Database| -> Result<(), DbError> {
            let _ = db.create_node()?;
            Ok(())
        };
        shared.with_write(seed_node).expect("seed node");
        assert_with_write_lock_poisoned(seed_node);
        shared
            .with_write_timeout(Duration::from_millis(1), ok_write)
            .expect("write with timeout before contention");
        shared
            .with_write_transaction_timeout(Duration::from_millis(1), ok_write_tx)
            .expect("write transaction with timeout before contention");

        let read_snapshot = shared.read_snapshot().expect("hold read lock");
        let write_err = shared
            .with_write_timeout(Duration::from_millis(1), ok_write)
            .expect_err("write lock should time out while read snapshot is held");
        assert_timeout(&write_err);
        assert!(write_err
            .to_string()
            .contains("write lock acquisition exceeded"));

        let write_tx_err = shared
            .with_write_transaction_timeout(Duration::from_millis(1), ok_write_tx)
            .expect_err("write transaction lock should time out while read snapshot is held");
        assert_timeout(&write_tx_err);
        assert!(write_tx_err
            .to_string()
            .contains("write transaction lock acquisition exceeded"));
        drop(read_snapshot);

        let write_guard = shared.inner.write().expect("acquire write lock");
        let read_err = shared
            .read_snapshot_with_timeout(Duration::from_millis(1))
            .expect_err("read lock should time out while write lock is held");
        assert_timeout(&read_err);
        assert!(read_err
            .to_string()
            .contains("read snapshot lock acquisition exceeded"));
        drop(write_guard);

        fs::remove_file(&path).expect("cleanup db");
        fs::remove_file(wal_path_for_db(&path)).expect("cleanup wal");
    }

