    #[test]
    fn shared_database_multi_writer_retry_replays_aborted_transaction() {
        let path = temp_db_path("shared-multi-writer-retry");
        let shared = SharedDatabase::init_with_write_mode(
            &path,
            Header::default_v1(),
            WriteConcurrencyMode::MultiWriter { max_retries: 2 },
        )
        .expect("init shared");
        shared
            .with_write(|db| {
                let _ = db.create_node_with(
                    &["Person".to_string()],
                    &PropertyMap::from([(
                        "name".to_string(),
                        PropertyValue::String("seed".to_string()),
                    )]),
                )?;
                Ok(())
            })
            .expect("seed node");

        let attempts = Arc::new(std::sync::atomic::AtomicUsize::new(0));
        let stale_snapshot = shared
            .read_snapshot()
            .expect("stale snapshot")
            .snapshot_txn_id();
        shared
            .with_write_transaction_from_snapshot_for_tests(stale_snapshot, |mut tx| {
                tx.set_node_properties(
                    0,
                    PropertyMap::from([(
                        "name".to_string(),
                        PropertyValue::String("first".to_string()),
                    )]),
                )?;
                tx.commit()
            })
            .expect("first writer commit");

        let attempts_b = attempts.clone();
        shared
            .with_write_transaction_retry_from_snapshot_for_tests(stale_snapshot, 2, |mut tx| {
                attempts_b.fetch_add(1, std::sync::atomic::Ordering::SeqCst);
                tx.set_node_properties(
                    0,
                    PropertyMap::from([(
                        "name".to_string(),
                        PropertyValue::String("second".to_string()),
                    )]),
                )?;
                tx.commit()
            })
            .expect("writer commit after retry");
        assert!(
            attempts.load(std::sync::atomic::Ordering::SeqCst) >= 2,
            "expected retry attempt"
        );

        let props = shared
            .read_snapshot()
            .expect("snapshot")
            .node_properties(0)
            .expect("node properties");
        assert_eq!(
            props.get("name"),
            Some(&PropertyValue::String("second".to_string()))
        );

        cleanup_db_artifacts(&path);
    }

    #[test]
    fn shared_database_replication_replays_wal_to_follower() {
        let leader_path = temp_db_path("replication-leader");
        let follower_path = temp_db_path("replication-follower");
        let leader = SharedDatabase::init(&leader_path, Header::default_v1()).expect("init leader");
        let follower =
            SharedDatabase::init(&follower_path, Header::default_v1()).expect("init follower");

        let mut source = leader
            .start_replication_source("127.0.0.1:0")
            .expect("start replication source");
        let mut sink = follower
            .connect_replica(&source.local_addr())
            .expect("connect replica");

        leader
            .with_write(|db| {
                let _ = db.create_node_with(
                    &["Person".to_string()],
                    &PropertyMap::from([(
                        "name".to_string(),
                        PropertyValue::String("Alice".to_string()),
                    )]),
                )?;
                let _ = db.create_node_with(
                    &["Person".to_string()],
                    &PropertyMap::from([(
                        "name".to_string(),
                        PropertyValue::String("Bob".to_string()),
                    )]),
                )?;
                let _ = db.add_typed_edge(
                    0,
                    1,
                    "KNOWS",
                    &PropertyMap::from([("since".to_string(), PropertyValue::I64(2024))]),
                )?;
                Ok(())
            })
            .expect("seed leader graph");

        let deadline = Instant::now() + Duration::from_secs(5);
        loop {
            let snapshot = follower.read_snapshot().expect("follower snapshot");
            if snapshot.node_count() == 2 && snapshot.edge_count() == 1 {
                assert_eq!(snapshot.neighbors(0).expect("follower neighbors"), vec![1]);
                break;
            }
            if Instant::now() >= deadline {
                panic!("follower did not catch up to leader before timeout");
            }
            drop(snapshot);
            thread::sleep(Duration::from_millis(10));
        }

        sink.stop().expect("stop replica sink");
        source.stop().expect("stop replication source");
        cleanup_db_artifacts(&leader_path);
        cleanup_db_artifacts(&follower_path);
    }

