    #[test]
    fn temporal_datetime_helpers_parse_timezone_offsets() {
        let (z_micros, z_offset) =
            parse_datetime_literal("2026-01-15T09:00:00Z").expect("parse zulu datetime");
        assert_eq!(z_offset, 0);
        assert_eq!(
            micros_to_datetime_string(z_micros, z_offset),
            "2026-01-15T09:00:00Z"
        );

        let (plus_micros, plus_offset) =
            parse_datetime_literal("2026-01-15T09:00:00+05:30").expect("parse offset datetime");
        assert_eq!(plus_offset, 330);
        assert_eq!(
            micros_to_datetime_string(plus_micros, plus_offset),
            "2026-01-15T09:00:00+05:30"
        );

        let (shifted_utc_micros, shifted_utc_offset) =
            parse_datetime_literal("2026-01-15T03:30:00Z").expect("parse shifted utc");
        assert_eq!(shifted_utc_offset, 0);
        assert_eq!(plus_micros, shifted_utc_micros);

        let (minus_micros, minus_offset) = parse_datetime_literal("2026-01-15T09:00:00-02:30")
            .expect("parse negative offset datetime");
        assert_eq!(minus_offset, -150);
        assert_eq!(
            micros_to_datetime_string(minus_micros, minus_offset),
            "2026-01-15T09:00:00-02:30"
        );
    }

