    #[test]
    fn cypher_duration_literals_arithmetic_and_round_trip_storage() {
        let path = temp_db_path("duration-literals-roundtrip");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");

        // Seed graph so standalone RETURN produces rows
        db.query("CREATE (n:Seed)").expect("seed node");

        // duration() function
        let result = db
            .query("RETURN duration('P1Y2M') AS d")
            .expect("query duration literal")
            .to_rows()
            .pop()
            .expect("row");
        assert_eq!(
            result.get("d"),
            Some(&PropertyValue::Duration {
                months: 14,
                days: 0,
                nanos: 0
            })
        );

        // duration + duration
        let add_result = db
            .query("RETURN duration('P1Y2M') + duration('P3D') AS d")
            .expect("query duration add")
            .to_rows()
            .pop()
            .expect("row");
        assert_eq!(
            add_result.get("d"),
            Some(&PropertyValue::Duration {
                months: 14,
                days: 3,
                nanos: 0
            })
        );

        // duration - duration
        let sub_result = db
            .query("RETURN duration('P1Y2M') - duration('P6M') AS d")
            .expect("query duration sub")
            .to_rows()
            .pop()
            .expect("row");
        assert_eq!(
            sub_result.get("d"),
            Some(&PropertyValue::Duration {
                months: 8,
                days: 0,
                nanos: 0
            })
        );

        // Storage round-trip
        let _ = db
            .create_node_with(
                &["Event".to_string()],
                &PropertyMap::from([(
                    "dur".to_string(),
                    PropertyValue::Duration {
                        months: 14,
                        days: 3,
                        nanos: 0,
                    },
                )]),
            )
            .expect("create event with duration");

        let before = db
            .query("MATCH (e:Event) RETURN e.dur AS dur")
            .expect("query before reopen")
            .to_rows();
        assert_eq!(
            before[0].get("dur"),
            Some(&PropertyValue::Duration {
                months: 14,
                days: 3,
                nanos: 0
            })
        );
        drop(db);

        let mut reopened = Database::open(&path).expect("reopen");
        let after = reopened
            .query("MATCH (e:Event) RETURN e.dur AS dur")
            .expect("query after reopen")
            .to_rows();
        assert_eq!(after, before);
        cleanup_db_artifacts(&path);
    }

