    #[test]
    fn index_lifecycle_validation_and_missing_index_planning_paths() {
        let path = temp_db_path("index-validation");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");
        let _ = db
            .create_node_with(
                &["Doc".to_string()],
                &PropertyMap::from([
                    (
                        "name".to_string(),
                        PropertyValue::String("Alice".to_string()),
                    ),
                    (
                        "embedding".to_string(),
                        PropertyValue::Vector(vec![1.0, 0.0, 0.0]),
                    ),
                ]),
            )
            .expect("create node");

        db.create_vector_index(
            "embedding_idx",
            Some("Doc"),
            "embedding",
            3,
            VectorDistanceMetric::Cosine,
        )
        .expect("create vector index");
        db.create_vector_index(
            "embedding_idx",
            Some("Doc"),
            "embedding",
            3,
            VectorDistanceMetric::Cosine,
        )
        .expect("duplicate vector index is idempotent");
        assert_eq!(db.list_vector_indexes().len(), 1);

        db.create_fulltext_index("name_idx", Some("Doc"), &["name".to_string()])
            .expect("create fulltext index");
        db.create_fulltext_index("name_idx", Some("Doc"), &["name".to_string()])
            .expect("duplicate fulltext index is idempotent");
        assert_eq!(db.list_fulltext_indexes().len(), 1);

        let vector_profiled = db
            .query_profiled_cypher(
                "CALL db.index.vector.queryNodes('embedding_idx', [1.0, 0.0, 0.0], 1) YIELD node, score RETURN node, score",
            )
            .expect("profiled vector procedure");
        assert_eq!(
            vector_profiled.0.columns,
            vec!["node".to_string(), "score".to_string()]
        );
        assert_eq!(vector_profiled.1.parse_micros, 0);
        assert_eq!(vector_profiled.1.analyze_micros, 0);
        assert_eq!(vector_profiled.1.logical_plan_micros, 0);
        assert_eq!(vector_profiled.1.physical_plan_micros, 0);
        assert!(vector_profiled.1.execute_micros > 0);

        let empty_vector_drop = db
            .drop_vector_index(" ")
            .expect_err("empty vector index name must fail");
        assert!(empty_vector_drop
            .to_string()
            .contains("vector index name cannot be empty"));
        db.drop_vector_index("missing")
            .expect("missing vector index drop is no-op");

        let empty_fulltext_drop = db
            .drop_fulltext_index("")
            .expect_err("empty fulltext index name must fail");
        assert!(empty_fulltext_drop
            .to_string()
            .contains("fulltext index name cannot be empty"));
        db.drop_fulltext_index("missing")
            .expect("missing fulltext index drop is no-op");

        cleanup_db_artifacts(&path);

        let missing_path = temp_db_path("missing-index-plan");
        let db = Database::init(&missing_path, Header::default_v1()).expect("init");

        let vector_ast = db
            .parse_cypher("MATCH (n:Doc) WHERE n.embedding <-> [1.0] < 0.5 RETURN n")
            .expect("parse vector");
        let vector_semantic = db.analyze_cypher(&vector_ast).expect("analyze vector");
        let vector_logical = db.plan_cypher(&vector_semantic).expect("plan vector");
        let vector_err = db
            .physical_plan_cypher(&vector_logical)
            .expect_err("vector plan without index should fail");
        assert!(vector_err.to_string().contains("no vector index available"));

        let text_ast = db
            .parse_cypher("MATCH (n:Doc) WHERE n.name CONTAINS TEXT 'alice' RETURN n")
            .expect("parse text");
        let text_semantic = db.analyze_cypher(&text_ast).expect("analyze text");
        let text_logical = db.plan_cypher(&text_semantic).expect("plan text");
        let text_err = db
            .physical_plan_cypher(&text_logical)
            .expect_err("text plan without index should fail");
        assert!(text_err.to_string().contains("no fulltext index available"));

        cleanup_db_artifacts(&missing_path);
    }

