    #[test]
    fn rbac_permissions_and_audit_log_procedure_work() {
        let path = temp_db_path("rbac-audit");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");
        db.create_user("alice", Some("token-alice"))
            .expect("create user");
        let authed = db.authenticate_token("token-alice");
        assert_eq!(authed.as_deref(), Some("alice"));

        let denied = db
            .query_as_user("alice", "CREATE (n)")
            .expect_err("read-only user should not write");
        assert!(denied.to_string().contains("permission denied"));

        db.grant_role("alice", DbRole::ReadWrite)
            .expect("grant role");
        db.query_as_user("alice", "CREATE (n)")
            .expect("read_write user can write");

        db.revoke_role("alice", DbRole::ReadWrite)
            .expect("revoke role");
        let denied_after_revoke = db
            .query_as_user("alice", "CREATE (n)")
            .expect_err("write should fail after revoke");
        assert!(denied_after_revoke
            .to_string()
            .contains("permission denied"));

        let audit_rows = db
            .query("CALL db.audit.log(0) YIELD entry RETURN entry")
            .expect("query audit log")
            .to_rows();
        assert!(
            !audit_rows.is_empty(),
            "audit log should contain write entry"
        );
        let first_entry = audit_rows[0].get("entry").expect("audit entry field");
        let first_json = match first_entry {
            PropertyValue::String(value) => value,
            other => panic!("expected audit entry string json, got {other:?}"),
        };
        let entry: AuditEntry = serde_json::from_str(first_json).expect("audit entry json");
        assert_eq!(entry.user, "alice");
        assert_eq!(entry.operation, "CREATE");

        cleanup_db_artifacts(&path);
    }

    #[test]
    fn shared_database_authenticate_token_with_validator_supports_sso_placeholder() {
        #[derive(Debug)]
        struct StaticValidator;

        impl TokenValidator for StaticValidator {
            fn validate_token(&self, token: &str) -> Result<Option<String>, DbError> {
                if token == "sso-token" {
                    Ok(Some("sso-user".to_string()))
                } else {
                    Ok(None)
                }
            }
        }

        let path = temp_db_path("sso-validator");
        let shared = SharedDatabase::init(&path, Header::default_v1()).expect("init");
        let validator = StaticValidator;

        let sso_user = shared
            .authenticate_token_with_validator("sso-token", Some(&validator))
            .expect("validator auth");
        assert_eq!(sso_user.as_deref(), Some("sso-user"));

        let missing = shared
            .authenticate_token_with_validator("missing-token", Some(&validator))
            .expect("missing token");
        assert!(missing.is_none());

        cleanup_db_artifacts(&path);
    }

    #[test]
    fn gql_union_and_optional_match_behaviors_are_supported() {
        let path = temp_db_path("gql-union-optional");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");
        let _ = db
            .create_node_with(
                &["Person".to_string()],
                &PropertyMap::from([(
                    "name".to_string(),
                    PropertyValue::String("Alice".to_string()),
                )]),
            )
            .expect("create alice");
        let _ = db
            .create_node_with(
                &["Person".to_string()],
                &PropertyMap::from([(
                    "name".to_string(),
                    PropertyValue::String("Bob".to_string()),
                )]),
            )
            .expect("create bob");

        let union = db
            .query(
                "MATCH (n:Person) RETURN n.name AS name UNION MATCH (n:Person) RETURN n.name AS name",
            )
            .expect("union");
        assert_eq!(union.row_count(), 2);

        let union_all = db
            .query(
                "MATCH (n:Person) RETURN n.name AS name UNION ALL MATCH (n:Person) RETURN n.name AS name",
            )
            .expect("union all");
        assert_eq!(union_all.row_count(), 4);

        let optional = db
            .query("OPTIONAL MATCH (n:Missing) RETURN n")
            .expect("optional match");
        assert_eq!(optional.row_count(), 1);
        let optional_rows = optional.to_rows();
        assert_eq!(
            optional_rows
                .first()
                .and_then(|row| row.get("n"))
                .cloned()
                .expect("optional n value"),
            PropertyValue::String("null".to_string())
        );

        cleanup_db_artifacts(&path);
    }

    #[test]
    fn relationship_property_projection_allows_missing_values_as_null() {
        let path = temp_db_path("relationship-property-nullable");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");
        let alice = db
            .create_node_with(
                &["Person".to_string()],
                &PropertyMap::from([(
                    "name".to_string(),
                    PropertyValue::String("Alice".to_string()),
                )]),
            )
            .expect("create alice");
        let bob = db
            .create_node_with(
                &["Person".to_string()],
                &PropertyMap::from([(
                    "name".to_string(),
                    PropertyValue::String("Bob".to_string()),
                )]),
            )
            .expect("create bob");
        let carol = db
            .create_node_with(
                &["Person".to_string()],
                &PropertyMap::from([(
                    "name".to_string(),
                    PropertyValue::String("Carol".to_string()),
                )]),
            )
            .expect("create carol");

        db.add_typed_edge(
            alice,
            carol,
            "KNOWS",
            &PropertyMap::from([("since".to_string(), PropertyValue::I64(2020))]),
        )
        .expect("create edge with since");
        db.add_typed_edge(bob, carol, "KNOWS", &PropertyMap::new())
            .expect("create edge without since");

        let rows = db
            .query(
                "MATCH (a:Person)-[r:KNOWS]->(c:Person) RETURN a.name AS name, r.since AS since ORDER BY a.name ASC",
            )
            .expect("query relationship property with mixed null values")
            .to_rows();
        assert_eq!(rows.len(), 2);
        assert_eq!(rows[0].get("since"), Some(&PropertyValue::I64(2020)));
        assert_eq!(
            rows[1].get("since"),
            Some(&PropertyValue::String("null".to_string()))
        );

        cleanup_db_artifacts(&path);
    }

    #[test]
    fn gql_case_exists_and_pattern_comprehension_execute() {
        let path = temp_db_path("gql-case-exists-pattern");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");
        let alice = db
            .create_node_with(
                &["Person".to_string()],
                &PropertyMap::from([(
                    "name".to_string(),
                    PropertyValue::String("Alice".to_string()),
                )]),
            )
            .expect("create alice");
        let bob = db
            .create_node_with(
                &["Person".to_string()],
                &PropertyMap::from([(
                    "name".to_string(),
                    PropertyValue::String("Bob".to_string()),
                )]),
            )
            .expect("create bob");
        let _ = db
            .add_typed_edge(alice, bob, "KNOWS", &PropertyMap::new())
            .expect("create knows edge");

        let case_rows = db
            .query(
                "MATCH (n:Person) RETURN n.name AS name, CASE n.name WHEN 'Alice' THEN 'A' ELSE 'X' END AS bucket ORDER BY n.name",
            )
            .expect("case query")
            .to_rows();
        assert_eq!(case_rows.len(), 2);
        assert_eq!(
            case_rows[0].get("bucket"),
            Some(&PropertyValue::String("A".to_string()))
        );
        assert_eq!(
            case_rows[1].get("bucket"),
            Some(&PropertyValue::String("X".to_string()))
        );

        let exists_rows = db
            .query(
                "MATCH (n:Person) WHERE n.name = 'Alice' RETURN EXISTS { MATCH (n)-[:KNOWS]->(m) RETURN m } AS has_knows",
            )
            .expect("exists query")
            .to_rows();
        assert_eq!(exists_rows.len(), 1);
        assert_eq!(
            exists_rows[0].get("has_knows"),
            Some(&PropertyValue::Bool(true))
        );

        let pattern_rows = db
            .query(
                "MATCH (n:Person) WHERE n.name = 'Alice' RETURN [(n)-[:KNOWS]->(m) | m.name] AS names",
            )
            .expect("pattern comprehension query")
            .to_rows();
        assert_eq!(pattern_rows.len(), 1);
        let names_value = pattern_rows[0]
            .get("names")
            .cloned()
            .expect("pattern names");
        let names_text = match names_value {
            PropertyValue::String(value) => value,
            other => panic!("expected string list from pattern comprehension, got {other:?}"),
        };
        assert!(
            names_text.contains("Bob"),
            "pattern comprehension projection should include Bob"
        );

        cleanup_db_artifacts(&path);
    }

