    #[test]
    fn agent_memory_and_graphrag_read_wrappers_are_available_on_read_handles() {
        let path = temp_db_path("agent-memory-read-wrappers");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");

        db.store_episode("agent-a", "s-1", "alpha memory", &[1.0, 0.0], 100, "{}")
            .expect("store first episode");
        db.store_episode("agent-a", "s-1", "beta memory", &[0.0, 1.0], 200, "{}")
            .expect("store second episode");

        let n0 = db
            .create_node_with(
                &["Doc".to_string()],
                &PropertyMap::from([
                    (
                        "content".to_string(),
                        PropertyValue::String("alpha retrieval memory".to_string()),
                    ),
                    (
                        "embedding".to_string(),
                        PropertyValue::Vector(vec![1.0, 0.0]),
                    ),
                ]),
            )
            .expect("create doc n0");
        let n1 = db
            .create_node_with(
                &["Doc".to_string()],
                &PropertyMap::from([
                    (
                        "content".to_string(),
                        PropertyValue::String("beta retrieval memory".to_string()),
                    ),
                    (
                        "embedding".to_string(),
                        PropertyValue::Vector(vec![0.0, 1.0]),
                    ),
                ]),
            )
            .expect("create doc n1");
        db.add_typed_edge(n0, n1, "LINK", &PropertyMap::new())
            .expect("link docs");
        db.add_typed_edge(n1, n0, "LINK", &PropertyMap::new())
            .expect("link docs reverse");
        db.create_vector_index(
            "doc_embedding_idx",
            Some("Doc"),
            "embedding",
            2,
            VectorDistanceMetric::Cosine,
        )
        .expect("create vector index");
        db.create_fulltext_index("doc_text_idx", Some("Doc"), &["content".to_string()])
            .expect("create fulltext index");

        let tx = db.begin_read();
        assert_eq!(
            tx.recall_episodes("agent-a", &[1.0, 0.0], 10, None)
                .expect("read tx recall episodes")
                .len(),
            2
        );
        assert_eq!(
            tx.recall_episode_scores("agent-a", &[1.0, 0.0], 10, None)
                .expect("read tx recall episode scores")
                .len(),
            2
        );
        assert_eq!(
            tx.recall_by_session("agent-a", "s-1")
                .expect("read tx recall by session")
                .len(),
            2
        );
        assert!(!tx
            .build_community_summaries(1.0)
            .expect("read tx build summaries")
            .is_empty());
        assert!(!tx
            .hybrid_rag_retrieve(&[1.0, 0.0], "alpha", 2, 0.5, None)
            .expect("read tx rag retrieve")
            .is_empty());
        #[allow(clippy::drop_non_drop)]
        drop(tx);
        drop(db);

        let shared = SharedDatabase::open(&path).expect("open shared database");
        let snapshot = shared.read_snapshot().expect("open read snapshot");
        assert_eq!(
            snapshot
                .recall_episodes("agent-a", &[1.0, 0.0], 10, None)
                .expect("snapshot recall episodes")
                .len(),
            2
        );
        assert_eq!(
            snapshot
                .recall_episode_scores("agent-a", &[1.0, 0.0], 10, None)
                .expect("snapshot recall episode scores")
                .len(),
            2
        );
        assert_eq!(
            snapshot
                .recall_by_session("agent-a", "s-1")
                .expect("snapshot recall by session")
                .len(),
            2
        );
        assert!(!snapshot
            .build_community_summaries(1.0)
            .expect("snapshot build summaries")
            .is_empty());
        assert!(!snapshot
            .hybrid_rag_retrieve(&[1.0, 0.0], "alpha", 2, 0.5, None)
            .expect("snapshot rag retrieve")
            .is_empty());

        cleanup_db_artifacts(&path);
    }

    #[test]
    fn graphrag_error_paths_and_prefilters_are_handled() {
        let empty_path = temp_db_path("graphrag-error-empty");
        let empty_db = Database::init(&empty_path, Header::default_v1()).expect("init");
        assert!(empty_db
            .build_community_summaries(1.0)
            .expect("empty summary build")
            .is_empty());
        assert!(empty_db
            .hybrid_rag_retrieve(&[1.0], "alpha", 0, 0.5, None)
            .expect("k=0 rag retrieve should return empty")
            .is_empty());
        let bad_alpha_err = empty_db
            .hybrid_rag_retrieve(&[1.0], "alpha", 1, 1.1, None)
            .expect_err("alpha outside range should fail");
        assert!(bad_alpha_err
            .to_string()
            .contains("alpha must be between 0.0 and 1.0"));
        let bad_embedding_err = empty_db
            .hybrid_rag_retrieve(&[], "alpha", 1, 0.5, None)
            .expect_err("empty embedding should fail");
        assert!(bad_embedding_err
            .to_string()
            .contains("query embedding dimensions must be between 1"));
        let bad_resolution_err = empty_db
            .build_community_summaries(0.0)
            .expect_err("zero resolution should fail");
        assert!(bad_resolution_err
            .to_string()
            .contains("resolution must be a positive finite value"));
        let no_vector_err = empty_db
            .hybrid_rag_retrieve(&[1.0], "alpha", 1, 0.5, None)
            .expect_err("missing vector index should fail");
        assert!(no_vector_err
            .to_string()
            .contains("no vector index available for rag retrieval"));
        cleanup_db_artifacts(&empty_path);

        let path = temp_db_path("graphrag-error-prefilter");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");
        let n0 = db
            .create_node_with(
                &["Doc".to_string()],
                &PropertyMap::from([
                    (
                        "content".to_string(),
                        PropertyValue::String("alpha retrieval memory".to_string()),
                    ),
                    (
                        "embedding".to_string(),
                        PropertyValue::Vector(vec![1.0, 0.0]),
                    ),
                ]),
            )
            .expect("create n0");
        let n1 = db
            .create_node_with(
                &["Doc".to_string()],
                &PropertyMap::from([
                    (
                        "content".to_string(),
                        PropertyValue::String("alpha graph memory".to_string()),
                    ),
                    (
                        "embedding".to_string(),
                        PropertyValue::Vector(vec![0.9, 0.1]),
                    ),
                ]),
            )
            .expect("create n1");
        let n2 = db
            .create_node_with(
                &["Doc".to_string()],
                &PropertyMap::from([
                    (
                        "content".to_string(),
                        PropertyValue::String("hidden src".to_string()),
                    ),
                    (
                        "embedding".to_string(),
                        PropertyValue::Vector(vec![0.0, 1.0]),
                    ),
                ]),
            )
            .expect("create n2");
        let n3 = db
            .create_node_with(
                &["Doc".to_string()],
                &PropertyMap::from([
                    (
                        "content".to_string(),
                        PropertyValue::String("hidden dst".to_string()),
                    ),
                    (
                        "embedding".to_string(),
                        PropertyValue::Vector(vec![0.1, 0.9]),
                    ),
                ]),
            )
            .expect("create n3");

        let hidden_edge = db
            .add_typed_edge(n0, n1, "LINK", &PropertyMap::new())
            .expect("add hidden edge");
        db.edge_versions[hidden_edge as usize].committed = false;
        db.add_typed_edge(n0, n1, "LINK", &PropertyMap::new())
            .expect("add visible edge");
        db.add_typed_edge(n2, n0, "LINK", &PropertyMap::new())
            .expect("add src-hidden edge");
        db.node_versions[n2 as usize].committed = false;
        db.add_typed_edge(n0, n3, "LINK", &PropertyMap::new())
            .expect("add dst-hidden edge");
        db.node_versions[n3 as usize].committed = false;

        db.create_vector_index(
            "doc_embedding_idx",
            Some("Doc"),
            "embedding",
            2,
            VectorDistanceMetric::Cosine,
        )
        .expect("create vector index");

        let no_fulltext_err = db
            .hybrid_rag_retrieve(&[1.0, 0.0], "alpha", 2, 0.5, None)
            .expect_err("missing fulltext index should fail");
        assert!(no_fulltext_err
            .to_string()
            .contains("no fulltext index available for rag retrieval"));

        db.create_fulltext_index("doc_text_idx", Some("Doc"), &["content".to_string()])
            .expect("create fulltext index");

        let summaries = db
            .build_community_summaries(1.0)
            .expect("build summaries with hidden nodes/edges");
        assert!(!summaries.is_empty());

        let empty_prefilter = db
            .hybrid_rag_retrieve(&[1.0, 0.0], "alpha", 2, 0.5, Some(u64::MAX))
            .expect("prefilter miss should be empty");
        assert!(empty_prefilter.is_empty());

        let rag_rows = db
            .hybrid_rag_retrieve(&[f32::NAN, 0.0], "alpha", 4, 0.5, None)
            .expect("nan rag query should succeed");
        assert!(rag_rows.iter().all(|row| row.score.is_finite()));

        cleanup_db_artifacts(&path);
    }

    #[test]
    fn agent_memory_episode_store_recall_forget_and_call_procedures() {
        let path = temp_db_path("agent-memory-episode");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");

        let e0 = db
            .store_episode(
                "agent-a",
                "s-1",
                "learned alpha",
                &[1.0, 0.0],
                100,
                r#"{"kind":"memory"}"#,
            )
            .expect("store e0");
        let e1 = db
            .store_episode(
                "agent-a",
                "s-1",
                "learned beta",
                &[0.0, 1.0],
                200,
                r#"{"kind":"memory"}"#,
            )
            .expect("store e1");
        let e2 = db
            .store_episode(
                "agent-b",
                "s-9",
                "other agent memory",
                &[1.0, 0.0],
                150,
                r#"{"kind":"memory"}"#,
            )
            .expect("store e2");

        assert!(db.list_indexes().iter().any(|definition| {
            definition.label == "Episode"
                && definition.property_keys == vec!["agent_id".to_string(), "timestamp".to_string()]
        }));
        assert!(db
            .list_vector_indexes()
            .iter()
            .any(|definition| definition.name == "episode_embedding_idx"));

        let recalled = db
            .recall_episodes("agent-a", &[1.0, 0.0], 10, None)
            .expect("recall episodes");
        assert_eq!(recalled.len(), 2);
        assert_eq!(recalled[0].episode_id, e0);
        assert_eq!(recalled[1].episode_id, e1);

        let ranged = db
            .recall_episodes("agent-a", &[1.0, 0.0], 10, Some((150, 250)))
            .expect("ranged recall");
        assert_eq!(ranged.len(), 1);
        assert_eq!(ranged[0].episode_id, e1);

        let by_session = db
            .recall_by_session("agent-a", "s-1")
            .expect("recall by session");
        assert_eq!(by_session.len(), 2);
        assert_eq!(by_session[0].episode_id, e0);
        assert_eq!(by_session[1].episode_id, e1);

        let mut stored_via_call = db
            .query(
                "CALL db.agent.storeEpisode('agent-a', 's-2', 'stored via call', [1.0, 0.0], 300, '{\"source\":\"call\"}') YIELD episodeId RETURN episodeId",
            )
            .expect("store via call")
            .to_rows();
        assert_eq!(stored_via_call.len(), 1);
        stored_via_call.insert(
            0,
            BTreeMap::from([(
                "episodeId".to_string(),
                PropertyValue::String("skip".to_string()),
            )]),
        );
        let call_episode_id = stored_via_call
            .iter()
            .find_map(|row| {
                row.get("episodeId").and_then(|value| match value {
                    PropertyValue::I64(value) => Some(*value as u64),
                    _ => None,
                })
            })
            .expect("episodeId row");
        assert!(call_episode_id > e2);

        let recall_via_call = db
            .query(
                "CALL db.agent.recall('agent-a', [1.0, 0.0], 2) YIELD episode, score RETURN episode, score ORDER BY score DESC",
            )
            .expect("recall via call");
        assert_eq!(
            recall_via_call.columns,
            vec!["episode".to_string(), "score".to_string()]
        );
        assert_eq!(recall_via_call.row_count(), 2);

        db.forget_episodes("agent-a", 200)
            .expect("forget episodes before timestamp");

        let by_session_after_forget = db
            .recall_by_session("agent-a", "s-1")
            .expect("recall by session after forget");
        assert_eq!(by_session_after_forget.len(), 1);
        assert_eq!(by_session_after_forget[0].episode_id, e1);

        let other_agent_episodes = db
            .recall_by_session("agent-b", "s-9")
            .expect("other agent remains");
        assert_eq!(other_agent_episodes.len(), 1);
        assert_eq!(other_agent_episodes[0].episode_id, e2);

        cleanup_db_artifacts(&path);
    }

