    #[test]
    fn subgraph_extraction_returns_nodes_and_edges_within_hops() {
        let path = temp_db_path("subgraph-extraction");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");
        let n0 = db.create_node().expect("n0");
        let n1 = db.create_node().expect("n1");
        let n2 = db.create_node().expect("n2");
        let n3 = db.create_node().expect("n3");
        let e0 = db.add_edge(n0, n1).expect("e0");
        let _e1 = db.add_edge(n1, n2).expect("e1");
        let e2 = db.add_edge(n0, n3).expect("e2");

        let subgraph = db
            .extract_subgraph(n0, 1, None)
            .expect("extract subgraph around n0");
        assert_eq!(subgraph.center, n0);
        assert_eq!(subgraph.max_hops, 1);
        assert_eq!(subgraph.nodes, vec![n0, n1, n3]);
        assert_eq!(subgraph.edges.len(), 2);
        assert_eq!(subgraph.edges[0].edge_id, e0);
        assert_eq!(subgraph.edges[1].edge_id, e2);

        let unknown_center = db
            .extract_subgraph(99, 1, None)
            .expect_err("unknown center should fail");
        assert!(unknown_center
            .to_string()
            .contains("unknown node id for subgraph extraction"));

        let road_edge = db
            .add_typed_edge(n0, n1, "ROAD", &PropertyMap::new())
            .expect("road edge");
        db.add_typed_edge(n0, n1, "AIR", &PropertyMap::new())
            .expect("air edge");
        let hidden_road_edge = db
            .add_typed_edge(n1, n0, "ROAD", &PropertyMap::new())
            .expect("hidden road edge");
        db.edge_versions[hidden_road_edge as usize].committed = false;

        let filtered = db
            .extract_subgraph(n0, 4, Some("ROAD"))
            .expect("road-only subgraph");
        assert_eq!(filtered.nodes, vec![n0, n1]);
        assert_eq!(filtered.edges.len(), 1);
        assert_eq!(filtered.edges[0].edge_id, road_edge);
        assert_eq!(filtered.edges[0].edge_type, Some("ROAD".to_string()));
    }

