    #[test]
    fn detect_wcoj_candidate_requires_at_least_three_variables() {
        let plan_2var = LogicalPlan::Expand {
            input: Box::new(LogicalPlan::Scan {
                label: Some("A".to_string()),
                variable: Some("a".to_string()),
            }),
            from: "a".to_string(),
            edge_type: Some("R".to_string()),
            direction: RelationshipDirection::LeftToRight,
            to: Some("b".to_string()),
            edge_variable: None,
            temporal_filter: None,
        };
        assert!(
            detect_wcoj_candidate(&plan_2var).is_none(),
            "2-variable pattern should not trigger WCOJ"
        );

        let plan_3var = LogicalPlan::Expand {
            input: Box::new(LogicalPlan::Expand {
                input: Box::new(LogicalPlan::Scan {
                    label: Some("A".to_string()),
                    variable: Some("a".to_string()),
                }),
                from: "a".to_string(),
                edge_type: Some("R".to_string()),
                direction: RelationshipDirection::LeftToRight,
                to: Some("b".to_string()),
                edge_variable: None,
                temporal_filter: None,
            }),
            from: "b".to_string(),
            edge_type: Some("S".to_string()),
            direction: RelationshipDirection::LeftToRight,
            to: Some("c".to_string()),
            edge_variable: None,
            temporal_filter: None,
        };
        let candidate = detect_wcoj_candidate(&plan_3var).expect("3 variables should qualify");
        assert_eq!(candidate.variable_order, vec!["a", "b", "c"]);

        let plan_cycle = LogicalPlan::Expand {
            input: Box::new(LogicalPlan::Expand {
                input: Box::new(LogicalPlan::Scan {
                    label: Some("A".to_string()),
                    variable: Some("a".to_string()),
                }),
                from: "a".to_string(),
                edge_type: Some("R".to_string()),
                direction: RelationshipDirection::LeftToRight,
                to: Some("b".to_string()),
                edge_variable: None,
                temporal_filter: None,
            }),
            from: "b".to_string(),
            edge_type: Some("R".to_string()),
            direction: RelationshipDirection::LeftToRight,
            to: Some("a".to_string()),
            edge_variable: None,
            temporal_filter: None,
        };
        let cycle_candidate =
            detect_wcoj_candidate(&plan_cycle).expect("cyclic pattern should trigger WCOJ");
        assert!(cycle_candidate.is_cyclic);
    }

