    #[test]
    fn factorized_expand_correctness_parity() {
        let path = temp_db_path("factorized-expand-parity");
        let mut db = Database::init(&path, Header::default_v1()).expect("init");

        let sources = (0..65)
            .map(|_| {
                db.create_node_with(&["Src".to_string()], &PropertyMap::new())
                    .expect("src")
            })
            .collect::<Vec<_>>();
        let targets = (0..20)
            .map(|_| {
                db.create_node_with(&["Dst".to_string()], &PropertyMap::new())
                    .expect("dst")
            })
            .collect::<Vec<_>>();

        for source in &sources {
            for target in &targets {
                db.add_typed_edge(*source, *target, "E", &PropertyMap::new())
                    .expect("edge");
            }
        }

        let logical = LogicalPlan::Expand {
            input: Box::new(LogicalPlan::Scan {
                label: Some("Src".to_string()),
                variable: Some("a".to_string()),
            }),
            from: "a".to_string(),
            edge_type: Some("E".to_string()),
            direction: RelationshipDirection::LeftToRight,
            to: Some("b".to_string()),
            edge_variable: None,
            temporal_filter: None,
        };
        let physical = build_physical_plan(&db, &logical).expect("physical");
        assert!(matches!(
            physical,
            PhysicalPlan::PhysicalFactorizedExpand {
                factorized: true,
                ..
            }
        ));

        let factorized_result = db
            .query("MATCH (a:Src)-[:E]->(b:Dst) RETURN a, b ORDER BY a, b")
            .expect("factorized query");
        assert_eq!(factorized_result.row_count(), 1300);
        let factorized_pairs = factorized_result
            .to_rows()
            .into_iter()
            .map(|row| {
                let a = match row.get("a") {
                    Some(PropertyValue::I64(value)) => *value,
                    _ => panic!("a should be i64 node id"),
                };
                let b = match row.get("b") {
                    Some(PropertyValue::I64(value)) => *value,
                    _ => panic!("b should be i64 node id"),
                };
                (a, b)
            })
            .collect::<BTreeSet<_>>();

        let source_scan = PhysicalPlan::PhysicalScan {
            label: Some("Src".to_string()),
            variable: Some("a".to_string()),
            scan_strategy: PhysicalScanStrategy::IndexScan,
            estimated_rows: 65,
            estimated_cost: 65.0,
        };
        let flat_expand = PhysicalPlan::PhysicalExpand {
            input: Box::new(source_scan),
            from: "a".to_string(),
            edge_type: Some("E".to_string()),
            direction: RelationshipDirection::LeftToRight,
            to: Some("b".to_string()),
            edge_variable: None,
            temporal_filter: None,
            join_strategy: PhysicalJoinStrategy::HashJoin,
            estimated_rows: 1300,
            estimated_cost: 1365.0,
        };
        let flat_batches = db
            .execute_physical_plan_batches(&flat_expand, db.current_snapshot_txn_id())
            .expect("execute flat expand");
        let flat_rows = rows_from_batches(&flat_batches);
        let flat_pairs = flat_rows
            .iter()
            .map(|row| {
                let a = match row.get("a") {
                    Some(RuntimeValue::Node(value)) => *value as i64,
                    _ => panic!("flat a should be node"),
                };
                let b = match row.get("b") {
                    Some(RuntimeValue::Node(value)) => *value as i64,
                    _ => panic!("flat b should be node"),
                };
                (a, b)
            })
            .collect::<BTreeSet<_>>();
        assert_eq!(flat_pairs, factorized_pairs);

        cleanup_db_artifacts(&path);
    }

